-- Poems batch 180
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('c8bc6c5f-cfdb-4a66-87d2-f15afe928005','閒居雜詠三十二首 目','陳淳','宋','宋诗','song-poetry','','[]','目所以司視，視正乃爲明。',24,'全唐诗/poet.song.175000.json','["目所以司視，視正乃爲明。", "非禮謹勿睹，睹之則爲盲。"]'),
('9cd4da5c-181b-4bad-a97d-49b0593a4997','閒居雜詠三十二首 口','陳淳','宋','宋诗','song-poetry','','[]','口所以司言，所言必正說。',24,'全唐诗/poet.song.175000.json','["口所以司言，所言必正說。", "非法謹勿道，道之爲噬噎。"]'),
('10dc38f7-2080-4c84-9d41-87f7c188241f','閒居雜詠三十二首 手','陳淳','宋','宋诗','song-poetry','','[]','手所以司執，所執必正事。',24,'全唐诗/poet.song.175000.json','["手所以司執，所執必正事。", "回德謹勿持，持必爲痿痺。"]'),
('c705cdbb-9d6a-4e1e-a25c-47e484171515','閒居雜詠三十二首 足','陳淳','宋','宋诗','song-poetry','','[]','足所以司履，所履必正道。',24,'全唐诗/poet.song.175000.json','["足所以司履，所履必正道。", "邪徑謹勿由，由之爲躃跛。"]'),
('18f4b9c6-7b4a-4928-9aed-c1649179f4e2','閒居雜詠三十二首 心','陳淳','宋','宋诗','song-poetry','','[]','心爲形之君，所主一身政。',24,'全唐诗/poet.song.175000.json','["心爲形之君，所主一身政。", "持養常清明，百體皆順令。"]'),
('24b7d57b-9aaf-46cf-8ffd-cb62bbd04007','閒居雜詠三十二首 博學','陳淳','宋','宋诗','song-poetry','','[]','泛觀事物間，是理真卓卓。',24,'全唐诗/poet.song.175000.json','["泛觀事物間，是理真卓卓。", "無一非吾事，要在博所學。"]'),
('e0592ef8-2d18-40f4-886f-2199807bc227','閒居雜詠三十二首 審問','陳淳','宋','宋诗','song-poetry','','[]','物理本不齊，雜然各異分。',24,'全唐诗/poet.song.175000.json','["物理本不齊，雜然各異分。", "參伍寧無疑，要在審所問。"]'),
('69cec258-5c38-4d5a-aac6-d9bbb949382e','閒居雜詠三十二首 謹思','陳淳','宋','宋诗','song-poetry','','[]','論學取諸友，舉隅發之師。',24,'全唐诗/poet.song.175000.json','["論學取諸友，舉隅發之師。", "欲自得其傳，要在謹厥思。"]'),
('e2950662-7ef1-4b1f-9349-a0b5715094d0','閒居雜詠三十二首 明辨','陳淳','宋','宋诗','song-poetry','','[]','利與善之間，微似未易斷。',24,'全唐诗/poet.song.175000.json','["利與善之間，微似未易斷。", "欲無毫釐差，要在明厥辨。"]'),
('8b0cf7d0-ba11-4272-b350-816204d99890','閒居雜詠三十二首 篤行','陳淳','宋','宋诗','song-poetry','','[]','學問思辨者，於中瑩且精。',24,'全唐诗/poet.song.175000.json','["學問思辨者，於中瑩且精。", "欲實據而有，要在篤於行。"]'),
('08a8bdda-8233-4c51-99ed-36721652e980','閒居雜詠三十二首 隆師','陳淳','宋','宋诗','song-poetry','','[]','師者人之範，辨惑正吾疑。',24,'全唐诗/poet.song.175000.json','["師者人之範，辨惑正吾疑。", "苟不就有道，倀倀其何之。"]'),
('d5fba837-1ee9-4ca1-9440-769ae6b01fe1','閒居雜詠三十二首 親友','陳淳','宋','宋诗','song-poetry','','[]','友者人之輔，以善相切磨。',24,'全唐诗/poet.song.175000.json','["友者人之輔，以善相切磨。", "不取直諒聞，其如損德何。"]'),
('471a9c11-852d-4366-afb3-0764674abbe0','閒居雜詠三十二首 遷善','陳淳','宋','宋诗','song-poetry','','[]','善者性所有，不可無諸躬。',24,'全唐诗/poet.song.175000.json','["善者性所有，不可無諸躬。", "每見必勇遷，吾德乃可崇。"]'),
('aac69461-de56-4031-a948-04595fc00e77','閒居雜詠三十二首 改過','陳淳','宋','宋诗','song-poetry','','[]','過者動之差，毋容實諸己。',24,'全唐诗/poet.song.175000.json','["過者動之差，毋容實諸己。", "才覺必速改，乃不爲吾累。"]'),
('736c4b84-243c-4579-8509-00fbedc58bb8','閒居雜詠三十二首 禮維','陳淳','宋','宋诗','song-poetry','','[]','禮以維其心，在心無不敬。',24,'全唐诗/poet.song.175000.json','["禮以維其心，在心無不敬。", "非此勿言動，非此勿視聽。"]'),
('a03f2adb-8514-4973-9939-c51f72b23718','閒居雜詠三十二首 義維','陳淳','宋','宋诗','song-poetry','','[]','義以維其心，在心常有制。',24,'全唐诗/poet.song.175000.json','["義以維其心，在心常有制。", "惟爲理所宜，不徇情所利。"]'),
('0a283d55-f0dd-4867-b438-f1fe520bcc95','閒居雜詠三十二首 廉維','陳淳','宋','宋诗','song-poetry','','[]','廉以維其心，在心常有辨。',24,'全唐诗/poet.song.175000.json','["廉以維其心，在心常有辨。", "一介不妄取，真如視土糞。"]'),
('c166c8b9-840a-4e42-8f80-5cdd7b2a7107','閒居雜詠三十二首 恥維','陳淳','宋','宋诗','song-poetry','','[]','恥以維其心，在心每知愧。',24,'全唐诗/poet.song.175000.json','["恥以維其心，在心每知愧。", "不善臨吾前，真如負芒刺。"]'),
('18c87141-b509-4402-bc2d-8a283ee45634','警惰','陳淳','宋','宋诗','song-poetry','','[]','日月雙跳丸，一旦復一旦。',60,'全唐诗/poet.song.175000.json','["日月雙跳丸，一旦復一旦。", "於穆無疆命，後□□如趲。", "前頭只逗遛，不勇攻與戰。", "當然緊切功，一一事散漫。", "便是惰天職，天地一罪漢。"]'),
('a8bdc5fd-db4c-4343-9f11-dc86e3dd392b','警滯','陳淳','宋','宋诗','song-poetry','','[]','賓主辨貴白，死生路宜分。',72,'全唐诗/poet.song.175000.json','["賓主辨貴白，死生路宜分。", "當克即便克，當存即必存。", "直須要脫灑，如彼霽月輪。", "超然物累上，無復渣滓渾。", "不須事黏滯，如咬老樹根。", "彌年齧不斷，豈不妨吾仁。"]'),
('5bb1733b-271c-435a-af7e-8644ee3bc0b2','丁未十月見梅一點','陳淳','宋','宋诗','song-poetry','','[]','清清一點玉，枯枝絕鮮鮮。',48,'全唐诗/poet.song.175000.json','["清清一點玉，枯枝絕鮮鮮。", "歷歷霜林奇，未省有此妍。", "雅如哲君子，覺在羣蒙先。", "揭之几案上，使我心洒然。"]'),
('ccc5e98e-1aea-4b2c-8329-99dd0c305425','丙辰十月見梅同感其韻再賦','陳淳','宋','宋诗','song-poetry','','[]','霜枝禿禿瘦，孤英自中鮮。',48,'全唐诗/poet.song.175000.json','["霜枝禿禿瘦，孤英自中鮮。", "出塵寒玉姿，熟視何清妍。", "端如仁者心，洒落萬物先。", "渾無一點累，表裏俱徹然。"]'),
('d68d940a-21c6-42fa-aa3b-7a7f3e5cefe6','憶李友叔皓三首  其一','陳淳','宋','宋诗','song-poetry','','[]','君居郭之東，我館亦東郭。',132,'全唐诗/poet.song.175000.json','["君居郭之東，我館亦東郭。", "君已素我心，我未一君目。", "時初丙辰秋，一見洞軒腹。", "君即就我眠，我亦共君讀。", "曆代故史編，皇家新典牘。", "我獵未暇精，君記抑何博。", "寒燈窗竅紅，明月庭陰綠。", "君舉口不休，我聽膝屢促。", "憶從半載餘，麗澤情方熟。", "胡爲一別後，終天訣遽作。", "嗟嗟懷若人，重攪我心曲。"]'),
('7e467022-b442-42fa-83d9-3b21438e0735','憶李友叔皓三首  其二','陳淳','宋','宋诗','song-poetry','','[]','君資蓋清湛，君氣亦溫暇。',132,'全唐诗/poet.song.175000.json','["君資蓋清湛，君氣亦溫暇。", "厭渠市利囂，向我訪清灑。", "卑渠世學陋，就我咨純雅。", "肺腸無膠轕，襟懷悉傾冩。", "談義信即篤，不以吾言野。", "箴過聽益敬，不以吾爲訝。", "授之關洛編，晝夜閲不捨。", "竊喜得良朋，可與結仁社。", "同驅入德車，共策適善馬。", "胡此會乖違，使我聞陋寡。", "嗟嗟今而後，詎見斯人者。"]'),
('8283d53f-b089-4068-9176-b3df91e2370a','憶李友叔皓三首  其三','陳淳','宋','宋诗','song-poetry','','[]','初見即我贈，東京博雅堂。',120,'全唐诗/poet.song.175000.json','["初見即我贈，東京博雅堂。", "再見復我和，北窗小梅章。", "此物今只存，而人乃云亡。", "有時牽龍尾，濃磨發精光。", "恍惚金漆交，相與游翰場。", "間或展騷軸，熟玩題芬芳。", "嶙峋骨鯁語，猶能動剛腸。", "觸物即君感，感物復君傷。", "藏之不敢輕，於以無君忘。", "嗟嗟豈無朋，知心鮮其當。"]'),
('9735516d-4f71-4360-96c8-a57312fa1bf2','自訟','陳淳','宋','宋诗','song-poetry','','[]','氣一志以動，志動氣益狂。',60,'全唐诗/poet.song.175000.json','["氣一志以動，志動氣益狂。", "輾轉互攻擊，其端何有窮。", "哲人動知幾，清明常在躬。", "私欲絕微萌，天真湛流通。", "表裏皎如日，一隙無曖曚。"]'),
('776ae8de-3973-4d72-81dd-9db7d2900108','失言戒','陳淳','宋','宋诗','song-poetry','','[]','言者身樞機，興戎亦出好。',108,'全唐诗/poet.song.175000.json','["言者身樞機，興戎亦出好。", "既正且中節，吉祥以類和。", "正苟發不中，忤物立召禍。", "不可言而言，夫子戒勿道。", "言輕則招憂，子雲亦辨早。", "龍門有明箴，懇懇豈欺我。", "爾素重所出，胡茲失太果。", "策駟非難追，噬臍悔自蹈。", "從今臭不同，謹謹三緘默。"]'),
('9fc919fa-7d0f-4129-ad29-555ad986b9c8','榘子名字義','陳淳','宋','宋诗','song-poetry','','[]','小子爾定孫，來前吾語汝。',288,'全唐诗/poet.song.175000.json','["小子爾定孫，來前吾語汝。", "爾今既加冠，盍以成人遇。", "今爾名以榘，字爾以方叟。", "告爾名字義，爾其敬聽受。", "榘所以爲方，是爲法度器。", "極天下之方，不能外乎是。", "在人事而言，不越乎此理。", "此理根所性，其本一而已。", "散諸事物間，各各有所止。", "當然不容易，萬殊而一揆。", "截截有成法，方正無少陂。", "聖人安而行，所欲不踰此。", "賢者勉而復，折旋必中矣。", "學者思聖賢，於學亦必以。", "所擇要精明，所執在固緻。", "法皆自中定，方非由外至。", "如或非禮視，是以不法視。", "於視爲不方，隨物而妄伺。", "如或非禮聽，是以不法聽。", "於聽爲不方，隨物而妄應。", "如或非禮言，是以不法言。", "於言爲不方，隨物而妄宣。", "如或非禮動，是以不法動。", "於動爲不方，隨物而妄往。"]'),
('561feb69-e618-4560-96e4-620e159fedd2','警懦','陳淳','宋','宋诗','song-poetry','','[]','顔子之克己，鏌鋣斫空桑。',84,'全唐诗/poet.song.175000.json','["顔子之克己，鏌鋣斫空桑。", "曾子毅於仁，重擔硬脊梁。", "子路勇有行，勁兵赴敵場。", "孟軻剛不屈，砥柱立滄浪。", "嗟哉入聖門，迢迢萬里長。", "儻非四子才，寧不中道僵。", "爾宜變爾質，變爾柔而剛。"]'),
('9fc32d15-2e0a-4157-9ef0-7224bec7c6a6','謹所之贈王氏子','陳淳','宋','宋诗','song-poetry','','[]','我贈王氏子，作此謹所之。',288,'全唐诗/poet.song.175000.json','["我贈王氏子，作此謹所之。", "之子何所喜，喜有近道資。", "妙齡正弱冠，立志已不卑。", "與之語則解，知弗流俗隨。", "今聞欲有行，問之如何其。", "曰取天下友，曰求天下師。", "斯言美則美，乃大人之爲。", "在子則太早，恐非其所宜。", "去聖嗟已遠，名家好相持。", "師者每異戶，友焉亦多岐。", "志稚未堅定，焉保無轉移。", "識嫩未的確，那知真是非。", "同人遽于野，懔乎其亦危。", "既慕聖賢學，須循聖賢規。", "聖功有次序，躐進徒爾疲。", "非益欲速成，孔深闕童譏。", "登高必自下，子思端不欺。", "道爾求諸遠，孟軻尤所嗤。", "小學極纖悉，無非固骸肌。", "洒掃進退間，三千其威儀。", "子曾與周旋，有虧已無虧。", "大學入德門，綱條備無遺。", "開端在格物，大當致吾知。", "子曾與講貫，有疑已無疑。"]'),
('3e7f16fa-1520-473d-953d-960ac6028ff9','名陳憲友清軒','陳淳','宋','宋诗','song-poetry','','[]','名軒何以清，惟有梅與竹。',72,'全唐诗/poet.song.175000.json','["名軒何以清，惟有梅與竹。", "梅清清且白，竹清清更綠。", "雪蕊破清洒，霜操挺清肅。", "至哉雙友清，格韻真寒玉。", "伊誰與之友，相對淡無欲。", "清心仁智翁，妙趣於中足。"]'),
('3d742473-1a45-4bbb-b4a1-1d9c23fde953','贈劉伯翔相師','陳淳','宋','宋诗','song-poetry','','[]','孔孟不說相，於人洞肺肝。',144,'全唐诗/poet.song.175000.json','["孔孟不說相，於人洞肺肝。", "由也行行如，不得其死然。", "括也未聞道，其軀難以全。", "賜億亦屢中，執玉俯仰間。", "經禮視平衡，下憂傾則姦。", "茲皆以理决，初匪由術傳。", "劉君以相名，表裏須相關。", "備道最上格，溫恭厲而安。", "晬面盎於背，德人盛容顔。", "論心勿徇形，心廣體自胖。", "敬吉怠則滅，炳炳真如丹。", "此訣若未喻，所閲非神觀。"]'),
('2a25f591-fb67-4f9f-896c-9f793d0664b4','赴調歸憂時題壁','陳淳','宋','宋诗','song-poetry','','[]','上林一株木，其大千百圍。',120,'全唐诗/poet.song.175000.json','["上林一株木，其大千百圍。", "栽培自上古，婆娑蔭八維。", "云何歲月老，頹衰復頹衰。", "守者勿灌溉，伐者交剝椎。", "木根既不固，枝葉何所依。", "心骨又有蠹，皮膚何能爲。", "安得善場師，轉回陽春熙。", "變却久悴態，如彼正茂時。", "坐令萬蟲蟻，稍託庇命絲。", "嗟嗟難爾必，慨然動長悲。"]'),
('40a651c3-8ba5-4584-9795-63243225509a','秋夜玩月','陳淳','宋','宋诗','song-poetry','','[]','月出已林杪，夜深光更佳。',48,'全唐诗/poet.song.175000.json','["月出已林杪，夜深光更佳。", "可愛滿地陰，扶疎漏瓊花。", "興來不能寐，庭除步百迴。", "微吟弄清輝，幽意誰會哉。"]'),
('259337b3-04ab-4055-a7fd-03746108709d','四十','陳淳','宋','宋诗','song-poetry','','[]','孔子四十而不惑，孟子四十不動心。',32,'全唐诗/poet.song.175000.json','["孔子四十而不惑，孟子四十不動心。", "爾年已及德未就，可不汲汲痛自箴。"]'),
('9aac3610-3dac-45af-96cf-2946df7a8e4b','和丁祖舜綠笋之韻','陳淳','宋','宋诗','song-poetry','','[]','哦風徑遊衛山峬，溢耳謠言如春敷。',384,'全唐诗/poet.song.175000.json','["哦風徑遊衛山峬，溢耳謠言如春敷。", "猗猗青青發三嘆，熟察其調未免粗。", "當年載歌淇水澳，區區但取枝葉綠。", "惡知中有至味存，爽人神思勝於玉。", "料想厥種未爲良，校之吾邦君視僕。", "吾邦此君最佳處，惟在根萌毓坤腹。", "出塵妙質瑩無疑，徹骨不容疵纖釐。", "地靈精白氣所孕，圃師培壅工弗施。", "火行用事正炎鬰，故遣特特清南垂。", "鑽泥苯䔿伸蟄龍，軋石朧腫亞卧獅。", "蓄節正直已不拔，藏心塞實如無私。", "新班黄甲固脆潤，半露青簪猶珍奇。", "雨餘荷鋤試一訪，穎穎競脫毛囊錐。", "發封奏之金錯刀，片片逐刃滋瓊脂。", "未數冰谷素龍肝，豈遜金墉白雲芝。", "天然真味本自足，不待滑瀡甘以飴。", "烹煎燔炙無不可，論材宜爲百品師。", "疏腸滌胃掃煩穢，侑巵贊膳功誰知。", "九飣槃中若得此，方貢諸羞特餘子。", "簞瓢陋巷時相逢，炳腹琅玕焰欲起。", "從知種種山海腴，那有似此清中癯。", "吳蓴楚荇儻埒美，恰類𨢎䤙擬醍醐。", "貓舄班孫真徒胥，何復敢校榮與枯。", "信哉超越天地爐，君子之德他所無。"]'),
('af5c434c-ba25-4fd6-bff4-ecee6543e8fb','和丁祖舜二月陰寒之作','陳淳','宋','宋诗','song-poetry','','[]','東皇涖事已告半，農村恰恰脂田車。',181,'全唐诗/poet.song.175000.json','["東皇涖事已告半，農村恰恰脂田車。", "胡爲玄冥尚偃蹇，暗弄威權未退斜。", "阿涖{雨/趻}最癡鎖烏脚，阿香亦懶敲龍牙。", "竟日欲雨竟不雨，號寒往往悲啼鴉。", "原苗縮澀鮮生意，且悴且腐真可嗟。", "皇天本自愛下氓，陰陽舒慘元不差。", "不知當軸燮理人，此劑得之誰氏家。", "傅霖遁跡莫與用，鄒律束手難爲夸。", "安得巨力挽天河，洗凈妖氣無蘗芽。", "放開和氣充人寰，均敷菽麥榮禾麻。", "同作堯民含哺樂，毋但獨醉盈畦花。"]'),
('bc5b0fdf-0fac-49fc-8669-1147bce954f5','晴和再用丁韻','陳淳','宋','宋诗','song-poetry','','[]','膏霖溉注既優渥，璇穹頓掃頑雲車。',176,'全唐诗/poet.song.175000.json','["膏霖溉注既優渥，璇穹頓掃頑雲車。", "沉香久鬰悉清豁，無復沴氣東西斜。", "金盤擁出三足烏，赫赫耀目伸爪牙。", "融融熙熙遍林谷，鳴有喜鶑無愁鴉。", "東阡土脈浸溫暢，頗頗釋我農人嗟。", "壯者舉耜趾相摩，少者行饁肩相差。", "乃知乾元父萬物，仁育兩間同一家。", "太和生生終莫遏，不容癡寒固驕夸。", "殘陰曀曀終必退，安能掩軋壯陽芽。", "日涉老僊憂民隠，詩詞懇惻如黄麻。", "料對茲晨少慰懌，行歌豳頌筆生花。"]'),
('b95597c0-c6c7-4962-a1d4-d770858fb62a','西征鉛山遇霜','陳淳','宋','宋诗','song-poetry','','[]','年來五十筋力衰，不耐風霜不耐雪。',80,'全唐诗/poet.song.175000.json','["年來五十筋力衰，不耐風霜不耐雪。", "手爲寒凋可鑢磋，足爲凍冽如刀切。", "泥濘跋涉負塗豕，磽确陟降蟠山鼈。", "欹行橫行又跳行，忍痛忍饑復忍渴。", "此勞此苦豈再堪，焚舟之戰惟一决。"]'),
('121b3fb5-75a2-4f98-9366-a80284d421b6','遭族人橫逆','陳淳','宋','宋诗','song-poetry','','[]','顔子有犯不之校，胸懷洒落冰雪融。',240,'全唐诗/poet.song.175000.json','["顔子有犯不之校，胸懷洒落冰雪融。", "孟軻橫逆必自反，律己程度嚴秋霜。", "君子於物本無悶，小人胡爾好有攻。", "矧今薄俗抑又甚，絕無禮義爭豪强。", "大倫大法毀瓦礫，小計小數橫干將。", "背面反覆蓋常態，是非毀譽無定章。", "朝爲懿親暮仇虜，外結同好中豺狼。", "奉之屈膝轉摇尾，擠之下石仍揮槍。", "喜躋跖蹻夷齊上，怒黜皋益共鯀傍。", "要之總總皆吾外，於我內者庸何傷。", "達人大觀等毫毛，不爲欣戚留心胸。", "剛應以柔逆以順，譟應以靜暴以恭。", "紅爐點雪不少凝，曲直勝負何所量。", "况乎他石可攻玉，火經百鍊金始剛。", "堅吾志節熟吾仁，理義之益端無窮。"]'),
('80545d33-e3d0-4852-a8d9-64bb7620dab0','敘趙守備學釋菜會餕','陳淳','宋','宋诗','song-poetry','','[]','嘉定四年日在房，趙侯來守南清漳。',384,'全唐诗/poet.song.175000.json','["嘉定四年日在房，趙侯來守南清漳。", "下車百事所未遑，先務化原修泮宮。", "發帑市材鳩衆工，改偏易陋規模洪。", "大門復舊正當陽，直挹名第真仙峰。", "泮渠下疏清波溶，時與潮汐相流通。", "兩廊軒軒如翬飛，朱欄翼之森衛防。", "講堂巖巖峙中央，高明洞豁無曖曚。", "東西兩舍夾其旁，扉楹新廠標祠堂。", "諸祠疇昔亂無章，從今一正嶢相望。", "東祀無極濂溪翁，渾淪再闢如羲皇。", "二程從而大發揚，千載絕學始有光。", "文公繼之擷精剛，發揮大學明中庸。", "善集諸儒粲朝綱，金聲玉振真玲瓏。", "此邦况又舊遊鄉，流風遺澤尤洋洋。", "合爲四座儼顒顒，卓示師表開羣矇。", "女令聖門知所從，無徒自棄甘面牆。", "西祀唐人相國常，首變蠻俗趨文風。", "配以周歐二俊良，破荒桂籍先傳芳。", "端明蔡公著清忠，始自蓮幕起騰驤。", "東溪高公拔上庠，勁節凜凜凌秋霜。", "力摧秦檜銳鋒鋩，瀕死奮不顧厥躬。", "列爲五像竦昂昂，論世尚友激懦慵。", "要令片善有磨礱，無往不切進修功。", "越惟明年神祝融，羣工告備襡器藏。"]'),
('233775c9-13a4-4cff-a62a-aa73abda4437','送趙守備解南漳赴湖北倉','陳淳','宋','宋诗','song-poetry','','[]','前年邦人迎公來，人人喜公來何暮。',256,'全唐诗/poet.song.175000.json','["前年邦人迎公來，人人喜公來何暮。", "今年邦人送公去，人人恨公去何遽。", "公在南漳甫三年，仁政率起百年慕。", "在民條目皆可書，及人惠愛何勝數。", "農歌田野士歌學，工歌市廛商歌路。", "攀轅無願以公歸，斷鞅必欲留公住。", "天子愛民南北均，豈暇私漳一隅故。", "命公乘軺使荆湖，歷訪民瘼清民蠹。", "况曰古來用武地，直瞰中原正門戶。", "英才分布豈偶然，籌畫端爲恢拓具。", "北視敵衆紛蠢蠢，義槩寧無激衷素。", "挽河洗兵特餘功，不日入爲聖明輔。", "沃心迪德文太平，上窺周召參伊傅。", "鯫生忝出陶鎔下，日望清光日以阻。", "闔門惟知自好修，何敢越分求攀附。", "竊幸斯道有主盟，用舍行藏無所與。"]'),
('021ea7a6-6fc0-464d-bf7d-006e2a8bd9af','用敖教所贈詩韻送行','陳淳','宋','宋诗','song-poetry','','[]','臞菴先生仙籍豪，固非塵中浪骼骨。',320,'全唐诗/poet.song.175000.json','["臞菴先生仙籍豪，固非塵中浪骼骨。", "挺特不隨時世粧，那學兒女誇首髴。", "朅來龍江主文盟，鑪錘廣大無棄物。", "裁狂雕朽誰弗容，遊刃三年不少𠜾。", "野人掩關北溪曲，於道未能探絲忽。", "甘謝馳驅抱孤拙，反獲優容免呵咄。", "紆軫衡茅過招邀，寘之學海滄流潏。", "道德淵源漫斟酌，理義芻豢飽齧齕。", "由堂賜室縱步躡，淵鱗騫翼恣手捽。", "金篦刮瘼丹起廢，萬斛塵胸爲一拂。", "要令齪齪鑛璞姿，無或晶光向埋沒。", "云何聚散不可常，征車已駕城東月。", "當今中原若角崩，曦娥薄蝕耀計孛。", "廟堂側席急選用，英才詎復偏方屈。", "便起鴞林簉鵷行，感時怒豎衝冠髮。", "整頓乾綱靖坤維，扶掖炎精夐熛欻。", "拯危直鼓濟商楫，逢邪須奮擊泚笏。", "挽回一氣轉洪鈞，平地春雷百蟄出。", "雍容細旃講唐虞，正鞸垂紳其弁突。", "抑均斯道覺斯民，何但諸王私蔭樾。"]'),
('d151ef2d-ef55-4362-aee6-0b4ebd55fd1f','詠陳世良天開圖畫之閣','陳淳','宋','宋诗','song-poetry','','[]','九仙來來到筠谷，誰向雲端締高閣。',256,'全唐诗/poet.song.175000.json','["九仙來來到筠谷，誰向雲端締高閣。", "背倚金山作後屏，左右龍虎交蟠伏。", "前頭諸峰列碧霄，獻奇貢異相聯絡。", "文筆時時氣蔚葱，香騰旦旦煙醲郁。", "瀑布西奔扈衛雄，席帽東出朝宗肅。", "玉欄管住不斷勢，銅鼎蓄就無窮祿。", "石潭通貫洗馬陂，一派寒流腰带束。", "雨暘舒慘變萬狀，青黄紫綠呈千簇。", "十里風光盡入懷，四時春色常在目。", "好是天開一圖畫，丹青巨擘難描摸。", "閣中仙翁有佳趣，襟抱磊磊還落落。", "飽餐蒼秀炯詩囊，靜挹菁華洗愁斛。", "日暄晝永酒三樽，月明夜清琴一曲。", "興來草木欣榮意，意到鳶魚自飛躍。", "此外應無人境喧，於中覺有天真樂。", "試問仙翁爲阿誰，世良其字陳其族。"]'),
('7bdd6260-4f3a-4c6b-9969-106b7df5c1ae','和林叔己詠揚守福壽林塘之韻','陳淳','宋','宋诗','song-poetry','','[]','史君幽趣鍾靈臺，胸中圖畫如天開。',128,'全唐诗/poet.song.175000.json','["史君幽趣鍾靈臺，胸中圖畫如天開。", "居閒薄發林塘勝，根原福壽兩山來。", "石骨旁峙虎蹲踞，泉脈下繞龍瀊洄。", "高低隨巧結亭榭，收拾造化成錦堆。", "緋黄紫綠獻態度，纖洪濃淡敷條枚。", "四時春色常在目，噓咻無用鄒律催。", "那知禁林鳳池上，須君緩步鏘鳴瓌。", "詎容袖手此山下，龜朋鶴侶相追陪。"]'),
('382d4519-e5c7-4009-9c73-a5ecb3785b91','和林叔己詠福壽林塘韻謝楊守舉狀','陳淳','宋','宋诗','song-poetry','','[]','漳臺最尊第一峰，分支福壽飛雙虹。',392,'全唐诗/poet.song.175000.json','["漳臺最尊第一峰，分支福壽飛雙虹。", "壽山左蟠氣葱葱，福山右峙狀窿窿。", "中有洞壺出塵蹤，景物簇聚造化功。", "不減杜陵門城東，未數漆園舊崆峒。", "高人卓犖關西公，神仙識趣清瀛蓬。", "疏瀹寒泉衆流潈，刮築巖石羣山嵩。", "滌洿剔穢輯和沖，飛甍敞棟勢如穹。", "福壽林塘扁其中，銀鈎鐵畫燦黑松。", "以次亭榭隨窠空，各各標揭題疎通。", "濯纓一點塵不叢，澄澄北繞冰壺融。", "新綠東開青藻芃，磨銅徹底瑩淵衷。", "水竹環之翠垂弓，波光暗射驚魚蟲。", "西問荷花滿地紅，千枝萬朵爛燒空。", "行行半山杖履逢，小憇平章景異同。", "絕巔奇觀趨陰朦，四方八達輝明瓏。", "俯瞰闤闠罔利翁，徒登壟斷誇嵷嵷。", "主人綠鬢碧方瞳，壽山嵯峩福海洪。", "濟川才具如飛𦨴，須遊鳳池職乃充。", "能蘇民瘼如香藭，須從禁苑馳華驄。", "况屢乘麾天眷隆，陽春脚布隨處豐。", "自當九二任發蒙，均陶生民天降侗。", "未應山人邀渤仝，登高臨清玩曨瞳。", "西隣隠霧有豹鼨，欲化龍虎九霄翀。", "卵翼之恩始而終，端頼餘福錫厥躬，庶幾攀附于飛雄。"]'),
('9ef494ff-d0e9-4e96-b5c3-1372c7b67bfd','仙霞嶺歌','陳淳','宋','宋诗','song-poetry','','[]','仙霞何事名仙霞，巔末得之神仙家。',192,'全唐诗/poet.song.175000.json','["仙霞何事名仙霞，巔末得之神仙家。", "此山南來絕高峻，上插雲表參天涯。", "羣仙遊宴絕頂上，不飲烟火湯與茶。", "朝餐赤霞吸其英，暮餐黄霞咀其華。", "日傲烟霞爲洞府，不踏塵寰寸泥沙。", "後躅躋攀不可得，危梯峻級頻咨嗟。", "高人欲解行者疲，掇作好語清而嘉。", "故取仙霞起人慕，非以仙霞爲世誇。", "流傳歲月浸久遠，此意零落說又差。", "謂酌流霞固淺陋，謂著霞衣亦浮葩。", "我來登陟動幽趣，愧無灑落清襟懷。", "聊寓數言代嶺記，未可例視爲南華。"]'),
('95c05d48-54fe-4e0d-80ad-8106797f5551','謁張公祠','陳淳','宋','宋诗','song-poetry','','[]','古來傳說雙劍靈，精氣直上干雲星。',96,'全唐诗/poet.song.175000.json','["古來傳說雙劍靈，精氣直上干雲星。", "有如掘出爲世用，一揮便可四海清。", "方今擾擾邊塵起，中原分裂亂無紀。", "正好提携爲掃平，何事雙龍卧此水。", "試問張公知不知，英靈千載如生時。", "何時神物得神用，爲報風雲會合期。"]'),
('c10f25aa-67a7-4631-b6d5-91f104f25772','三月十一夜紀候','陳淳','宋','宋诗','song-poetry','','[]','春光正濃二三月，氣候不作春和柔。',32,'全唐诗/poet.song.175000.json','["春光正濃二三月，氣候不作春和柔。", "白晝炎炎若盛夏，半夜凄凄如老秋。"]'),
('5752a380-647d-4377-a98f-330ed51ec799','久不雨','陳淳','宋','宋诗','song-poetry','','[]','草廬卧龍目未開，巖溪作霖手未擡。',32,'全唐诗/poet.song.175000.json','["草廬卧龍目未開，巖溪作霖手未擡。", "蒼生望望亦勞爾，霶霈甘澤從何來。"]'),
('6a9f514a-84c8-4b75-9a38-71548c99146b','賀傅寺丞喜雨二十六韻','陳淳','宋','宋诗','song-poetry','','[]','去冬九旬已渴雨，那意今春渴尤苦。',384,'全唐诗/poet.song.175000.json','["去冬九旬已渴雨，那意今春渴尤苦。", "自開正元越三月，生意全蟄不闖吐。", "陽威烈烈熾盛夏，田野熬熬劇焦釜。", "新秧既長且乾萎，播種無由可入土。", "農民望雨若倒垂，類嘆天命我無所。", "太守念膺民命寄，如傷體膚痛心膂。", "奔禱山川社稷前，下及百祠靡不舉。", "壇告雷師雷莫聞，江叩龍神龍弗顧。", "間或沾洒隨即收，翹想霶霈殊烏有。", "日切一日不遑寧，直欲伐牲實籩俎。", "精虔充積四十朝，幽明貫徹忽無阻。", "季春望夜五鼓餘，瓦鳴琢琢簷垂縷。", "起來四顧雲黑暝，阿香驅車震鼉鼓。", "甘霔一番復一番，達晝傾盆莫之禦。", "東阡西陌土膏溶，負耒荷鋤翕旁午。", "父語其子兄語弟，或曰我侯感格故。", "滴滴皆是真珠飯，天救我民賜我哺。", "非我下民能動天，侯澤我民如父母。", "既優既渥尚未已，實穎實栗决可睹。", "人解戚容爲懽忻，歲轉凶兆爲豐阜。", "從知天人本一機，氣脈流通有如許。", "端猶影響應形聲，證驗昭昭真足數。", "亦侯作霖大手段，家學淵源傳自古。", "豈徒蕞爾南漳濱，特私所惠偏一塢。"]'),
('8335e832-9fd5-4d44-afbb-f9264fad59d4','訓兒童八首 孔子','陳淳','宋','宋诗','song-poetry','','[]','孔子生東魯，斯文實在茲。',24,'全唐诗/poet.song.175000.json','["孔子生東魯，斯文實在茲。", "六經垂訓法，萬世共宗師。"]'),
('8d8176bf-dcca-4e3a-997b-7af11237b0f2','訓兒童八首 弟子','陳淳','宋','宋诗','song-poetry','','[]','洙泗三千衆，何人得正傳。',24,'全唐诗/poet.song.175000.json','["洙泗三千衆，何人得正傳。", "省身有曾子，克己獨顔淵。"]'),
('7521a8d3-01a9-4cef-b677-4bc6e0feff28','訓兒童八首 顔子','陳淳','宋','宋诗','song-poetry','','[]','賢哉顔氏子，陋巷獨幽居。',24,'全唐诗/poet.song.175000.json','["賢哉顔氏子，陋巷獨幽居。", "簞食與瓢飲，蕭然樂有餘。"]'),
('3f2783c2-11aa-4486-9cbe-badcee600e09','訓兒童八首 曾子','陳淳','宋','宋诗','song-poetry','','[]','敬謹曾參氏，臨深履薄如。',24,'全唐诗/poet.song.175000.json','["敬謹曾參氏，臨深履薄如。", "平生傳聖訓，要具孝經書。"]'),
('0a9fc3ec-4c2b-4144-9503-56e6932d59a6','訓兒童八首 人子','陳淳','宋','宋诗','song-poetry','','[]','人子勤於孝，無時志不存。',24,'全唐诗/poet.song.175000.json','["人子勤於孝，無時志不存。", "夜來安寢息，早起問寒暄。"]'),
('36ee5cf9-1d83-4f25-9a4a-dce128fb14c3','訓兒童八首 灑掃','陳淳','宋','宋诗','song-poetry','','[]','奉水微微洒，恭提帚與箕。',24,'全唐诗/poet.song.175000.json','["奉水微微洒，恭提帚與箕。", "室堂須淨掃，几案亦輕麾。"]'),
('5577d9f3-5cd8-4610-9e56-80db80a1acbb','訓兒童八首 應對','陳淳','宋','宋诗','song-poetry','','[]','應對須恭謹，言言罔不祗。',24,'全唐诗/poet.song.175000.json','["應對須恭謹，言言罔不祗。", "父呼唯無諾，長問遜爲辭。"]'),
('8a6d9597-083e-4489-98e2-23a70f5eb773','訓兒童八首 進退','陳淳','宋','宋诗','song-poetry','','[]','進退須恭敬，時時勿敢輕。',24,'全唐诗/poet.song.175000.json','["進退須恭敬，時時勿敢輕。", "先生趨拱立，長者後徐行。"]'),
('71962e15-9409-4e38-8d38-f6ef57da418e','西征黄蓮坑遇雪','陳淳','宋','宋诗','song-poetry','','[]','行入黄蓮北，風嚴雪又加。',48,'全唐诗/poet.song.175000.json','["行入黄蓮北，風嚴雪又加。", "滿山羅玉樹，遍地錯瓊花。", "清灑姿無纇，虛明質不華。", "瘴眸爲一洗，驚覺若仙家。"]'),
('722a61b6-0822-414c-9277-f6f545cd8915','分水嶺','陳淳','宋','宋诗','song-poetry','','[]','寶貝山前去，瓊瑶世界行。',48,'全唐诗/poet.song.175000.json','["寶貝山前去，瓊瑶世界行。", "蠟鞋穿瑟瑟，竹杖獨鏗鏗。", "凍色迫毛竅，寒光射眼晴。", "酒亭何處認，速欲一壺傾。"]'),
('7a3926bd-b4b8-41a6-a648-727b85fd7d8f','祝杖投錢唐江','陳淳','宋','宋诗','song-poetry','','[]','爾自黄源嶺，相從到上都。',48,'全唐诗/poet.song.175000.json','["爾自黄源嶺，相從到上都。", "扶持千險阻，策掖萬崎嶇。", "鳳沼波應煖，龍門路不迂。", "便須齊變化，霈澤濟寰區。"]'),
('e8c01e32-93f3-4d57-a197-2d4059dc9b81','和陳叔餘韻二首一以謝來意一以勉之  其一','陳淳','宋','宋诗','song-poetry','','[]','碌碌平生學，慚無席上珍。',48,'全唐诗/poet.song.175000.json','["碌碌平生學，慚無席上珍。", "僅餘守師訓，豈欲衒時人。", "誤入侯門聽，翻勞友義陳。", "願從溫故業，庶或稍知新。"]'),
('08d94479-52af-4865-838c-15113b79bc52','和陳叔餘韻二首一以謝來意一以勉之  其二','陳淳','宋','宋诗','song-poetry','','[]','此道何曾遠，吾儒自有珍。',48,'全唐诗/poet.song.175000.json','["此道何曾遠，吾儒自有珍。", "反求皆在我，中畫豈由人。", "利善分須白，知行語未陳。", "若能祛舊見，明德日惟新。"]'),
('ee68b99b-a40b-4c70-9ee9-724225de80c1','送王子正宰長樂二首  其一','陳淳','宋','宋诗','song-poetry','','[]','一陽天運復來亨，君子隨時亦吉征。',64,'全唐诗/poet.song.175000.json','["一陽天運復來亨，君子隨時亦吉征。", "暫向三山瀕海處，小馳百里愛人聲。", "從知文物新長樂，便作絃歌舊武城。", "須信道行由此兆，牛刀指日宰寰瀛。"]'),
('17e3335b-220d-42f5-8446-3d555e0983ec','送王子正宰長樂二首  其二','陳淳','宋','宋诗','song-poetry','','[]','君當民社戴星遊，我玩簞瓢守故丘。',64,'全唐诗/poet.song.175000.json','["君當民社戴星遊，我玩簞瓢守故丘。", "袂自此分何所憾，學無與講是吾憂。", "聖心未可窺覘得，道體難從寡陋求。", "鱗翼元無南北間，時推緒論發蒙不。"]'),
('d1037d9c-e9b5-47df-b757-955063ba8b0f','送瘳子晦倅潮還別四絕  其一','陳淳','宋','宋诗','song-poetry','','[]','紫陽門戶聳參天，駢往紛來幾計千。',32,'全唐诗/poet.song.175000.json','["紫陽門戶聳參天，駢往紛來幾計千。", "誰立脚跟老彌篤，交溪原上有深傳。"]'),
('61528788-e5c9-4381-a0a4-fd4c474b0cbb','送瘳子晦倅潮還別四絕  其二','陳淳','宋','宋诗','song-poetry','','[]','使車南騖過吾邦，幸挹端嚴毅直風。',32,'全唐诗/poet.song.175000.json','["使車南騖過吾邦，幸挹端嚴毅直風。", "多謝兩年勤尺素，諄諄頻爲發童蒙。"]'),
('9adc4e61-2e7a-4899-ae1d-758b2c540798','送瘳子晦倅潮還別四絕  其三','陳淳','宋','宋诗','song-poetry','','[]','松窗梅雪歲寒餘，奉別城東古驛頭。',32,'全唐诗/poet.song.175000.json','["松窗梅雪歲寒餘，奉別城東古驛頭。", "君去有行應可樂，我來獨學重爲憂。"]'),
('8786c4bf-9bf2-455f-881d-40632166b4cc','送瘳子晦倅潮還別四絕  其四','陳淳','宋','宋诗','song-poetry','','[]','聖賢事業浩無疆，未易孤聞寡見窮。',32,'全唐诗/poet.song.175000.json','["聖賢事業浩無疆，未易孤聞寡見窮。", "友善更資天下士，時推一二附南鴻。"]'),
('2a7c9bc4-7a81-4797-a008-06903b644885','送廖婿林伯魯東歸南寺席中因舉送王長樂詩伯魯用後篇韻求教故復依其韻以別之','陳淳','宋','宋诗','song-poetry','','[]','良夜禪房款一遊，義心相與重山丘。',64,'全唐诗/poet.song.175000.json','["良夜禪房款一遊，義心相與重山丘。", "少陪文字賡酬樂，頓釋胸懷鄙隠憂。", "我愧反身無寸得，君方努力勇前求。", "懸知日有新新益，還肯雙魚遠寄不。"]'),
('1e620ccb-9502-46fa-b57f-bb90fcf964cd','和丁祖舜重修日涉園','陳淳','宋','宋诗','song-poetry','','[]','重來日涉整前盟，欲與淵明細論朋。',64,'全唐诗/poet.song.175000.json','["重來日涉整前盟，欲與淵明細論朋。", "向市閙中渾覺勝，可人幽處不妨仍。", "歲寒依舊竹三逕，春意長新花數棚。", "對景舂容無一事，好將氣馬款調乘。"]'),
('8d87a99f-8ff2-44cf-8284-023e40b522dd','依趙尉獄空韻上陳宰','陳淳','宋','宋诗','song-poetry','','[]','民沐仁風狀小兒，陶陶遠罪日何知。',64,'全唐诗/poet.song.175000.json','["民沐仁風狀小兒，陶陶遠罪日何知。", "圜扉草色春長茂，公舍棠陰晝緩移。", "誰復鼠牙紛擊剝，類將雞黍樂追隨。", "塗歌里詠喧傳處，盡是吾侯德政碑。"]'),
('c857aeaf-41cf-4b0d-ad16-cefa113fa48c','依方宗丞和林簽判賞梅進璧水之韵','陳淳','宋','宋诗','song-poetry','','[]','冰玉精神清且凝，不嫌霜霜慘於刑。',64,'全唐诗/poet.song.175000.json','["冰玉精神清且凝，不嫌霜霜慘於刑。", "傳來春信嚴明地，吐出陽和節愛亭。", "孤艷迥凌仙子桂，餘香暗及庶民星。", "尋盟璧水渾閒事，好整和羹入帝庭。"]'),
('794c87c5-4d67-4f3f-9a1b-8b01c6e60eef','送陳尉后之園  其一','陳淳','宋','宋诗','song-poetry','','[]','巖邑崎嶇俗最獰，君來談笑自風生。',64,'全唐诗/poet.song.175000.json','["巖邑崎嶇俗最獰，君來談笑自風生。", "平戎大策方微露，執訊奇功便立成。", "百里秋光瓜代及，九重春色笋班榮。", "金閨此去應無阻，好把胸中次第行。"]'),
('e733c78e-1b67-4c54-89a7-c233d4557031','送陳尉后之園  其二','陳淳','宋','宋诗','song-poetry','','[]','世論年來太不和，真真僞僞總偏頗。',64,'全唐诗/poet.song.175000.json','["世論年來太不和，真真僞僞總偏頗。", "陽尊孔孟陰排斥，深怯周程浪詆訶。", "誰是橫流堅立砥，類於入室反操戈。", "始終無負傳心處，一片精剛要不磨。"]'),
('dc7aa3e4-553c-4749-af5f-bff6ef6ef0e5','送滕教歸二首  其一','陳淳','宋','宋诗','song-poetry','','[]','本是山林一陋蒙，何心馳騖利名中。',64,'全唐诗/poet.song.175000.json','["本是山林一陋蒙，何心馳騖利名中。", "只因尺檄來蓬戶，故策駑才入藻宮。", "既爾薰陶知厚德，又於歷練熟頹風。", "區區未飫高山仰，何事征蹄今已東。"]'),
('ae6cba91-dc02-4ae9-a6d5-5824a7f1168a','送滕教歸二首  其二','陳淳','宋','宋诗','song-poetry','','[]','驛道芬菲春氣柔，征蹄去去不容留。',64,'全唐诗/poet.song.175000.json','["驛道芬菲春氣柔，征蹄去去不容留。", "俯辭南國摳衣佩，直向端門拜冕旒。", "璧沼從知新訓導，石渠旋復細刊讎。", "澤民致主淵源學，那或浮沉逐輩流。"]'),
('58e5565a-645e-479b-a91a-80cc9a4cf5fd','不赴十姊初度之席','陳淳','宋','宋诗','song-poetry','','[]','吾姊今朝慶誕辰，奈何賤弟亦同倫。',64,'全唐诗/poet.song.175000.json','["吾姊今朝慶誕辰，奈何賤弟亦同倫。", "汝逢壽考榮雙老，我感劬勞悼昔人。", "贊祝欲陪千歲願，追思難遏寸心真。", "一懽一戚應殊分，只任天情不必均。"]'),
('27590ba1-3af8-4fa8-9c2c-98d5d0eaaefd','湖齋對蓮','陳淳','宋','宋诗','song-poetry','','[]','平湖花葉亂相撐，恰對幽齋小榻清。',64,'全唐诗/poet.song.175000.json','["平湖花葉亂相撐，恰對幽齋小榻清。", "萬綠淺深非作意，千紅濃淡總無情。", "好觀物態羣嘉萃，從識乾元一理生。", "佔畢暇餘時與玩，會予心處有誰評。"]'),
('8c0dcf61-3a59-4696-bacb-c9b35dec497c','對葵','陳淳','宋','宋诗','song-poetry','','[]','開闔隨陽自曉昏，輕如綃縠凈瑶琨。',64,'全唐诗/poet.song.175000.json','["開闔隨陽自曉昏，輕如綃縠凈瑶琨。", "淡黄相枕五重靚，濃紫深藏一竅渾。", "熟視絕無粧點態，細看不見剪裁痕。", "誰能會取箇中意，與玩乾坤造化根。"]'),
('229a533b-c38e-4603-b8e8-79269c870589','和丁大詠史君禱雨之韻','陳淳','宋','宋诗','song-poetry','','[]','史君持志一恭謙，何間幽明與巨纖。',64,'全唐诗/poet.song.175000.json','["史君持志一恭謙，何間幽明與巨纖。", "渴雨方將爲旱閔，卧龍便不復泥潛。", "連宵頗作霶𩃱注，闔郡均蒙優渥沾。", "竊喜陽春端有脚，閭閻和氣日須添。"]'),
('bc602b69-f6e2-4a5f-9ea5-dd8ca3162725','用明師叔韻贈畫工張子英','陳淳','宋','宋诗','song-poetry','','[]','雖憑縑素狀儀容，的自毫心藴妙鋒。',32,'全唐诗/poet.song.175000.json','["雖憑縑素狀儀容，的自毫心藴妙鋒。", "箇箇本來天所賦，隨人變化有奇工。"]'),
('f7160ac1-114d-4c5a-9b99-be292bb8bd2a','送王子正赴灨倅  其一','陳淳','宋','宋诗','song-poetry','','[]','飛騰仙馭自漳濱，去去西隅指灨津。',64,'全唐诗/poet.song.175000.json','["飛騰仙馭自漳濱，去去西隅指灨津。", "夾道賓僚方一際，滿城老稚便皆春。", "正心誠意平生學，愛物親民此日仁。", "只恐貳藩車未煖，紫泥催促貳皇鈞。"]'),
('1b1022aa-cc56-4784-b4e6-903e815aa814','送王子正赴灨倅  其二','陳淳','宋','宋诗','song-poetry','','[]','昔日濂溪倅此州，施爲洒落豈常儔。',64,'全唐诗/poet.song.175000.json','["昔日濂溪倅此州，施爲洒落豈常儔。", "今承遺躅百餘載，又得當朝一雋流。", "詔世典刑應未泯，在民德化豈無求。", "發揮舊事重增煥，好與邦人作勝謀。"]'),
('40c8f94b-866f-4769-a010-c509552eba2b','子方宗弟側弄之璋','陳淳','宋','宋诗','song-poetry','','[]','珍祥充塞故旁流，底信先傳慶有由。',64,'全唐诗/poet.song.175000.json','["珍祥充塞故旁流，底信先傳慶有由。", "莫訝雞胞寧吐鳳，須知虎氣已吞牛。", "古來孽士皆榮達，此日宗支自穎尤。", "蟄蟄繩繩從未艾，會看貴種出公侯。"]'),
('56f487fc-8bec-436f-9187-38ac50f37d86','西征范田遇雪三絕  其一','陳淳','宋','宋诗','song-poetry','','[]','夜宿荒村曰范田，聲聲頻滴屋簷前。',32,'全唐诗/poet.song.175000.json','["夜宿荒村曰范田，聲聲頻滴屋簷前。", "朝來揭起柴扉看，滿目青山白玉巔。"]'),
('369a26f7-ffca-4439-a550-93884b4d9bac','西征范田遇雪三絕  其二','陳淳','宋','宋诗','song-poetry','','[]','飽啗炊粱萊菔羹，皂臺催促趕前程。',32,'全唐诗/poet.song.175000.json','["飽啗炊粱萊菔羹，皂臺催促趕前程。", "手携竹杖足穿革，緩撥瓊花徒步行。"]'),
('82213013-6a85-48f6-8954-eac79076d5f1','西征范田遇雪三絕  其三','陳淳','宋','宋诗','song-poetry','','[]','歷歷山坳凍迫人，指頭欲墮痹難伸。',32,'全唐诗/poet.song.175000.json','["歷歷山坳凍迫人，指頭欲墮痹難伸。", "探囊速買三杯後，更覺陽和暢此身。"]'),
('50e7a94b-eab2-46fd-9695-33288857549c','大漿嶺','陳淳','宋','宋诗','song-poetry','','[]','大漿陟降幾千層，積雪朝來錯去程。',64,'全唐诗/poet.song.175000.json','["大漿陟降幾千層，積雪朝來錯去程。", "溜石瓊花新琢就，平田玉鏡恰塵成。", "不嫌凍氣侵肌慄，最愛清姿照膽明。", "聊把杖頭敲擊處，那忘疲苶旅中情。"]'),
('c3393730-cc93-48ee-8ecd-333c8659e57b','過武夷','陳淳','宋','宋诗','song-poetry','','[]','武夷山下幾迴過，未暇於中賞一遭。',32,'全唐诗/poet.song.175000.json','["武夷山下幾迴過，未暇於中賞一遭。", "獅鶴諸仙知我意，故將青靄淡遮羅。"]'),
('b78fd99c-f9dc-4da6-9780-3d29ee36bc67','紫溪遇日','陳淳','宋','宋诗','song-poetry','','[]','日露雪頭紅玉盤，氤氳和氣靄人寰。',32,'全唐诗/poet.song.175000.json','["日露雪頭紅玉盤，氤氳和氣靄人寰。", "回眸萬素無從覓，依舊千山列翠鬟。"]'),
('54a88103-a163-4321-aa47-720fc06811ab','鉛山遇霜','陳淳','宋','宋诗','song-poetry','','[]','冒風冒雪冒霜寒，手足胼胝百狀艱。',32,'全唐诗/poet.song.175000.json','["冒風冒雪冒霜寒，手足胼胝百狀艱。", "只爲胸中春一點，未能忘世卧溪山。"]'),
('471a4098-9418-4575-9d10-55663afece59','和梅韻','陳淳','宋','宋诗','song-poetry','','[]','不妨雪壓與霜糊，友結松筠鄙橘奴。',64,'全唐诗/poet.song.175000.json','["不妨雪壓與霜糊，友結松筠鄙橘奴。", "特放孤標先煖覺，肯隨衆卉望寒逋。", "疑將冰月爲精爽，端借瓊瑶琢體膚。", "闖出一元生物意，從茲引領萬容姝。"]'),
('a9b44477-e631-417f-b6ed-ccd00d8df006','示兒定孫二絕  其一','陳淳','宋','宋诗','song-poetry','','[]','童蒙發軔最初時，庸聖分岐謹所之。',32,'全唐诗/poet.song.175000.json','["童蒙發軔最初時，庸聖分岐謹所之。", "凡百小兒嬉戲事，汝皆鄙俚不須爲。"]'),
('68141e1c-cb17-4fe1-852b-0ed1eb83a077','示兒定孫二絕  其二','陳淳','宋','宋诗','song-poetry','','[]','丈夫尚志志高明，勿效卑卑世俗情。',32,'全唐诗/poet.song.175000.json','["丈夫尚志志高明，勿效卑卑世俗情。", "從上一條平坦路，千賢萬聖所通行。"]'),
('a4b86655-721b-41e4-bced-89367e224f08','鄰舍橫逆','陳淳','宋','宋诗','song-poetry','','[]','茫茫薄俗沸蚊蛆，禮義全無一點餘。',64,'全唐诗/poet.song.175000.json','["茫茫薄俗沸蚊蛆，禮義全無一點餘。", "只得杜門對賢聖，專來教子讀詩書。", "千般橫直休干己，一切是非無問渠。", "若救鄉鄰爲被髮，風波轉起撓吾廬。"]'),
('bd5eee7b-9494-43e0-baa6-64c901b7ec9d','西征過仙霞雪晴','陳淳','宋','宋诗','song-poetry','','[]','自入仙霞十里程，滿山晴雪射虛明。',64,'全唐诗/poet.song.175000.json','["自入仙霞十里程，滿山晴雪射虛明。", "路從寶貝洞中去，人在瓊瑶世界行。", "枯木競傳千狀巧，荒崖亦作十分清。", "回環四望真奇觀，識破乾坤洒落情。"]'),
('6bb51a50-bfd6-462d-a5c0-26aede0cd8d1','過江山遇雪','陳淳','宋','宋诗','song-poetry','','[]','江山方進半程前，正值羣遊剪水仙。',64,'全唐诗/poet.song.175000.json','["江山方進半程前，正值羣遊剪水仙。", "滿道鹽花堆粲粲，飛空粉屑舞翩翩。", "樊牆廬舍皆銀飾，溝瀆潢汙盡玉瑱。", "却認青山埋不得，嶆峨氣勢直凌天。"]'),
('88515273-1b4c-42fe-bb7c-cb47c4321ab6','平坦雪兼風雨','陳淳','宋','宋诗','song-poetry','','[]','自從平坦望衢南，值雪霏霏日日添。',64,'全唐诗/poet.song.175000.json','["自從平坦望衢南，值雪霏霏日日添。", "既挾狂風和面撲，又偕猛雨向身沾。", "手拈紙傘凝猶痹，足踏皮鞋凍亦漸。", "那識堅剛金石操，於中凜凜獨爭嚴。"]'),
('946690d0-e5ed-4ab8-8da9-350c400e0d1f','玩雪','陳淳','宋','宋诗','song-poetry','','[]','南人乍見此般奇，驚怪誰司妙化機。',64,'全唐诗/poet.song.175000.json','["南人乍見此般奇，驚怪誰司妙化機。", "月裏姮娥篩粉撒，雲端仙子削瓊飛。", "寶山瑶室隨村峙，玉樹銀花夾道輝。", "造物襟懷真洒落，更無塵滓間纖微。"]'),
('d8f4320b-199d-4f55-b2d9-9478f5bf7107','過衢州第二程見麥雪中青','陳淳','宋','宋诗','song-poetry','','[]','雪過三衢越厚埋，却於農事不爲災。',32,'全唐诗/poet.song.175000.json','["雪過三衢越厚埋，却於農事不爲災。", "今朝方爾半融釋，隴麥青青奮出來。"]'),
('1fc91f2d-dbb9-4226-a893-cd6fc698a463','答留粹中承奉求教之韻','陳淳','宋','宋诗','song-poetry','','[]','玉質雖精更用礲，切磋磨琢趣無窮。',64,'全唐诗/poet.song.175000.json','["玉質雖精更用礲，切磋磨琢趣無窮。", "但於天理昭如視，何患私情衆互攻。", "明善誠身爲要訣，博文約禮是深功。", "從今日用培基處，敬道尤須徹始終。"]'),
('b7dffaf8-84d5-4638-af42-3a41b7da98b5','橫逆自廣三絕  其一','陳淳','宋','宋诗','song-poetry','','[]','湯文事小豈爲迷，物我從來絕町畦。',32,'全唐诗/poet.song.175000.json','["湯文事小豈爲迷，物我從來絕町畦。", "胸次洞然天地闊，本無南北與東西。"]'),
('b7f41276-44b9-4620-890d-a9e111a1b0c0','橫逆自廣三絕  其二','陳淳','宋','宋诗','song-poetry','','[]','樂天一說見軻書，豈是高談强解渠。',32,'全唐诗/poet.song.175000.json','["樂天一說見軻書，豈是高談强解渠。", "牛馬蚊虻無足校，不須芥蔕此襟裾。"]'),
('c98b9fd5-0591-409e-9ec7-20689a642b68','橫逆自廣三絕  其三','陳淳','宋','宋诗','song-poetry','','[]','仁人方寸萬機空，片逆何能介此中。',32,'全唐诗/poet.song.175000.json','["仁人方寸萬機空，片逆何能介此中。", "視爾恰如風動竹，在予安有竹嫌風。"]'),
('6e7ba60d-7926-4ee8-9288-70462a596962','趙守禮延入學陳伯躍有詩詠其事因和以復之','陳淳','宋','宋诗','song-poetry','','[]','趙學規模本自宏，師傳敢背此心盟。',64,'全唐诗/poet.song.175000.json','["趙學規模本自宏，師傳敢背此心盟。", "追思嚴訓昭如在，立誓終身篤所行。", "每患無成辜宿志，那知自鬻釣浮名。", "賢侯愛友交提奬，重我慚惶未見榮。"]'),
('e994ac56-ee24-4d0c-9b46-9dad085346ff','修學扁大成殿門依敖教韻上趙寺丞','陳淳','宋','宋诗','song-poetry','','[]','育才爲國寸心丹，修泮時聞鏘八鸞。',64,'全唐诗/poet.song.175000.json','["育才爲國寸心丹，修泮時聞鏘八鸞。", "綠引滄溟循道入，青徘名第對門看。", "宸鈎日煥龍蛇動，書閣雲齊牛斗寒。", "末學幸陪芹藻豆，詎耽秋菊夕英餐。"]'),
('d4b16357-6b39-4589-a1b7-a72d94d646f6','存心','陳淳','宋','宋诗','song-poetry','','[]','心藏隠奧最難知，出入無時不可羈。',32,'全唐诗/poet.song.175000.json','["心藏隠奧最難知，出入無時不可羈。", "須向動時牢把住，莫教失却便支離。"]'),
('636381de-0b67-479c-ad2e-fdd84a138cc4','和卓廷瑞贈詩之韻四絕  其一','陳淳','宋','宋诗','song-poetry','','[]','一見襟懷便豁然，交情輸寫意忘年。',32,'全唐诗/poet.song.175000.json','["一見襟懷便豁然，交情輸寫意忘年。", "傾囊經訓璠璵富，與我從頭細細傳。"]'),
('0d3f504e-abd7-424c-a2bb-6a63902215e9','和卓廷瑞贈詩之韻四絕  其二','陳淳','宋','宋诗','song-poetry','','[]','日復陪遊泮水湄，發揮史學到淵微。',32,'全唐诗/poet.song.175000.json','["日復陪遊泮水湄，發揮史學到淵微。", "直從天理人心處，剖破存亡治亂機。"]'),
('b99849a0-22b3-4a50-8a21-615f95477708','和卓廷瑞贈詩之韻四絕  其三','陳淳','宋','宋诗','song-poetry','','[]','長書一卷墨新題，志在斯民壽域躋。',32,'全唐诗/poet.song.175000.json','["長書一卷墨新題，志在斯民壽域躋。", "歷歷愛君憂國語，施行須自起鋤犁。"]'),
('57f9b4b7-cf42-498a-92d5-3555eb751df3','和卓廷瑞贈詩之韻四絕  其四','陳淳','宋','宋诗','song-poetry','','[]','我愧年幾六十秋，時華虛度事優柔。',32,'全唐诗/poet.song.175000.json','["我愧年幾六十秋，時華虛度事優柔。", "頭云皓矣未聞道，深藉磨礱與勿休。"]'),
('22298ac2-8270-4f97-99e2-48d99d86c67a','林戶求明道堂詩二首  其一','陳淳','宋','宋诗','song-poetry','','[]','秉彝同是得天生，道在其中本自明。',64,'全唐诗/poet.song.175000.json','["秉彝同是得天生，道在其中本自明。", "氣爲稟來微有蔽，欲因感處復多萌。", "磨礱須到十分粹，克治全教一味清。", "從此洞然無別體，真元輝露日光星。"]'),
('4959fe40-37ea-40e0-b504-febdaefc8bdd','林戶求明道堂詩二首  其二','陳淳','宋','宋诗','song-poetry','','[]','自從河洛發真筌，節目綱條已粲然。',64,'全唐诗/poet.song.175000.json','["自從河洛發真筌，節目綱條已粲然。", "志若堅剛方可適，心如扞格决難詮。", "從頭格物爲當務，穩步求仁乃秘傳。", "表裏直須名副實，高標終不愧前賢。"]'),
('aca0cb89-6a41-4eea-aedf-5ae1b90d272d','遊雷峰塔處晦上人求詩','陳淳','宋','宋诗','song-poetry','','[]','擺脫人間名利韁，湖山深處事韜藏。',32,'全唐诗/poet.song.175000.json','["擺脫人間名利韁，湖山深處事韜藏。", "要知晦裏真消息，養取靈臺一點光。"]'),
('53712e28-2fcf-4830-8ed5-559ec49cda23','無言上人求詩依黄簿韻','陳淳','宋','宋诗','song-poetry','','[]','休說西來幾許年，此身動靜莫非禪。',64,'全唐诗/poet.song.175000.json','["休說西來幾許年，此身動靜莫非禪。", "須知天理流行妙，不待人言髣髴傳。", "運水搬柴存實則，著衣喫飯即當然。", "若能默悟真消息，剖破諸空億大千。"]'),
('be9225dd-9bda-43f3-9251-177cb0098add','寓嚴陵學和鄧學錄相留之韻','陳淳','宋','宋诗','song-poetry','','[]','道爲賢侯講泮宮，淵源程子及周翁。',64,'全唐诗/poet.song.175000.json','["道爲賢侯講泮宮，淵源程子及周翁。", "路開正脈同歸極，川障狂瀾浪駕空。", "珍重前廊渾氣合，督提後進要心通。", "聖門相與從容入，矩步規行不用匆。"]'),
('b80b4736-0d99-4c61-aae3-d3e9622542b5','題蓋竹廟六絕  其一','陳淳','宋','宋诗','song-poetry','','[]','人心污物本來靈，動靜那分晦與明。',32,'全唐诗/poet.song.175000.json','["人心污物本來靈，動靜那分晦與明。", "晝接事爲思有主，夜思無主夢因成。"]'),
('f8867079-f773-47fc-a449-d31bd37fbd56','題蓋竹廟六絕  其二','陳淳','宋','宋诗','song-poetry','','[]','夢生於想本來非，一自魂交百感隨。',32,'全唐诗/poet.song.175000.json','["夢生於想本來非，一自魂交百感隨。", "漠漠茫茫無定準，若何據此卜前逵。"]'),
('92861f1d-05c5-4f47-bb86-9b75684d266f','題蓋竹廟六絕  其三','陳淳','宋','宋诗','song-poetry','','[]','世人莫悟此端原，兆自心機闢闔間。',32,'全唐诗/poet.song.175000.json','["世人莫悟此端原，兆自心機闢闔間。", "却向妖祠求證應，妖祠於我固何關。"]'),
('af01f69a-a66a-44a2-bed2-90d2a9b44f70','題蓋竹廟六絕  其四','陳淳','宋','宋诗','song-poetry','','[]','至人神定氣常清，夜息虛明一若醒。',32,'全唐诗/poet.song.175000.json','["至人神定氣常清，夜息虛明一若醒。", "假使妖祠能獻兆，如何窺得此門庭。"]'),
('9619f09e-772b-4c52-b3f8-fee3cdb7031b','題蓋竹廟六絕  其五','陳淳','宋','宋诗','song-poetry','','[]','大都流俗急榮名，切切於中夢自形。',32,'全唐诗/poet.song.175000.json','["大都流俗急榮名，切切於中夢自形。", "附會便爲神所告，神明虛得號通靈。"]'),
('44d0d6fb-af9c-4888-85ec-3c28fe29fa7f','題蓋竹廟六絕  其六','陳淳','宋','宋诗','song-poetry','','[]','升沉大分係於天，决匪人謀所必然。',32,'全唐诗/poet.song.175000.json','["升沉大分係於天，决匪人謀所必然。", "告爾往來通達者，不須贅贅鬼神前。"]'),
('d5584905-28f7-4194-90b8-09301132e110','馮中郎廟','陳淳','宋','宋诗','song-poetry','','[]','爲問中郎昔抗忠，力箴頗牧不能庸。',32,'全唐诗/poet.song.175000.json','["爲問中郎昔抗忠，力箴頗牧不能庸。", "如今疆埸多塵擾，頗牧還能容不容。"]'),
('b3484ef1-14c2-4622-9310-2666d318f219','西楚霸王廟二絕  其一','陳淳','宋','宋诗','song-poetry','','[]','氣壓關河力拔山，絕人武勇更無前。',32,'全唐诗/poet.song.175000.json','["氣壓關河力拔山，絕人武勇更無前。", "若於今代當戎寄，子弟何須用八千。"]'),
('4c127575-a970-43a6-a792-84f73b6d1f19','西楚霸王廟二絕  其二','陳淳','宋','宋诗','song-poetry','','[]','轍亂旗靡繞舊畿，烽烟起處羽書馳。',32,'全唐诗/poet.song.175000.json','["轍亂旗靡繞舊畿，烽烟起處羽書馳。", "思君一劍爲平蕩，蓋世英魂知不知。"]'),
('c39f94a1-0562-4910-bf00-d641c9cf8597','題江郎廟六絕  其一','陳淳','宋','宋诗','song-poetry','','[]','三石參天作柱擎，自從開闢便崢嶸。',32,'全唐诗/poet.song.175000.json','["三石參天作柱擎，自從開闢便崢嶸。", "何爲末俗爲奇怪，盡道江郎魄化成。"]'),
('482a7d50-aa36-4ef4-976c-fd6dcf42d99a','題江郎廟六絕  其二','陳淳','宋','宋诗','song-poetry','','[]','緣爾江家兄弟三，平生愛此石巖巖。',32,'全唐诗/poet.song.175000.json','["緣爾江家兄弟三，平生愛此石巖巖。", "寓居石下多年代，陋俗因成附會談。"]'),
('7fba616e-b28f-465c-97bb-91d7efd9ed62','題江郎廟六絕  其三','陳淳','宋','宋诗','song-poetry','','[]','好看三石絕奇蹤，自是山靈氣所鍾。',32,'全唐诗/poet.song.175000.json','["好看三石絕奇蹤，自是山靈氣所鍾。", "致雨興雲功利博，合編祀典以神封。"]'),
('825bd901-2013-4964-bced-c72983c1247b','題江郎廟六絕  其四','陳淳','宋','宋诗','song-poetry','','[]','禮經岳瀆視公侯，只謂祠儀一例修。',32,'全唐诗/poet.song.175000.json','["禮經岳瀆視公侯，只謂祠儀一例修。", "不識鬼神情狀者，錯將經意以人求。"]'),
('a935f8c9-6e95-42ea-b69a-8c7531c98248','題江郎廟六絕  其五','陳淳','宋','宋诗','song-poetry','','[]','峙立嶆峨本石形，人其廟貌據何經。',32,'全唐诗/poet.song.175000.json','["峙立嶆峨本石形，人其廟貌據何經。", "祗宜壇壝爲民禱，時雨時暘便是靈。"]'),
('7c58d415-c010-4fcc-a1a0-fef0449bc30f','題江郎廟六絕  其六','陳淳','宋','宋诗','song-poetry','','[]','禮學無人發世蒙，正神流弊與妖同。',32,'全唐诗/poet.song.175000.json','["禮學無人發世蒙，正神流弊與妖同。", "既非氣類相求者，豈解精誠妙感通。"]'),
('3f48f9bd-8c64-44e6-8162-177e316d9627','和傅侍郎至臨漳感舊十詠  其一','陳淳','宋','宋诗','song-poetry','','[]','陽復東郊雨閣絲，歡迎父老擁車隨。',32,'全唐诗/poet.song.175000.json','["陽復東郊雨閣絲，歡迎父老擁車隨。", "競傳碧眼朱顔在，宛若當年剖竹時。"]'),
('aad97c73-6bd5-4548-a46f-c112505d1e5d','和傅侍郎至臨漳感舊十詠  其二','陳淳','宋','宋诗','song-poetry','','[]','黄堂盛事據今論，向日郎君忠肅孫。',32,'全唐诗/poet.song.175000.json','["黄堂盛事據今論，向日郎君忠肅孫。", "依舊誠心勞撫字，漳民世世沐深恩。"]'),
('a2b8b2e0-6781-4a58-a3cf-db386b6043f8','和傅侍郎至臨漳感舊十詠  其三','陳淳','宋','宋诗','song-poetry','','[]','郡圃森森幾閲春，一番太守一番新。',32,'全唐诗/poet.song.175000.json','["郡圃森森幾閲春，一番太守一番新。", "何如今日同行樂，綵袖恭陪紫橐人。"]'),
('8e491cc4-e4d5-4e9c-bf3a-fb448c9bb201','和傅侍郎至臨漳感舊十詠  其四','陳淳','宋','宋诗','song-poetry','','[]','燕遊規畫孔明廬，陳法區藏梅李株。',32,'全唐诗/poet.song.175000.json','["燕遊規畫孔明廬，陳法區藏梅李株。", "慨想先儒遺意遠，能將舊觀一還無。"]'),
('8cf10cd2-fc0d-4ae6-8fec-6a95f7aea525','和傅侍郎至臨漳感舊十詠  其五','陳淳','宋','宋诗','song-poetry','','[]','老榕盤鬰植根深，意到扶藜賞綠陰。',32,'全唐诗/poet.song.175000.json','["老榕盤鬰植根深，意到扶藜賞綠陰。", "天理流行隨寓足，何心故步與追尋。"]'),
('8802b769-2b06-4088-b0a0-bd4f22b6b004','和傅侍郎至臨漳感舊十詠  其六','陳淳','宋','宋诗','song-poetry','','[]','依山種竹襯山佳，傍水栽花水妬霞。',32,'全唐诗/poet.song.175000.json','["依山種竹襯山佳，傍水栽花水妬霞。", "一意生生俱好玩，休分紅翠有無遮。"]'),
('28ee6e6b-6da9-47eb-a82b-debd600208e5','和傅侍郎至臨漳感舊十詠  其七','陳淳','宋','宋诗','song-poetry','','[]','雲移月色爽人看，雨趁潮聲迅拍欄。',32,'全唐诗/poet.song.175000.json','["雲移月色爽人看，雨趁潮聲迅拍欄。", "自是與民同樂地，何妨一整復前歡。"]'),
('b8bbd789-07a5-4d1a-aa00-a7fc9901e131','和傅侍郎至臨漳感舊十詠  其八','陳淳','宋','宋诗','song-poetry','','[]','南州佳品勝羅浮，青女飛花任打頭。',32,'全唐诗/poet.song.175000.json','["南州佳品勝羅浮，青女飛花任打頭。", "寒涸更深香更烈，松朋梅友敢凌不。"]'),
('633a8757-d529-4712-9cb8-5f964f90503d','和傅侍郎至臨漳感舊十詠  其九','陳淳','宋','宋诗','song-poetry','','[]','三山昂首狀魁嵬，虎踞龍蟠萃一臺。',32,'全唐诗/poet.song.175000.json','["三山昂首狀魁嵬，虎踞龍蟠萃一臺。", "若跨地靈規貢宇，英才衮衮拔條枚。"]'),
('db1b7f53-a337-4ab1-ac9e-ff15cb46cba3','和傅侍郎至臨漳感舊十詠  其一○','陳淳','宋','宋诗','song-poetry','','[]','臺前一带繞漳溪，臺下回環萬象齊。',32,'全唐诗/poet.song.175000.json','["臺前一带繞漳溪，臺下回環萬象齊。", "就拓宏模須大手，非爲諂語病丁畦。"]'),
('8b276e54-e208-4d94-9a29-9acca1c04330','和陳侍郎韻寄題林尉肯堂','陳淳','宋','宋诗','song-poetry','','[]','肯堂題扁自名公，表裏須教實一同。',64,'全唐诗/poet.song.175000.json','["肯堂題扁自名公，表裏須教實一同。", "門閲不誇車馬大，家聲端藉禮詩隆。", "熟仁便足膏粱味，殉義能傳清白風。", "終始此生無忝處，精誠妙與古人通。"]'),
('10edac04-96a9-40fc-a4c3-fa9c22612e34','和陳侍郎韻寄題林尉尚絅堂','陳淳','宋','宋诗','song-poetry','','[]','中庸尚絅示諸儒，爲己何心世毀譽。',64,'全唐诗/poet.song.175000.json','["中庸尚絅示諸儒，爲己何心世毀譽。", "只要美中存德本，無容飾外事文餘。", "魚潛理趣真如灼，屋漏工夫的不虛。", "珍重子思深屬意，一言綱領此篇書。"]'),
('f358060f-f632-4667-a496-81b76cd7799a','權長泰簿喜雨呈鄭宰','陳淳','宋','宋诗','song-poetry','','[]','夜雨滂沱一若傾，朝來南畝足春耕。',64,'全唐诗/poet.song.175000.json','["夜雨滂沱一若傾，朝來南畝足春耕。", "相呼荷耒奔趨急，便與擔秧插蒔盈。", "令尹精誠知到處，上天仁愛見真情。", "從今可釋懸懸望，百里已無愁嘆聲。"]'),
('15be35ae-66b0-46a4-9c41-61e55577245e','四月十八日喜雨再用前韻呈鄭宰','陳淳','宋','宋诗','song-poetry','','[]','民間霓望正頻傾，天澤如期爲養耕。',64,'全唐诗/poet.song.175000.json','["民間霓望正頻傾，天澤如期爲養耕。", "終夜連朝淋不住，上畦下畝浸皆盈。", "春來又見茲濃霈，秋穫何愁弗滿情。", "感格一機無外事，氣和端自有和聲。"]'),
('dd1e16ac-0261-46fb-bf0c-e5dee708647c','解職歸題主簿軒壁','陳淳','宋','宋诗','song-poetry','','[]','偶然寓興五山陰，可嘆頹波日轉深。',64,'全唐诗/poet.song.175000.json','["偶然寓興五山陰，可嘆頹波日轉深。", "鼓瑟齊門莫同調，舞韶鄭側鮮知音。", "歸尋舊徑掃新榻，從整遺編理素琴。", "惟有春秋知罪我，外餘橫直一何心。"]'),
('1a7513ad-24fe-4680-b50a-59e00eaf11a0','挽王郎中五首  其一','陳淳','宋','宋诗','song-poetry','','[]','早得名師友，淵源正不他。',48,'全唐诗/poet.song.175000.json','["早得名師友，淵源正不他。", "持身莊以重，接物簡而和。", "游夏文章學，求由政事科。", "朝聞今可矣，爲恨復云何。"]'),
('09692a8a-01b2-4df7-8202-984313e16cb6','挽王郎中五首  其二','陳淳','宋','宋诗','song-poetry','','[]','壯歲登科甲，淹遲暮始通。',48,'全唐诗/poet.song.175000.json','["壯歲登科甲，淹遲暮始通。", "閩中馳德政，灨上振儒風。", "藥石王宮訓，權衡璧水功。", "儼然遺躅在，誰不悼思公。"]'),
('00cdeb32-5d5e-4533-812c-ef5721ab99ae','挽王郎中五首  其三','陳淳','宋','宋诗','song-poetry','','[]','剖竹毘陵郡，乘軺古越城。',48,'全唐诗/poet.song.175000.json','["剖竹毘陵郡，乘軺古越城。", "活民均惠澤，報主一忠誠。", "强禦歛蹤伏，姦欺束手清。", "至今誦遺愛，何日可忘情。"]'),
('3d7ae2f6-5864-487a-a91e-8610524a5f85','挽王郎中五首  其四','陳淳','宋','宋诗','song-poetry','','[]','暮景孤高節，巖巖挺歲寒。',48,'全唐诗/poet.song.175000.json','["暮景孤高節，巖巖挺歲寒。", "松姿標雪嶺，玉質照冰盤。", "一介應無取，纖毫不可干。", "老成視前輩，宜作典刑看。"]'),
('f2aa1d77-016b-4ea5-b8ca-e3e231b8ff76','挽王郎中五首  其五','陳淳','宋','宋诗','song-poetry','','[]','近甸勳勞著，中朝寵眷隆。',48,'全唐诗/poet.song.175000.json','["近甸勳勞著，中朝寵眷隆。", "召從宗正貳，躐進戶曹郎。", "從橐方虛佇，生經遽不融。", "睪如巖下息，萬古儼公宮。"]'),
('61925f83-ba02-47ae-af2f-a46346ce59fe','挽楊料院二首  其一','陳淳','宋','宋诗','song-poetry','','[]','早識淵源正，從師事切磨。',48,'全唐诗/poet.song.175000.json','["早識淵源正，從師事切磨。", "天姿純不纇，世俗淡無波。", "廬墓誠於孝，刑家儉以和。", "自應仁者壽，命也奈之何。"]'),
('a60c8b02-4c70-430e-894f-c621871343bb','挽楊料院二首  其二','陳淳','宋','宋诗','song-poetry','','[]','恩沐賢關渥，名登桂籍榮。',48,'全唐诗/poet.song.175000.json','["恩沐賢關渥，名登桂籍榮。", "古田馳義勇，永福播仁聲。", "料院從優選，朝階即坦行。", "胡爲成契闊，第爾哭銘旌。"]'),
('7f1bf55c-ebbb-4c0e-af82-34dbb161dbeb','挽程推官二首  其一','陳淳','宋','宋诗','song-poetry','','[]','壯歲聲場屋，高年僅小行。',48,'全唐诗/poet.song.175000.json','["壯歲聲場屋，高年僅小行。", "鄫江夷暴跡，湟水雪冤情。", "節志冰壺潔，襟期玉井清。", "竟登泉石趣，勇去謝榮名。"]'),
('ee22c906-7ba7-4e4b-abf6-2e2f76e3d2cd','挽程推官二首  其二','陳淳','宋','宋诗','song-poetry','','[]','生質鍾來厚，風流近古人。',48,'全唐诗/poet.song.175000.json','["生質鍾來厚，風流近古人。", "奉官常翼翼，居里復恂恂。", "甥姪誨猶子，夫妻敬若賓。", "噫嘻公不死，嗣世有簪紳。"]'),
('83e238a9-2c3d-4b43-ad9e-329a4b15c69d','挽蕭知縣二首  其一','陳淳','宋','宋诗','song-poetry','','[]','資稟於人異，天鍾自粹夷。',48,'全唐诗/poet.song.175000.json','["資稟於人異，天鍾自粹夷。", "懷才無表襮，制行絕瑕疵。", "孝比王祥篤，知機下惠遺。", "鄉閭稱厚德，已矣但長噫。"]'),
('fa2a5f4a-af04-4d16-96d6-2ba5bfa0937a','挽蕭知縣二首  其二','陳淳','宋','宋诗','song-poetry','','[]','早擢儒科秀，旋驅仕路榮。',48,'全唐诗/poet.song.175000.json','["早擢儒科秀，旋驅仕路榮。", "平反東廣幕，撫字桂陽城。", "選調方優脫，朝階自坦行。", "如何中道處，遽爾輟千旌。"]'),
('62d665e5-0ed3-4e38-bc0d-5c334d6f5b6e','挽孫少卿四首  其一','陳淳','宋','宋诗','song-poetry','','[]','自拋襴苧列簪紳，便展施爲志獲伸。',64,'全唐诗/poet.song.175000.json','["自拋襴苧列簪紳，便展施爲志獲伸。", "剖竹三衢無警盜，乘軺兩浙蔑冤民。", "居官清節冰壺凜，到處仁恩雨露春。", "歷歷典刑如在日，慕思遺愛幾多人。"]'),
('8425fce3-590f-4e36-b0f1-3bd3e5e5394b','挽孫少卿四首  其二','陳淳','宋','宋诗','song-poetry','','[]','聖主更新大化年，趨朝正預拔茅連。',64,'全唐诗/poet.song.175000.json','["聖主更新大化年，趨朝正預拔茅連。", "青華上厠郎星列，近密光陪卿月聯。", "垂躡從班提從橐，遽萌歸興乞歸田。", "至今士論追懷處，第誦南山景行篇。"]'),
('0a976186-6fde-466c-859c-cc95a63d935f','挽孫少卿四首  其三','陳淳','宋','宋诗','song-poetry','','[]','厚德天鍾有異資，反身尤謹事操持。',64,'全唐诗/poet.song.175000.json','["厚德天鍾有異資，反身尤謹事操持。", "儉勤忠孝傳家訓，直諒忱恂獲上知。", "正色嫉邪嚴莫犯，高標立懦屹難移。", "睪如香坂孤峰下，千載唯存篤行碑。"]'),
('43ae67e7-1187-48dd-8e7d-c825b4b273c7','挽孫少卿四首  其四','陳淳','宋','宋诗','song-poetry','','[]','福慶於人鮮比方，一生坦若履康莊。',64,'全唐诗/poet.song.175000.json','["福慶於人鮮比方，一生坦若履康莊。", "好逑得偶天官胄，嗣子能傳月窟芳。", "壽入九齡光寶籙，服膺三品燦金章。", "始終可謂無遺憾，信矣榮歸死不亡。"]'),
('e0b71e6f-0345-4613-8a41-1fd022bb9e4b','偈頌三十四首  其一','釋如淨','宋','宋诗','song-poetry','','[]','截斷程途驀直來，乾坤洞徹此門開。',32,'全唐诗/poet.song.175000.json','["截斷程途驀直來，乾坤洞徹此門開。", "左邊拍兮右邊吹，倒翻關捩起風雷。"]'),
('db8a33d2-1469-4d7b-a8a6-256bb75b656a','偈頌三十四首  其二','釋如淨','宋','宋诗','song-poetry','','[]','開殿見佛，眼中毒刺。',26,'全唐诗/poet.song.175000.json','["開殿見佛，眼中毒刺。", "咄，拔却刺。", "禮拜燒香，顛倒鈍置。"]'),
('803af8c5-5176-49ab-bfdd-a6c3ba698e39','偈頌三十四首  其三','釋如淨','宋','宋诗','song-poetry','','[]','抉出達磨眼睛，作泥彈子打人。',26,'全唐诗/poet.song.175000.json','["抉出達磨眼睛，作泥彈子打人。", "海枯徹過底，波浪拍天高。"]'),
('a379ac20-4786-423b-b7c0-e8483980f06e','偈頌三十四首  其四','釋如淨','宋','宋诗','song-poetry','','[]','筆頭禿盡一毫通，至治寥寥靜極中。',32,'全唐诗/poet.song.175000.json','["筆頭禿盡一毫通，至治寥寥靜極中。", "點起風雲傳號令，雷霆潑墨振綱宗。"]'),
('1b778d4b-89bb-4e82-a46a-5aef25767f34','偈頌三十四首  其五','釋如淨','宋','宋诗','song-poetry','','[]','瞿曇頂骨，夫子眼睛。',20,'全唐诗/poet.song.175000.json','["瞿曇頂骨，夫子眼睛。", "兩彩一賽，玉振金聲。"]'),
('67f71ec3-ae7e-4c92-b6e1-cd6ad442f62d','偈頌三十四首  其六','釋如淨','宋','宋诗','song-poetry','','[]','大地平沈，此座高廣。',20,'全唐诗/poet.song.175000.json','["大地平沈，此座高廣。", "千變萬化，無功受賞。"]'),
('881e1d9e-87cf-4105-84ca-bdaded4483ed','偈頌三十四首  其七','釋如淨','宋','宋诗','song-poetry','','[]','露柱懷胎，忽然爆裂。',24,'全唐诗/poet.song.175000.json','["露柱懷胎，忽然爆裂。", "突出無孔鐵槌，歷劫都盧敗缺。"]'),
('b1a105d2-23fa-4df9-bb55-3d88ed4ba1b6','偈頌三十四首  其八','釋如淨','宋','宋诗','song-poetry','','[]','一舉首登龍虎榜，太平親到鳳凰池。',32,'全唐诗/poet.song.175000.json','["一舉首登龍虎榜，太平親到鳳凰池。", "全生全殺超言象，更透機先向上機。"]'),
('db0bb3df-ea0c-4b0c-b836-9508d5d5f1b1','偈頌三十四首  其九','釋如淨','宋','宋诗','song-poetry','','[]','拔斷毒蛇尾巴，穿住黑牛鼻孔。',60,'全唐诗/poet.song.175000.json','["拔斷毒蛇尾巴，穿住黑牛鼻孔。", "虛空背上牽來，大地六番震動。", "甚惡毒兮甚仇讎，屎尿腥臊汗血流。", "擬將眼覷無蹤跡，箇是清凉第一頭。"]'),
('c2e87332-c5f0-4bda-8bca-440e07ad3538','偈頌三十四首  其一○','釋如淨','宋','宋诗','song-poetry','','[]','過去然燈佛，相牽弄業識。',66,'全唐诗/poet.song.175000.json','["過去然燈佛，相牽弄業識。", "現在漏燈盞，光影瞞人眼。", "未來乾紙撚，賊贓無處典。", "咄，髑髏前點破，鼻孔裏看見。", "衲僧門下黑漫漫，歷劫不分通一線。"]'),
('fc718da4-edbb-43bd-b311-fd1da3009fd6','偈頌三十四首  其一一','釋如淨','宋','宋诗','song-poetry','','[]','梅花清曉香，爛熳而借功。',54,'全唐诗/poet.song.175000.json','["梅花清曉香，爛熳而借功。", "柳線早春濃，日暄而轉位。", "非那邊去，從者裏來。", "哆哆和和兮主賓妙叶，跛跛挈挈兮偏正全該。"]'),
('85772444-d4ad-460a-a099-9885b9564c08','偈頌三十四首  其一二','釋如淨','宋','宋诗','song-poetry','','[]','春風輕，春日晴。',67,'全唐诗/poet.song.175000.json','["春風輕，春日晴。", "柳眼青，黄鶑鳴。", "鬰鬰葱葱生瑞氣，世上老人天上星。", "釋迦讚歎，彌勒證明，蟠桃仙果笑中呈。", "林下衲僧將何酬獻，手中千古一枝藤。"]'),
('afbce42e-e844-4853-b1ac-1e358db460db','偈頌三十四首  其一三','釋如淨','宋','宋诗','song-poetry','','[]','三分光陰二早過，遲日江山麗。',56,'全唐诗/poet.song.175000.json','["三分光陰二早過，遲日江山麗。", "靈臺一點不揩磨，春風花草香。", "貪生逐日區區去，泥融飛燕子。", "喚不回頭爭奈何，沙暖睡鴛鴦。"]'),
('6b8e2cca-a5a0-4e21-bc65-4c8a475583bc','偈頌三十四首  其一四','釋如淨','宋','宋诗','song-poetry','','[]','雲開山嶽露，雨過色新鮮。',50,'全唐诗/poet.song.175000.json','["雲開山嶽露，雨過色新鮮。", "翟曇不出世，敗闕未生前。", "天上天下，賊是小人。", "三拜起來澆惡水，謾將掩彩當慇懃。"]'),
('1aacec4f-e474-4e1b-b78f-593f45414fc5','偈頌三十四首  其一五','釋如淨','宋','宋诗','song-poetry','','[]','一葉落，空索索。',34,'全唐诗/poet.song.175000.json','["一葉落，空索索。", "天下秋，乾剝剝。", "霹靂一聲，滂沱大霔，笑看烏藤倒上樹。"]'),
('5ca8e215-d409-4193-8627-1d82bafc129c','偈頌三十四首  其一六','釋如淨','宋','宋诗','song-poetry','','[]','六年落草野狐精，跳出渾身是葛藤。',32,'全唐诗/poet.song.175000.json','["六年落草野狐精，跳出渾身是葛藤。", "打失眼睛無覓處，誑人剛道悟明星。"]'),
('8a197bba-8f35-4c22-8c55-fc4f23de5464','偈頌三十四首  其一七','釋如淨','宋','宋诗','song-poetry','','[]','今朝正月初一，一舉上上大吉。',40,'全唐诗/poet.song.175000.json','["今朝正月初一，一舉上上大吉。", "吉無不利，春風和氣。", "散入花梢百草頭，塵塵剎剎轉風流。"]'),
('fdfbee4d-1b5f-4156-a3f7-ff871c3bd4fa','偈頌三十四首  其一八','釋如淨','宋','宋诗','song-poetry','','[]','髑髏前，腦蓋後，一點洞明光影裏走。',27,'全唐诗/poet.song.175000.json','["髑髏前，腦蓋後，一點洞明光影裏走。", "咄，然燈古佛轉誵訛。"]'),
('06c8accc-8e40-4398-9203-bf0ead159722','偈頌三十四首  其一九','釋如淨','宋','宋诗','song-poetry','','[]','無面目漢，面目全該。',34,'全唐诗/poet.song.175000.json','["無面目漢，面目全該。", "日烘楊柳眼，烟抹杏花腮。", "黄鶑啼不盡，特地下枝來。"]'),
('35340717-e76d-430d-bc97-0b75f565a497','偈頌三十四首  其二○','釋如淨','宋','宋诗','song-poetry','','[]','瞿曇夜半翻筋斗，萬像平沈大地空。',32,'全唐诗/poet.song.175000.json','["瞿曇夜半翻筋斗，萬像平沈大地空。", "贏得波旬拍手笑，燈籠露柱暗搥胸。"]'),
('777bac27-997e-4cd0-8477-afff7f957900','偈頌三十四首  其二一','釋如淨','宋','宋诗','song-poetry','','[]','龍生龍，鳳生鳳，指天指地獨稱尊，老鼠養兒巡屋棟。',40,'全唐诗/poet.song.175000.json','["龍生龍，鳳生鳳，指天指地獨稱尊，老鼠養兒巡屋棟。", "共將惡水驀頭澆，萬兩黄金也合消。"]'),
('578f6116-326d-42e2-8346-d8cbd0fada81','偈頌三十四首  其二二','釋如淨','宋','宋诗','song-poetry','','[]','白圭無玷，頑石點頭。',30,'全唐诗/poet.song.175000.json','["白圭無玷，頑石點頭。", "轉關一拶，佛祖仇讎。", "咦，咬豬狗漢轉風流。"]'),
('b6a885fc-47de-4cd2-acb6-c1a72b5fe34a','偈頌三十四首  其二三','釋如淨','宋','宋诗','song-poetry','','[]','雲散秋空，即心見月。',52,'全唐诗/poet.song.175000.json','["雲散秋空，即心見月。", "家家門前照明月，處處行人共明月。", "騎鯨捉月，撐船載月。", "忽然月落夜沈沈，笑殺胡僧齒門缺。"]'),
('80d2a87b-e03c-4608-ab76-277ec2c3fa87','偈頌三十四首  其二四','釋如淨','宋','宋诗','song-poetry','','[]','當堂不露，主人翁元是舊時。',66,'全唐诗/poet.song.175000.json','["當堂不露，主人翁元是舊時。", "借影全彰，第一座屈煩今日。", "雪夜金烏歷堂，炎天玉兔轉懷。", "妙叶兒孫，全該祖父。", "木人執板雲中拍，石女含笙水底吸。"]'),
('e38e49d7-79e6-46cd-9c4d-4ea52f6708b4','偈頌三十四首  其二五','釋如淨','宋','宋诗','song-poetry','','[]','清凉大火聚，炎炎沒回互。',56,'全唐诗/poet.song.175000.json','["清凉大火聚，炎炎沒回互。", "衲僧赤骨律，通身是劍樹。", "在裏許相挨廝拶，在裏許放行把住。", "放行把住逞風流，總是冤家笑點頭。"]'),
('0e75bb0d-f157-417d-a451-36c20097a2c6','偈頌三十四首  其二六','釋如淨','宋','宋诗','song-poetry','','[]','昨日一線短，今朝一線長。',34,'全唐诗/poet.song.175000.json','["昨日一線短，今朝一線長。", "針眼裏過，尺寸上量。", "短長驀劄斷，巧綉出鴛鴦。"]'),
('3a772e74-2684-46df-8338-4669c36cec9e','偈頌三十四首  其二七','釋如淨','宋','宋诗','song-poetry','','[]','天地一指，萬物一馬。',78,'全唐诗/poet.song.175000.json','["天地一指，萬物一馬。", "二由一有，一亦放下。", "然後向者裏拈起，謂之衲僧火柴頭。", "大海波心輕𢫫動，須彌頂上汗通流。", "今朝以此開爐，無賓主話勘破趙州。", "擬歸暖處，箭過髑髏。"]'),
('7e178e59-c939-436a-b9b1-80a0a6bc0aa3','偈頌三十四首  其二八','釋如淨','宋','宋诗','song-poetry','','[]','瞿曇打失眼睛時，雪裏梅花只一枝。',58,'全唐诗/poet.song.175000.json','["瞿曇打失眼睛時，雪裏梅花只一枝。", "而今到處成荆棘，却笑春風繚亂吹。", "諸方說禪，清凉念詩。", "燒香點燭拜泥團，腦後遼天鷂子飛。"]'),
('6d71995a-1283-4bda-9159-d0ffa4dcfa9d','偈頌三十四首  其二九','釋如淨','宋','宋诗','song-poetry','','[]','一滴不息，兩滴三滴。',99,'全唐诗/poet.song.175000.json','["一滴不息，兩滴三滴。", "滴滴瀝瀝，連朝至夕。", "變作滂沱勿奈何，山河大地衮風波。", "總不出衲僧噴嚏一激，直得雲開日出。", "朗朗晴空吞八極，若還依舊水漉漉，渾家飄墮羅剎國。", "稽首釋迦，南無彌勒。", "能救世間苦，觀音妙智力。"]'),
('62927d63-c7bf-4cde-bf2e-61e8fe68ab8a','偈頌三十四首  其三○','釋如淨','宋','宋诗','song-poetry','','[]','大地平沈，側布黄金。',38,'全唐诗/poet.song.175000.json','["大地平沈，側布黄金。", "虛空透闊，高架栴檀。", "依稀馬廐，彷彿牛欄。", "鶻眼鷹睛不許看。"]'),
('1540480c-a689-43db-807c-58f0a3208ea0','偈頌三十四首  其三一','釋如淨','宋','宋诗','song-poetry','','[]','活剗群牛腦後毛，風吹日炙轉腥臊。',48,'全唐诗/poet.song.175000.json','["活剗群牛腦後毛，風吹日炙轉腥臊。", "不堪狼藉薰天地，罪惡重將業火燒。", "切忌死灰尋舍利，臭烟蓬㶿燄頭高。"]'),
('3e38a8c3-b904-4905-bb42-84e9a00d7742','偈頌三十四首  其三二','釋如淨','宋','宋诗','song-poetry','','[]','船無底，米無粒，積岳堆山，洪波直入。',34,'全唐诗/poet.song.175000.json','["船無底，米無粒，積岳堆山，洪波直入。", "恁麽歸來得自由，清凉門下盡點頭。"]'),
('51967ec6-6529-40c4-9739-fd0838293189','偈頌三十四首  其三三','釋如淨','宋','宋诗','song-poetry','','[]','金剛寶劍入紅爐，煅出楊岐三脚馿。',32,'全唐诗/poet.song.175000.json','["金剛寶劍入紅爐，煅出楊岐三脚馿。", "到處沙場鏖死戰，髑髏交衮血糢糊。"]'),
('e446a934-4632-4e89-844f-36577b1db2e6','偈頌三十四首  其三四','釋如淨','宋','宋诗','song-poetry','','["\u7ec4\u8bd7", "\u590f\u5929", "\u5199\u666f"]','糝徑楊花鋪白氈，點池荷葉疊青錢。',42,'全唐诗/poet.song.175000.json','["糝徑楊花鋪白氈，點池荷葉疊青錢。", "兩彩一賽，其或未然。", "竹根稚子無人見，沙上鳬雛傍母眠。"]'),
('8cd1a791-6ed1-4113-8975-a3f8fbc6edeb','偈頌三十四首  其三五','釋如淨','宋','宋诗','song-poetry','','[]','秋風凉，岩桂香。',36,'全唐诗/poet.song.175000.json','["秋風凉，岩桂香。", "未歸客，思故鄉。", "吾無隠乎爾，捉賊須捉贓，舞蝶遊蜂過短牆。"]'),
('e6fa5d53-7b28-40fe-8b06-6398ce11c4f5','偈頌十二首  其一','釋如淨','宋','宋诗','song-poetry','','[]','不曾動步上天台，金鎖玄關盡豁開。',32,'全唐诗/poet.song.175000.json','["不曾動步上天台，金鎖玄關盡豁開。", "坐斷鞔峰第一句，萬機俱透起風雷。"]'),
('44ef3d9b-6a57-4122-aafc-5ac19760fdab','偈頌十二首  其二','釋如淨','宋','宋诗','song-poetry','','[]','饑來喫飯，困來打眠。',20,'全唐诗/poet.song.175000.json','["饑來喫飯，困來打眠。", "爐鞴亙天，倒退三千。"]'),
('4f014a2c-4642-4918-b2e0-2761448ff57a','偈頌十二首  其三','釋如淨','宋','宋诗','song-poetry','','[]','平沈大地，高出虛空。',28,'全唐诗/poet.song.175000.json','["平沈大地，高出虛空。", "機先坐斷，遊戲神通。", "須彌燈王立下風。"]'),
('2333f34d-06f4-43f0-8d66-87bff63f74d8','偈頌十二首  其四','釋如淨','宋','宋诗','song-poetry','','[]','打破黑漆桶，十方空豁豁。',55,'全唐诗/poet.song.175000.json','["打破黑漆桶，十方空豁豁。", "爆雷一喝變通，掣電千機頓發。", "便可以東行撐架門庭，西班怒駡佛祖。", "收放絕來由，縱橫透今古。"]'),
('b6dcfdfa-bf2c-4ee4-8c0f-dae03930242c','偈頌十二首  其五','釋如淨','宋','宋诗','song-poetry','','[]','韓信造浮橋，李廣入布袋。',24,'全唐诗/poet.song.175000.json','["韓信造浮橋，李廣入布袋。", "一箭透雙關，乾坤無罣碍。"]'),
('1cff57ed-cf8b-4038-ba6e-d95817b2bb5e','偈頌十二首  其六','釋如淨','宋','宋诗','song-poetry','','[]','晷運推移，日南長至。',38,'全唐诗/poet.song.175000.json','["晷運推移，日南長至。", "眼睛裏放光，鼻孔裏出氣。", "飽飯快活屙一堆，超過瞿曇親授記。"]'),
('4d7a8e15-f001-4884-8ed6-4a486f8bb827','偈頌十二首  其七','釋如淨','宋','宋诗','song-poetry','','[]','斬鯨龍頭角，截虎豹爪牙。',44,'全唐诗/poet.song.175000.json','["斬鯨龍頭角，截虎豹爪牙。", "爛泥團受用不盡，踏著刺方見作家。", "誰在畫樓沽酒處，相邀來喫趙州茶。"]'),
('d685dfb5-d950-42f8-8837-706a6c0fb188','偈頌十二首  其八','釋如淨','宋','宋诗','song-poetry','','[]','今朝九月初一，打板普請坐禪。',92,'全唐诗/poet.song.175000.json','["今朝九月初一，打板普請坐禪。", "第一切忌瞎睡，直下猛烈爲先。", "忽然爆破漆桶，豁如雲散秋天。", "劈脊棒，迸胸拳，晝夜方纔不可眠。", "虛空消殞更消殞，透過威音未朕前。", "咦，栗棘金圈恣交衮，凱歌高賀徹風顛。"]'),
('51a0ecb4-3ea1-45ef-9c2a-864a4338fcb8','偈頌十二首  其九','釋如淨','宋','宋诗','song-poetry','','[]','夜半烏雞抱鵠卵，天明生出箇老鸛。',58,'全唐诗/poet.song.175000.json','["夜半烏雞抱鵠卵，天明生出箇老鸛。", "毛長觜短鷺鷀形，飛起一天星斗亂。", "一拳拳倒黄鶴樓，一踢踢翻鸚鵡洲。", "咄，籬邊燕雀空啾啾。"]'),
('e6c0f562-d5da-45ac-8c1f-2d404976af75','偈頌十二首  其一○','釋如淨','宋','宋诗','song-poetry','','[]','元正啟祚，萬物咸新。',20,'全唐诗/poet.song.175000.json','["元正啟祚，萬物咸新。", "伏惟大衆，梅開早春。"]'),
('c9f25cbb-b793-493a-9444-31eb5afe2efd','偈頌十二首  其一一','釋如淨','宋','宋诗','song-poetry','','[]','半年喫飯坐鞔峰，鎖斷烟雲千萬重。',32,'全唐诗/poet.song.175000.json','["半年喫飯坐鞔峰，鎖斷烟雲千萬重。", "忽地一聲轟霹靂，帝鄉春色杏花紅。"]'),
('34048974-b3cc-4bf5-b321-bb8a4cd36a94','偈頌三十八首  其一','釋如淨','宋','宋诗','song-poetry','','[]','淨慈門下，牛欄馬廄。',29,'全唐诗/poet.song.175000.json','["淨慈門下，牛欄馬廄。", "一拶透關，豁開宇宙。", "咦，切忌追風捕影。"]'),
('e760a9c6-6ad2-497a-bf50-5ef4b1e913c7','偈頌三十八首  其二','釋如淨','宋','宋诗','song-poetry','','[]','黄金殿上一轉語，烜爀紅輪照萬方。',32,'全唐诗/poet.song.175000.json','["黄金殿上一轉語，烜爀紅輪照萬方。", "草木叢林成正覺，磚頭瓦礫放毫光。"]'),
('c973f652-0788-4c1f-aee0-014a2dd58920','偈頌三十八首  其三','釋如淨','宋','宋诗','song-poetry','','[]','截斷千差，單提一著。',100,'全唐诗/poet.song.175000.json','["截斷千差，單提一著。", "那邊放下龜毛，者裏拈起兔角。", "咦，敲開歡喜妙樓閣，瑞靄祥雲充碧落。", "轉入梅花爛熳看，春風撼動玉欄干。", "人天普會，佛祖透關。", "發大機，顯大用，鐵鎚混隊骨毛寒。", "四海五湖皇化裏，太平無象有來端。"]'),
('1503b711-a349-4db4-a3a7-134a57453a99','偈頌三十八首  其四','釋如淨','宋','宋诗','song-poetry','','[]','一言相契，萬古不移。',22,'全唐诗/poet.song.175000.json','["一言相契，萬古不移。", "柳眼發新條，梅花滿舊枝。"]'),
('2ec3b60e-6225-4058-b485-c4b9bc992572','偈頌三十八首  其五','釋如淨','宋','宋诗','song-poetry','','[]','今朝二月初一，拂子眼睛凸出。',46,'全唐诗/poet.song.175000.json','["今朝二月初一，拂子眼睛凸出。", "明似鏡，黑如漆。", "驀然𨁝跳，吞却乾坤一色。", "衲僧門下，猶是撞牆撞壁。"]'),
('b02f15cc-1a2f-4ea8-ac71-5c9609032ead','偈頌三十八首  其六','釋如淨','宋','宋诗','song-poetry','','[]','霖霪大雨，豁遠大晴。',39,'全唐诗/poet.song.175000.json','["霖霪大雨，豁遠大晴。", "蝦蟆啼，蚯蚓鳴，古佛不曾過去，發揮金剛眼睛。", "咄，葛藤葛藤。"]'),
('16f4c1b9-6e5b-4a29-a1d9-226d92fd2342','偈頌三十八首  其七','釋如淨','宋','宋诗','song-poetry','','[]','不曾生，不曾死，洞裏桃花紅照水。',32,'全唐诗/poet.song.175000.json','["不曾生，不曾死，洞裏桃花紅照水。", "可憐開眼被渠瞞，人間天上風波起。"]'),
('e3b892fb-7681-4965-96ae-c82735ebf092','偈頌三十八首  其八','釋如淨','宋','宋诗','song-poetry','','[]','簷聲不斷前旬雨，電影還連後夜雷。',54,'全唐诗/poet.song.175000.json','["簷聲不斷前旬雨，電影還連後夜雷。", "麥怕水侵秧怕冷，蠶桑猶要暖來催。", "衆生沒在苦，蒼天良可哀。", "咄，杲日當空慧眼開。"]'),
('d6ad218d-bd51-40b8-8a02-a1d0472c6fc4','偈頌三十八首  其九','釋如淨','宋','宋诗','song-poetry','','[]','無憂樹下浴嬰孩，清曉薔薇带露開。',32,'全唐诗/poet.song.175000.json','["無憂樹下浴嬰孩，清曉薔薇带露開。", "轉過衲僧相見處，後槽馿馬出胞胎。"]'),
('4aced8ca-c52a-4728-a507-6d21159fcac6','偈頌三十八首  其一○','釋如淨','宋','宋诗','song-poetry','','[]','結夏已過了，解夏猶未來。',37,'全唐诗/poet.song.175000.json','["結夏已過了，解夏猶未來。", "中間一句子，蓮花照水開。", "因甚落草止啼，元只爲嬰孩。"]'),
('9231350a-87a8-400b-9b4c-12a4dfe29f18','偈頌三十八首  其一一','釋如淨','宋','宋诗','song-poetry','','[]','四月十五日結夏，老鼠入飯甕。',72,'全唐诗/poet.song.175000.json','["四月十五日結夏，老鼠入飯甕。", "七月十五日解夏，烏龜上竹竿。", "諸方恁麽，淨慈不然。", "翻身透出竿頭路，開眼掀翻甕裏天。", "咄，兩段不同休寐語，機先鷂子隔馿年。"]'),
('af439e2a-2616-43b4-8f11-c403a6c529a1','偈頌三十八首  其一二','釋如淨','宋','宋诗','song-poetry','','[]','雲漫漫，雨漫漫。',32,'全唐诗/poet.song.175000.json','["雲漫漫，雨漫漫。", "中秋當此夜，漫漫黑漫漫。", "箇般真境界，贏得倚欄干。"]'),
('85e74860-2da1-494d-ae32-4ff663799ef6','偈頌三十八首  其一三','釋如淨','宋','宋诗','song-poetry','','[]','風颯颯，雨霖霖。',38,'全唐诗/poet.song.175000.json','["風颯颯，雨霖霖。", "聖人不曾滅度，演出清淨妙音。", "若將耳聽終難會，一句機先透古今。"]'),
('ee743e7b-8ac6-44cc-b077-5bc49c1f103e','偈頌三十八首  其一四','釋如淨','宋','宋诗','song-poetry','','[]','至人垂化無生死，示現閻浮有去來。',32,'全唐诗/poet.song.175000.json','["至人垂化無生死，示現閻浮有去來。", "剎剎塵塵成正覺，黄金寶殿玉樓臺。"]'),
('15995691-6bed-43d9-8041-09cbdd21e6a1','偈頌三十八首  其一五','釋如淨','宋','宋诗','song-poetry','','[]','把釣歸來得錦鱗，充天塞地笑忻忻。',32,'全唐诗/poet.song.175000.json','["把釣歸來得錦鱗，充天塞地笑忻忻。", "雖然也只尋常事，歷盡風波驗盡人。"]'),
('6f27f8e6-ade2-47f9-9d8e-67363a67f3eb','偈頌三十八首  其一六','釋如淨','宋','宋诗','song-poetry','','[]','清淨法身盧舍那，衲僧隊裏乾羅蔔。',48,'全唐诗/poet.song.175000.json','["清淨法身盧舍那，衲僧隊裏乾羅蔔。", "逐日呼來打一槌，萬像森羅轉轆轆。", "知恩以此報深恩，大家贏得噇齋粥。"]'),
('db5a3532-089e-4c60-acd0-2551e18bdab3','偈頌三十八首  其一七','釋如淨','宋','宋诗','song-poetry','','[]','壽皇頂𩕳老冤魔，痛念先師舊草窠。',32,'全唐诗/poet.song.175000.json','["壽皇頂𩕳老冤魔，痛念先師舊草窠。", "聊借蒲團供打坐，大家拍手唱山歌。"]'),
('497881b1-9b14-49e3-9ad7-5145dffabd19','偈頌三十八首  其一八','釋如淨','宋','宋诗','song-poetry','','[]','獨瞎頂門眼，大人具大見。',50,'全唐诗/poet.song.175000.json','["獨瞎頂門眼，大人具大見。", "掀翻甕裏天，大智具大機。", "以大入小，萬化普施。", "鶑遷喬木調新舌，梅吐清香發舊枝。"]'),
('eb8c3222-29df-4b2e-a9a3-437765f651af','偈頌三十八首  其一九','釋如淨','宋','宋诗','song-poetry','','[]','涅槃堂裏死功夫，風衮葫蘆水上浮。',32,'全唐诗/poet.song.175000.json','["涅槃堂裏死功夫，風衮葫蘆水上浮。", "恁麽點開參學眼，釋迦彌勒是他奴。"]'),
('53309a8f-5627-4e78-a402-241046c226e8','偈頌三十八首  其二○','釋如淨','宋','宋诗','song-poetry','','[]','雨打虛空乾剝剝，日明大地黑漫漫。',48,'全唐诗/poet.song.175000.json','["雨打虛空乾剝剝，日明大地黑漫漫。", "箇中開得金剛眼，生死何嘗有異端。", "須彌山，大海水，衲僧頂上波濤起。"]'),
('e5f6b968-e1dc-49a5-8c21-d192033a1bc3','偈頌三十八首  其二一','釋如淨','宋','宋诗','song-poetry','','[]','天得一以清，元正啟祚。',45,'全唐诗/poet.song.175000.json','["天得一以清，元正啟祚。", "地得一以寧，萬物咸新。", "且道衲僧得一合作麽生，太平歌有道，和氣笑迎春。"]'),
('494cdb65-9843-471a-883c-e169c8bb30cf','偈頌三十八首  其二二','釋如淨','宋','宋诗','song-poetry','','[]','燈點點，月團團，遊人歌皷閙中看。',32,'全唐诗/poet.song.175000.json','["燈點點，月團團，遊人歌皷閙中看。", "咫尺鳳樓開雉扇，玉皇仙仗紫雲端。"]'),
('98f8ad31-3fd9-400b-8770-60ec0aa0106d','偈頌三十八首  其二三','釋如淨','宋','宋诗','song-poetry','','[]','天蒼蒼，地皇皇。',36,'全唐诗/poet.song.175000.json','["天蒼蒼，地皇皇。", "鍾馗元是鬼，赤口併消亡。", "衲僧八面無門戶，今古寥寥白晝長。"]'),
('3efc7824-a25c-480d-910e-10a80d50715e','偈頌三十八首  其二四','釋如淨','宋','宋诗','song-poetry','','[]','解却禪和布袋頭，虛空豁達逞風流。',32,'全唐诗/poet.song.175000.json','["解却禪和布袋頭，虛空豁達逞風流。", "去亦得，住亦得，大用現前無軌則。"]'),
('a1690d27-223a-4cab-94dd-5a04e08f393e','偈頌三十八首  其二五','釋如淨','宋','宋诗','song-poetry','','[]','大海汪洋，須彌突兀。',26,'全唐诗/poet.song.175000.json','["大海汪洋，須彌突兀。", "現在說法不思議，稽首光明最奇特。"]'),
('913cb972-be3b-49fc-bdd4-510c55065b19','偈頌三十八首  其二六','釋如淨','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十五日已前，湖光瀲灧晴方好。',66,'全唐诗/poet.song.175000.json','["十五日已前，湖光瀲灧晴方好。", "十五日已後，山色空濛雨益奇。", "正當十五日，若把西湖比西子，淡粧濃抹總相宜。", "中秋月似鸞臺鏡，贏得多才一首詩。"]'),
('7f376772-9dd1-422a-abfd-cc0f8be7fcb2','偈頌三十八首  其二七','釋如淨','宋','宋诗','song-poetry','','[]','連雨初晴九月一，日頭依舊東邊出。',46,'全唐诗/poet.song.175000.json','["連雨初晴九月一，日頭依舊東邊出。", "照見五藴皆空，衲僧參學事畢。", "一尺水，一丈波，謝郎船上唱山歌。"]'),
('f83c5ca6-f6bb-4035-9f26-d3a6cfc13685','偈頌三十八首  其二八','釋如淨','宋','宋诗','song-poetry','','[]','坐斷老盧頂𩕳，拈起無柄木杓。',47,'全唐诗/poet.song.175000.json','["坐斷老盧頂𩕳，拈起無柄木杓。", "忽然舀出銅汁鐵丸，忽然舀出醍醐酥酪。", "佛祖大機難測度，猶是家常茶飯。"]'),
('4f369e26-0070-4213-b2d6-0464d5699794','偈頌三十八首  其二九','釋如淨','宋','宋诗','song-poetry','','[]','殺人刀，活人劍，轉磨轉精，累試累驗。',48,'全唐诗/poet.song.175000.json','["殺人刀，活人劍，轉磨轉精，累試累驗。", "乃上古之風規，亦今時之樞要。", "淨慈門下實相當，倚天照雪寒光耀。"]'),
('0de81b3e-2691-4f7d-bf8c-e2b94a51b3fc','偈頌三十八首  其三○','釋如淨','宋','宋诗','song-poetry','','[]','烟濛濛，雨濛濛，芍藥花開濕嫩紅。',32,'全唐诗/poet.song.175000.json','["烟濛濛，雨濛濛，芍藥花開濕嫩紅。", "我今灌沐諸如來，人間天上起清風。"]'),
('fe44477d-d8a2-4227-8d85-9e3ad6bd1cde','偈頌三十八首  其三一','釋如淨','宋','宋诗','song-poetry','','[]','鐘樓上念讚，牀脚下種菜。',48,'全唐诗/poet.song.175000.json','["鐘樓上念讚，牀脚下種菜。", "不會不自在，會得是障礙。", "白狗喫生薑，胡人夜渡關。", "若不得流水，還應過別山。"]'),
('8c8f6f9e-519e-4e04-b3a6-e2659dc7b5a6','偈頌三十八首  其三二','釋如淨','宋','宋诗','song-poetry','','[]','人從平江來，却得福州信。',42,'全唐诗/poet.song.175000.json','["人從平江來，却得福州信。", "寒食拜新年，虛空突出柄。", "咦，打破虛空笑不休，大家徹底驗聱頭。"]'),
('6a27f2e8-96ce-4b64-b4d3-973482914ff8','偈頌三十八首  其三三','釋如淨','宋','宋诗','song-poetry','','[]','掩室摩竭國，老胡豁開頂門。',42,'全唐诗/poet.song.175000.json','["掩室摩竭國，老胡豁開頂門。", "杜口毗耶城，淨名敗缺話柄。", "提上古兩端公案，發今朝一段威光。"]'),
('f965a424-5fb6-4693-9e7d-f73bab3b2620','偈頌三十八首  其三四','釋如淨','宋','宋诗','song-poetry','','[]','竿木隨身，逢場作戲。',44,'全唐诗/poet.song.175000.json','["竿木隨身，逢場作戲。", "釋迦老子毒花開，達磨大師王小二。", "吹笛打皷，攙行奪市，萬像森羅笑點頭。"]'),
('db9b6235-6153-4eac-9061-75261ddff160','偈頌三十八首  其三五','釋如淨','宋','宋诗','song-poetry','','[]','元正啟祚，鼻孔發露。',36,'全唐诗/poet.song.175000.json','["元正啟祚，鼻孔發露。", "萬物咸新，笑面迎春。", "淨慈門下轉風流，飯滿鉢盂茶滿甌。"]'),
('d4cc49c3-c416-4204-b672-0cf59a240426','偈頌三十八首  其三六','釋如淨','宋','宋诗','song-poetry','','[]','春雨洗春雪，雪消湖上山。',24,'全唐诗/poet.song.175000.json','["春雨洗春雪，雪消湖上山。", "雨晴相對看，突兀髑髏寒。"]'),
('5f3074f0-06c6-4f40-8c12-e48fc5b4c467','偈頌三十八首  其三七','釋如淨','宋','宋诗','song-poetry','','[]','一番雨，一番風，風雨湖山圖畫中。',42,'全唐诗/poet.song.175000.json','["一番雨，一番風，風雨湖山圖畫中。", "風摇水色瑠璃滑，雨潑山光翡翠濃。", "咄，杜鵑啼血滴花紅。"]'),
('bcac3cee-9687-42ce-8058-5d85136fcdc3','偈頌三十八首  其三八','釋如淨','宋','宋诗','song-poetry','','[]','鐵酸豏，金剛劍，吞了斬了，以活爲驗。',34,'全唐诗/poet.song.175000.json','["鐵酸豏，金剛劍，吞了斬了，以活爲驗。", "作家恁麽共提持，超過佛祖增光焰。"]'),
('41d212b0-fb41-464e-87de-2442252eb871','偈頌十首  其一','釋如淨','宋','宋诗','song-poetry','','[]','回避無門，此門大開。',22,'全唐诗/poet.song.175000.json','["回避無門，此門大開。", "家私都脫盡，平白起風雷。"]'),
('47c48174-190e-42f7-b0de-d3b121505bfa','偈頌十首  其二','釋如淨','宋','宋诗','song-poetry','','[]','黄金妙相，著衣喫飯。',38,'全唐诗/poet.song.175000.json','["黄金妙相，著衣喫飯。", "因我禮你，早眠晏起。", "咦，談玄說妙太無端，切忌拈花自熱瞞。"]'),
('05eb92cd-2932-4ce9-8021-1540cb1262e6','偈頌十首  其三','釋如淨','宋','宋诗','song-poetry','','[]','舞衫歌扇，花皷拍板。',58,'全唐诗/poet.song.175000.json','["舞衫歌扇，花皷拍板。", "總是者箇戲棚，賣弄許多伎倆。", "咦，任他千聖出頭來，立在下風高著眼。", "建法幢，立宗旨，明明佛敕曹溪是。"]'),
('9029447f-2d47-4f6d-9b74-13435d5a7d48','偈頌十首  其四','釋如淨','宋','宋诗','song-poetry','','[]','西來祖意庭前柏，鼻孔寥寥對眼睛。',32,'全唐诗/poet.song.175000.json','["西來祖意庭前柏，鼻孔寥寥對眼睛。", "落地枯枝纔𨁝跳，松蘿亮鬲笑掀騰。"]'),
('e1778f07-c05a-47a4-9c4b-65a440cec4be','偈頌十首  其五','釋如淨','宋','宋诗','song-poetry','','[]','深山岩崖問，石頭大小答。',24,'全唐诗/poet.song.175000.json','["深山岩崖問，石頭大小答。", "崖崩石迸裂，虛空閙聒聒。"]'),
('e4a12e17-ea6f-489a-900d-97342230b2ae','偈頌十首  其六','釋如淨','宋','宋诗','song-poetry','','[]','一言相契即住，笑面花開玉樹。',46,'全唐诗/poet.song.175000.json','["一言相契即住，笑面花開玉樹。", "諸方恁麽點頭，瑞岩剗地惡辣。", "咦，拳頭無私絕後看，瞿曇頂上活鱍鱍。"]'),
('41190629-9baf-4952-931c-7b8b6def70ee','偈頌十首  其七','釋如淨','宋','宋诗','song-poetry','','[]','十二峰前上戲棚，那吒赤脫點天强。',32,'全唐诗/poet.song.175000.json','["十二峰前上戲棚，那吒赤脫點天强。", "屈煩皷笛低頭舞，弄醜真堪笑一場。"]'),
('e01acb6c-8eed-4d6b-985a-1d97654b1977','偈頌十首  其八','釋如淨','宋','宋诗','song-poetry','','[]','秋風清，秋月明，大地山河露眼睛。',32,'全唐诗/poet.song.175000.json','["秋風清，秋月明，大地山河露眼睛。", "瑞岩點瞎重相見，棒喝交馳驗衲僧。"]'),
('f7bcb4d7-3c3f-4620-9d33-61ba93658c2f','偈頌十首  其九','釋如淨','宋','宋诗','song-poetry','','[]','今朝日南長至，黑豆生芽。',39,'全唐诗/poet.song.175000.json','["今朝日南長至，黑豆生芽。", "大衆恭惟懽慶，鐵樹開花。", "如何結果，龍馳虎驟，撒土拋沙。"]'),
('6695a0e8-c94e-4ae8-9787-67c1554db28f','偈頌十首  其一○','釋如淨','宋','宋诗','song-poetry','','[]','瑞岩一隻破木靴，幾箇攙來盡要拕。',32,'全唐诗/poet.song.175000.json','["瑞岩一隻破木靴，幾箇攙來盡要拕。", "唯有老僧能踢脫，出門赤脚笑呵呵。"]'),
('2ea23d7b-a0bb-48fe-b7bc-f7c55a68bfe9','偈頌十八首  其一','釋如淨','宋','宋诗','song-poetry','','[]','淨慈屋裏門，淨慈屋裏開。',38,'全唐诗/poet.song.175000.json','["淨慈屋裏門，淨慈屋裏開。", "昔日淨慈曾此去，淨慈從此又還來。", "咦，淨慈關棙衮風雷。"]'),
('bd1c3de1-248b-43e4-ae67-7840be546a2e','偈頌十八首  其二','釋如淨','宋','宋诗','song-poetry','','[]','大開此殿，親面一見。',28,'全唐诗/poet.song.175000.json','["大開此殿，親面一見。", "眼裏抽釘，腦後拔箭，本來無象通機變。"]'),
('b6945518-a924-4d42-9f2c-3b70e78f3bb0','偈頌十八首  其三','釋如淨','宋','宋诗','song-poetry','','[]','坐斷維摩方丈，發露閻羅地獄。',30,'全唐诗/poet.song.175000.json','["坐斷維摩方丈，發露閻羅地獄。", "千古萬古黑漫漫，劍樹刀山轉轆轆。"]'),
('f585b6e3-506b-4329-8fc5-ed024fe3cfb0','偈頌十八首  其四','釋如淨','宋','宋诗','song-poetry','','[]','當天一句，萬機顯露。',24,'全唐诗/poet.song.175000.json','["當天一句，萬機顯露。", "衲僧頂戴奉行，鼻孔機先證據。"]'),
('1083fb2b-4694-4d9b-8027-edbba29763d9','偈頌十八首  其五','釋如淨','宋','宋诗','song-poetry','','[]','淨慈法座，木頭一棚。',20,'全唐诗/poet.song.175000.json','["淨慈法座，木頭一棚。", "橫撐豎撐，黑漆光生。"]'),
('927d1acd-f135-4fd9-bbe6-a61a97c280db','偈頌十八首  其六','釋如淨','宋','宋诗','song-poetry','','[]','漫天大水雲翻墨，捲地狂風浪衮山。',48,'全唐诗/poet.song.175000.json','["漫天大水雲翻墨，捲地狂風浪衮山。", "掣斷絲綸歸喝彩，鯨鰲只在此山間。", "操舟又入洪波裏，愁殺漁翁兩鬢斑。"]'),
('d0d7c47c-6188-40f5-9b9b-d66e24dfcd7a','偈頌十八首  其七','釋如淨','宋','宋诗','song-poetry','','[]','打殺然燈佛，墮落黑暗獄。',32,'全唐诗/poet.song.175000.json','["打殺然燈佛，墮落黑暗獄。", "永劫無出期，衲僧歌一曲。", "滿天星斗輝華屋。"]'),
('de7db3c7-5cb3-47ac-ba06-d8208b9f13fa','偈頌十八首  其八','釋如淨','宋','宋诗','song-poetry','','[]','楊柳粧腰带，梅花絡臂韝。',32,'全唐诗/poet.song.175000.json','["楊柳粧腰带，梅花絡臂韝。", "黄鶑偷眼覷，舞得最風流。", "淨慈門下蘿蔔頭。"]'),
('1c243345-d13a-4459-98ab-d4e721d55d2f','偈頌十八首  其九','釋如淨','宋','宋诗','song-poetry','','[]','者箇是百尺竿頭，進一步則有象，退一步則無蹤。',42,'全唐诗/poet.song.175000.json','["者箇是百尺竿頭，進一步則有象，退一步則無蹤。", "進退全機變，從衡振祖風。", "都在南山掌握中。"]'),
('ddb7e59b-d10f-480e-be87-2fc376c1282e','偈頌十八首  其一○','釋如淨','宋','宋诗','song-poetry','','[]','今朝五月正清和，榴花詩句入禪那。',32,'全唐诗/poet.song.175000.json','["今朝五月正清和，榴花詩句入禪那。", "濃綠萬枝紅一點，動人春色不須多。"]'),
('346b1766-74c7-4087-878b-efd9e1fb2128','偈頌十八首  其一一','釋如淨','宋','宋诗','song-poetry','','[]','莫謗瞿曇今日生，插天山嶽勢崢嶸。',32,'全唐诗/poet.song.175000.json','["莫謗瞿曇今日生，插天山嶽勢崢嶸。", "一番雨洗添狼藉，萬古風烟恨不平。"]'),
('c86757dd-3a3d-4f73-888e-0a838baf5a47','偈頌十八首  其一二','釋如淨','宋','宋诗','song-poetry','','[]','萬派朝宗一派收，揚清激濁幾經秋。',32,'全唐诗/poet.song.175000.json','["萬派朝宗一派收，揚清激濁幾經秋。", "忽然到底都乾却，露柱燈籠笑不休。"]'),
('e2fce014-5850-4860-81ed-cbb5bffcee81','偈頌十八首  其一三','釋如淨','宋','宋诗','song-poetry','','[]','古佛不曾過去，現在法如是。',25,'全唐诗/poet.song.175000.json','["古佛不曾過去，現在法如是。", "一聲婆餠焦，啼在竹林裏。"]'),
('977de792-9ddd-4619-a1f3-facde0b24057','偈頌十八首  其一四','釋如淨','宋','宋诗','song-poetry','','[]','惆悵杜鵑鳥，哀哀晝夜啼。',62,'全唐诗/poet.song.175000.json','["惆悵杜鵑鳥，哀哀晝夜啼。", "落花飛絮怨流水，芳草懊恨迷東西。", "嗚呼，春光浩蕩可吊而不可送，醉倒愁人爛似泥。", "若匪丹山鳳，徒勞語楚雞。"]'),
('f53f3258-e280-4270-a5dd-b3ff64860ebf','偈頌十八首  其一五','釋如淨','宋','宋诗','song-poetry','','[]','六月連三伏，人間似焰爐。',32,'全唐诗/poet.song.175000.json','["六月連三伏，人間似焰爐。", "依稀寒水玉，彷彿冷秋菰。", "脩竹芭蕉入畫圖。"]'),
('5e38e8d2-90b5-426b-be43-0aa42d00c09e','偈頌十八首  其一六','釋如淨','宋','宋诗','song-poetry','','["\u897f\u6e56"]','上大人，丘乙己，西湖南山圖畫裏。',48,'全唐诗/poet.song.175000.json','["上大人，丘乙己，西湖南山圖畫裏。", "孔門弟子無人識，空有三千七十士。", "忽然一陣秋風吹，吹作秋雲送流水。"]'),
('39bb59e7-6aa3-4bf5-ab7f-2c404e1be627','偈頌十八首  其一七','釋如淨','宋','宋诗','song-poetry','','["\u897f\u6e56"]','衲僧拄杖子，漫漫黑似烟。',40,'全唐诗/poet.song.175000.json','["衲僧拄杖子，漫漫黑似烟。", "西湖九箇月，可惡亦堪憐。", "忽然飛過鄞江去，攪動滄溟浪拍天。"]'),
('8b582440-662d-4b73-8424-beb7f316a5eb','偈頌二十五首  其一','釋如淨','宋','宋诗','song-poetry','','[]','天童大解脫門豁開。',37,'全唐诗/poet.song.175000.json','["天童大解脫門豁開。", "衲僧自已透，乾坤無表裏。", "萬古清風八面來，前樓後閣玲瓏起。"]'),
('9d3e3499-44f7-4def-84e1-ec6a75a084c5','偈頌二十五首  其二','釋如淨','宋','宋诗','song-poetry','','[]','黄金妙相，馿腮馬觜。',22,'全唐诗/poet.song.175000.json','["黄金妙相，馿腮馬觜。", "咦，賊是小人，智過君子。"]'),
('6feacbfd-568d-4305-aee1-537822d761ef','偈頌二十五首  其三','釋如淨','宋','宋诗','song-poetry','','[]','橫一丈，豎一丈。',28,'全唐诗/poet.song.175000.json','["橫一丈，豎一丈。", "文殊維摩，隔壁抓癢。", "盡大地人，不釣自上。"]'),
('b01f3c24-2e79-496e-b838-df2c61042660','偈頌二十五首  其四','釋如淨','宋','宋诗','song-poetry','','[]','爐炭爲牀，鑊湯爲座。',20,'全唐诗/poet.song.175000.json','["爐炭爲牀，鑊湯爲座。", "口吐黑烟，彌天罪過。"]'),
('502ac0b2-d16c-4d8a-9ed9-6640f4d845b9','偈頌二十五首  其五','釋如淨','宋','宋诗','song-poetry','','[]','有問有答，屎尿狼藉。',20,'全唐诗/poet.song.175000.json','["有問有答，屎尿狼藉。", "無問無答，雷霆霹靂。"]'),
('085a6390-7fa3-479e-a253-a5ea7d2171ab','偈頌二十五首  其六','釋如淨','宋','宋诗','song-poetry','','[]','外不放入，內不放出。',36,'全唐诗/poet.song.175000.json','["外不放入，內不放出。", "痛下一槌，萬事了畢。", "太白峰前令斬新，內外紀綱俱委悉。"]'),
('9783ff35-490d-4e33-ae4f-d9c59a0e9685','偈頌二十五首  其七','釋如淨','宋','宋诗','song-poetry','','[]','冤有頭，債有主。',42,'全唐诗/poet.song.175000.json','["冤有頭，債有主。", "一劍當鋒，豁開門戶。", "拽隊成群恁麽來，放火殺人相合聚。", "老胡頂𩕳跨龍虎。"]'),
('925508aa-8956-409e-aaeb-1a3a75ba5bbf','偈頌二十五首  其八','釋如淨','宋','宋诗','song-poetry','','[]','心念分飛，如何措手。',81,'全唐诗/poet.song.175000.json','["心念分飛，如何措手。", "趙州狗子佛性無，只箇無字鐵掃帚。", "掃處紛飛多，紛飛多處掃。", "轉掃轉多，掃不得處拚命掃。", "晝夜豎起脊梁，勇猛切莫放倒。", "忽然掃破太虛空，萬別千差盡豁通。"]'),
('bf4aeca3-f27b-4de3-8b91-fe3dceccb405','偈頌二十五首  其九','釋如淨','宋','宋诗','song-poetry','','[]','只箇柴頭煨火種，諸方聿起競開爐。',62,'全唐诗/poet.song.175000.json','["只箇柴頭煨火種，諸方聿起競開爐。", "天童直截超宗處，爐與柴頭盡底無。", "恁麽却有煖氣，正好猛做工夫。", "驀忽雷霆轟烈焰，從教深夜雪糢糊。"]'),
('55ee95b1-7377-454e-b6fb-ddf44db49ddc','偈頌二十五首  其一○','釋如淨','宋','宋诗','song-poetry','','[]','開無間地獄，現閻羅大王。',70,'全唐诗/poet.song.175000.json','["開無間地獄，現閻羅大王。", "聚夜叉一部，列牛頭兩行。", "與其進者劍樹上猛火進用，與其退者刀山裏寒冰退藏。", "尀耐飯飽弄筯，判斷屎急尿床。", "花柳春風入戲場。"]'),
('2edeb506-2796-47e4-90f6-c33d75222875','偈頌二十五首  其一一','釋如淨','宋','宋诗','song-poetry','','[]','天童鐵臭老拳頭，打殺江湖水牯牛。',48,'全唐诗/poet.song.175000.json','["天童鐵臭老拳頭，打殺江湖水牯牛。", "夜深忽然生箇卵，天明推出大日頭。", "晒㫰諸人烝濕處，免教行步滑如油。"]'),
('9deeb539-4467-467d-815b-9f84bb0a28ed','偈頌二十五首  其一二','釋如淨','宋','宋诗','song-poetry','','[]','靈雲見處桃花開，天童見處桃花落。',44,'全唐诗/poet.song.175000.json','["靈雲見處桃花開，天童見處桃花落。", "桃花開，春風催。", "桃花落，春風惡。", "春風惡，桃花躍浪生頭角。"]'),
('a8df4c81-9bbf-4def-a1b4-8a989dc827cc','偈頌二十五首  其一三','釋如淨','宋','宋诗','song-poetry','','[]','結却衲僧布袋頭，天童拈來作氣毬。',32,'全唐诗/poet.song.175000.json','["結却衲僧布袋頭，天童拈來作氣毬。", "脚尖趯出佛無數，付與叢林作馬牛。"]'),
('86e38b2e-2dac-4711-a843-4fd2e0336ffd','偈頌二十五首  其一四','釋如淨','宋','宋诗','song-poetry','','[]','鐵酸豏，金剛圈。',40,'全唐诗/poet.song.175000.json','["鐵酸豏，金剛圈。", "塞斷咽喉，拽脫鼻孔。", "天童立地有分，衲僧乞命無門，堪與瞿曇作子孫。"]'),
('8c223b95-9610-49e2-8766-aac7aefa934a','偈頌二十五首  其一五','釋如淨','宋','宋诗','song-poetry','','[]','推倒多年老鼠窠，掃空平地笑呵呵。',62,'全唐诗/poet.song.175000.json','["推倒多年老鼠窠，掃空平地笑呵呵。", "從空架起生頭角，蓋覆馿牛不厭多。", "今朝成就大緣，千古發揮大事。", "斫額任他門外客，到家還我箇中人。"]'),
('0582e05e-1e0d-48f5-af53-99cd70e431b7','偈頌二十五首  其一六','釋如淨','宋','宋诗','song-poetry','','[]','竇八布衫穿，大家出隻手。',56,'全唐诗/poet.song.175000.json','["竇八布衫穿，大家出隻手。", "橫須彌爲槩，量大海爲斗。", "生殺在前，收放在後，歸功塞破虛空口。", "天童不敢相辜，甘作啼雞吠狗。"]'),
('1cec8d05-b78a-45f3-ab0f-40aac9f07222','偈頌二十五首  其一七','釋如淨','宋','宋诗','song-poetry','','[]','金剛王寶劍在匣，有望風不犯之威。',60,'全唐诗/poet.song.175000.json','["金剛王寶劍在匣，有望風不犯之威。", "天童喝下飛出，變作無孔鐵鎚。", "輥入荒田亂草，任教日炙風吹。", "拈匙把筯知多少，不是知音不易知。"]'),
('6b380057-8050-408a-aa0b-a32ac9d89c64','偈頌二十五首  其一八','釋如淨','宋','宋诗','song-poetry','','[]','去那邊去，來者裏來，中間絕壑斷崖。',51,'全唐诗/poet.song.175000.json','["去那邊去，來者裏來，中間絕壑斷崖。", "依稀金磴闊，彷彿彩虹彎，人從橋上過。", "松蘿影裏開天巧，汗黑光中入畫看。"]'),
('f4f9f5dc-5cdd-4e05-9c75-2c1dda6c2abe','偈頌二十五首  其一九','釋如淨','宋','宋诗','song-poetry','','[]','眼見黄葉落，耳聞孤雁鳴。',22,'全唐诗/poet.song.175000.json','["眼見黄葉落，耳聞孤雁鳴。", "咦，溪上秋光分外清。"]'),
('7710a83b-bf00-485c-bd11-63ff77646c28','偈頌二十五首  其二○','釋如淨','宋','宋诗','song-poetry','','[]','八月十八錢塘潮，浙翁聲價潑天高。',64,'全唐诗/poet.song.175000.json','["八月十八錢塘潮，浙翁聲價潑天高。", "盡教四海弄潮手，徹底窮淵輥一遭。", "重揀擇，不辭勞，要透龍門繼鳳毛。", "忽然收卷還源去，萬古曹溪風怒號。"]'),
('640a156b-363b-4080-8dcf-3927b59ba85f','偈頌二十五首  其二一','釋如淨','宋','宋诗','song-poetry','','[]','天童仲冬第一句，槎槎牙牙老梅樹。',91,'全唐诗/poet.song.175000.json','["天童仲冬第一句，槎槎牙牙老梅樹。", "忽開花，一花兩花三四五花無數花。", "清不可誇，香不可誇。", "散作春容吹草木，衲僧箇箇頂門禿。", "驀劄變怪，狂風暴雨交衮，大地雪漫漫。", "老梅樹太無端，寒凍摩挲鼻孔酸。"]'),
('02e2623e-15ae-4468-88a3-18a069006bc4','偈頌二十五首  其二二','釋如淨','宋','宋诗','song-poetry','','[]','古今大雪滿長安，天童賣却這心肝。',52,'全唐诗/poet.song.175000.json','["古今大雪滿長安，天童賣却這心肝。", "無神通菩薩猛劈一椎，千手眼大悲捏怪多端。", "獅子教兒迷子訣，老婆心切不相瞞。"]'),
('ac2c64f6-6849-460b-98d1-20bcb9d4aa67','偈頌二十五首  其二三','釋如淨','宋','宋诗','song-poetry','','[]','霜風號肅殺，霜葉墮蕭颾。',24,'全唐诗/poet.song.175000.json','["霜風號肅殺，霜葉墮蕭颾。", "唯有玲瓏岩，崔嵬望轉高。"]'),
('d37d1b7e-680c-4774-b455-657df3e889a6','偈頌二十五首  其二四','釋如淨','宋','宋诗','song-poetry','','[]','瞿曇臘月八，夜半走出山。',32,'全唐诗/poet.song.175000.json','["瞿曇臘月八，夜半走出山。", "賊路羊腸曲，偷心虎背斑。", "鈍置人天者一番。"]'),
('358b17c0-eaea-45cc-8452-f8314b1b9cb0','偈頌二十五首  其二五','釋如淨','宋','宋诗','song-poetry','','[]','進院得住便住，退院要行便行。',26,'全唐诗/poet.song.175000.json','["進院得住便住，退院要行便行。", "箇條烏拄杖，莫怪太生獰。"]'),
('2d91ac4b-89e0-4d41-aac9-fa85a80a2492','偈頌九首  其一','釋如淨','宋','宋诗','song-poetry','','[]','衲衣下事火燒山，臘月家貧徹骨寒。',32,'全唐诗/poet.song.175000.json','["衲衣下事火燒山，臘月家貧徹骨寒。", "堪笑連延曾未息，眉毛焦赤面皮斑。"]'),
('24f83725-cbfd-4105-8744-4a022884c21c','偈頌九首  其二','釋如淨','宋','宋诗','song-poetry','','[]','打破黑漆桶，十方空索索。',24,'全唐诗/poet.song.175000.json','["打破黑漆桶，十方空索索。", "不受靈山記，安居大圓覺。"]'),
('eb312c17-0880-41e9-8388-cc21923eabc0','偈頌九首  其三','釋如淨','宋','宋诗','song-poetry','','[]','十方聚會魚游網，三月安居鳥入籠。',32,'全唐诗/poet.song.175000.json','["十方聚會魚游網，三月安居鳥入籠。", "生殺盡時蠶作繭，心空及第黑山中。"]'),
('806bb54f-bf50-4e00-8f63-fa6fb14b31f9','偈頌九首  其四','釋如淨','宋','宋诗','song-poetry','','[]','鑽冰取火憑誰信，拚命工夫入死門。',32,'全唐诗/poet.song.175000.json','["鑽冰取火憑誰信，拚命工夫入死門。", "脫體一交翻得活，金剛正焰透乾坤。"]'),
('18fc19cf-f3c8-4862-b67f-486fe25f6248','偈頌九首  其五','釋如淨','宋','宋诗','song-poetry','','[]','五臺山上雲蒸飯，佛殿階前狗尿天。',32,'全唐诗/poet.song.175000.json','["五臺山上雲蒸飯，佛殿階前狗尿天。", "剎竿頭上煎䭔子，三箇胡孫夜簸錢。"]'),
('46023767-acd9-4538-bc51-113c6a34361e','偈頌九首  其六','釋如淨','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖湖裏水，南山山上雲。',24,'全唐诗/poet.song.175000.json','["西湖湖裏水，南山山上雲。", "天台拄杖子，相見笑忻忻。"]'),
('5e142c64-b4d5-4628-a1ce-07fea5c5873e','偈頌九首  其七','釋如淨','宋','宋诗','song-poetry','','[]','平地起骨堆，虛空剜窟籠。',24,'全唐诗/poet.song.175000.json','["平地起骨堆，虛空剜窟籠。", "驀透兩重關，拈却黑漆桶。"]'),
('10639d49-1cdc-4574-9a2f-31a7c48cea58','偈頌九首  其八','釋如淨','宋','宋诗','song-poetry','','[]','妙音觀世音，具足神通力。',24,'全唐诗/poet.song.175000.json','["妙音觀世音，具足神通力。", "十方諸國土，無剎不現身。"]'),
('f10c43ec-f55b-4be6-b50c-aeb665c55a10','偈頌九首  其九','釋如淨','宋','宋诗','song-poetry','','[]','跳出淨慈牛欄，撞入太白馬廄。',30,'全唐诗/poet.song.175000.json','["跳出淨慈牛欄，撞入太白馬廄。", "一團罪業黑漫漫，風吹日炙薰天臭。"]'),
('9aba88c2-b553-40c5-8e65-6f02cf3d091c','頌古八首  其一','釋如淨','宋','宋诗','song-poetry','','[]','清貧三盞便輕酬，萬里曹門出鄭州。',32,'全唐诗/poet.song.175000.json','["清貧三盞便輕酬，萬里曹門出鄭州。", "盡情斫却月中桂，惱亂春風卒未休。"]'),
('c0d8e835-b155-4654-85c4-9a55dd685b7c','頌古八首  其二','釋如淨','宋','宋诗','song-poetry','','[]','喚一聲兮應一聲，兩箇分明好弟兄。',32,'全唐诗/poet.song.175000.json','["喚一聲兮應一聲，兩箇分明好弟兄。", "倒却門前剎竿著，芳草漫天荆棘生。"]'),
('826c4a73-cc1c-465a-9c8d-ce0ea05d4a24','頌古八首  其三','釋如淨','宋','宋诗','song-poetry','','[]','鐘聲披起鬰多羅，妙用靈通變化多。',32,'全唐诗/poet.song.175000.json','["鐘聲披起鬰多羅，妙用靈通變化多。", "賊是家親須掃跡，太平無象始安和。"]'),
('f113f3af-0224-49e9-a58b-0a4887751cf7','頌古八首  其四','釋如淨','宋','宋诗','song-poetry','','[]','萬物朝元不較他，拈來直截辨誵訛。',32,'全唐诗/poet.song.175000.json','["萬物朝元不較他，拈來直截辨誵訛。", "游春浪子風流甚，賣弄三文黑老婆。"]'),
('0cef1bae-c67a-4216-969d-36db4ecb8abc','頌古八首  其五','釋如淨','宋','宋诗','song-poetry','','[]','肘後驀生閑絡索，風前忽布閙叉撐。',32,'全唐诗/poet.song.175000.json','["肘後驀生閑絡索，風前忽布閙叉撐。", "那吒八臂空惆悵，夜半三更白晝行。"]'),
('fde425b2-701b-48d4-8d86-9c47f7a33aa8','頌古八首  其六','釋如淨','宋','宋诗','song-poetry','','[]','張來張打油，李來李打油。',24,'全唐诗/poet.song.175000.json','["張來張打油，李來李打油。", "通身骨轆轉，打得最風流。"]'),
('7f21ded1-144e-4afe-9611-bd287c08c537','頌古八首  其七','釋如淨','宋','宋诗','song-poetry','','[]','一箇烏梅似本形，蜘蛛結網打蜻蜓。',32,'全唐诗/poet.song.175000.json','["一箇烏梅似本形，蜘蛛結網打蜻蜓。", "蜻蜓落了兩片翼，堪笑烏梅咬鐵釘。"]'),
('91c7f6a5-af3a-41e5-ba1f-19cd6786c92d','頌古八首  其八','釋如淨','宋','宋诗','song-poetry','','[]','策起眉毛答問端，親曾見佛不相瞞。',32,'全唐诗/poet.song.175000.json','["策起眉毛答問端，親曾見佛不相瞞。", "至今應供四天下，春在梅梢带雪寒。"]'),
('3678cae5-d475-4b5b-a5fa-0c6f78aadbdb','觀音贊  其一','釋如淨','宋','宋诗','song-poetry','','[]','端坐圓通微妙相，衆生眼裏堆青嶂。',32,'全唐诗/poet.song.175000.json','["端坐圓通微妙相，衆生眼裏堆青嶂。", "曉來窗外聽啼禽，春風不在花枝上。"]'),
('c03b0433-795c-4467-a3d1-b265a9ab1a09','觀音贊  其二','釋如淨','宋','宋诗','song-poetry','','[]','頭上寶冠牛戴角，脚下蓮華馬踏蹄。',32,'全唐诗/poet.song.175000.json','["頭上寶冠牛戴角，脚下蓮華馬踏蹄。", "通身瓔珞皮毛債，歷劫風流輥水泥。"]'),
('7ab53b51-42a9-4a1b-80f0-caca1a5a55e4','觀音贊  其三','釋如淨','宋','宋诗','song-poetry','','[]','心塵脫落開岩洞，自性圓通儼紺容。',42,'全唐诗/poet.song.175000.json','["心塵脫落開岩洞，自性圓通儼紺容。", "天子敬，龍之恭，不以爲喜安然中。", "咦，更薦海濤翻黑風。"]'),
('10e98168-4b26-4a07-8212-709d253cca51','出山相贊  其一','釋如淨','宋','宋诗','song-poetry','','[]','凍不死，餓不死，深山走出這面觜。',26,'全唐诗/poet.song.175000.json','["凍不死，餓不死，深山走出這面觜。", "咦，人間天上風波起。"]'),
('04a02945-e1fc-4df1-ad94-5aea176d8d89','出山相贊  其二','釋如淨','宋','宋诗','song-poetry','','[]','摩耶落賺屙出來，撞入草窠打一回。',32,'全唐诗/poet.song.175000.json','["摩耶落賺屙出來，撞入草窠打一回。", "誰知有屈叫不得，殃害兒孫作罪魁。"]'),
('4bc21bc5-3c27-4e96-a9b1-6c17b71f00d6','維摩贊','釋如淨','宋','宋诗','song-poetry','','[]','大病現前，乾坤一默。',31,'全唐诗/poet.song.175000.json','["大病現前，乾坤一默。", "老而不死，是謂之賊。", "賊賊，春風啼鳥花狼藉。"]'),
('6ba7105d-3d47-4657-b056-7ac01dcb5b2c','達磨贊  其一','釋如淨','宋','宋诗','song-poetry','','[]','豁然無聖，自作自敗。',54,'全唐诗/poet.song.175000.json','["豁然無聖，自作自敗。", "面壁釘樁，猶敢捏怪。", "尀耐神光屙一堆，引他臭穢遭他壞。", "咦，葛藤荒草徧乾坤，年年賸欠春風債。"]'),
('0f16fc7e-e1a8-4018-927b-553ff1ff68b4','達磨贊  其二','釋如淨','宋','宋诗','song-poetry','','[]','金烏飛上玉闌干，黑漆崑崙背面看。',32,'全唐诗/poet.song.175000.json','["金烏飛上玉闌干，黑漆崑崙背面看。", "畢竟者些傳不得，落花流水太無端。"]'),
('00aefe11-59f2-48f4-8534-ec7e9f2f7af8','達磨贊  其三','釋如淨','宋','宋诗','song-poetry','','[]','脚下莖蘆，到岸也未。',30,'全唐诗/poet.song.175000.json','["脚下莖蘆，到岸也未。", "直指人心，馿屁狗屁。", "咦，千古叢林遭鈍置。"]'),
('c9680604-de59-4f23-9bd8-8223ade933d2','聽松風布袋贊  其一','釋如淨','宋','宋诗','song-poetry','','[]','松風鳴，側耳聽，捫腹而笑，賊精賊精。',28,'全唐诗/poet.song.175000.json','["松風鳴，側耳聽，捫腹而笑，賊精賊精。", "咦，千古萬古得人憎。"]'),
('52cbdb9c-49d3-4d25-bff3-3bbc39afa9b9','聽松風布袋贊  其二','釋如淨','宋','宋诗','song-poetry','','[]','靠箇布袋瞌睡，平地突出毒刺。',28,'全唐诗/poet.song.175000.json','["靠箇布袋瞌睡，平地突出毒刺。", "有人一踼踼翻，天下脚跟出氣。"]'),
('82f8c166-ac16-4e6a-aa1e-e0557f02a242','四睡圖贊','釋如淨','宋','宋诗','song-poetry','','[]','拾得寒山，老虎豐干。',38,'全唐诗/poet.song.175000.json','["拾得寒山，老虎豐干。", "睡到馿年，也太無端。", "咦，驀地起來開活眼，許多妖怪自相瞞。"]'),
('6ca5eada-599c-4052-80c2-b17c86a3cd39','圓覺圖贊','釋如淨','宋','宋诗','song-poetry','','[]','一隊豬狗漢，圍繞業識幢。',48,'全唐诗/poet.song.175000.json','["一隊豬狗漢，圍繞業識幢。", "只管要說傍人罪過，不知敗缺自己賊贓。", "咄，太平無象打一椎，驚破虛空閃電飛。"]'),
('0242cf5f-2917-4253-b17d-27dd529989cb','善財贊','釋如淨','宋','宋诗','song-poetry','','[]','捏住乾坤粉一團，大人剛被小人瞞。',32,'全唐诗/poet.song.175000.json','["捏住乾坤粉一團，大人剛被小人瞞。", "機先若具機先眼，走殺從教起釁端。"]'),
('8c1e9c4a-6559-484b-8ed3-694eeeb32edd','普化贊','釋如淨','宋','宋诗','song-poetry','','[]','者漢走從何處來，皷合臨濟白拈賊。',32,'全唐诗/poet.song.175000.json','["者漢走從何處來，皷合臨濟白拈賊。", "鐸聲摇撼動風雷，至今大地俱狼藉。"]'),
('5b166197-f4fb-4baa-9491-88ddff9e9411','泉大道贊','釋如淨','宋','宋诗','song-poetry','','[]','棒頭挑起葫蘆，手裏伸出鉢盂。',30,'全唐诗/poet.song.175000.json','["棒頭挑起葫蘆，手裏伸出鉢盂。", "噇酒噇肉破落戶，天上人間大丈夫。"]'),
('635f3437-1e1a-4e7d-81d9-2bd0fb6e2a69','端獅子贊','釋如淨','宋','宋诗','song-poetry','','[]','咄哉捏怪老狐狸，披起金毛獅子皮。',32,'全唐诗/poet.song.175000.json','["咄哉捏怪老狐狸，披起金毛獅子皮。", "弄盡任從天外去，尾巴敗露已多時。"]'),
('2ec0415f-633e-4744-804b-d6d438ada0ec','言法華贊','釋如淨','宋','宋诗','song-poetry','','[]','脚下長拖破木履，口內不知道甚底。',32,'全唐诗/poet.song.175000.json','["脚下長拖破木履，口內不知道甚底。", "惱亂風光沒奈何，南北東西無定止。"]'),
('478671ca-f18d-42eb-ab3f-fb5e484c5b85','南山律師贊','釋如淨','宋','宋诗','song-poetry','','[]','優波離後身，韋將軍捧足。',42,'全唐诗/poet.song.175000.json','["優波離後身，韋將軍捧足。", "布衣真童男，瓦缽天厨食。", "咦，歷劫戒光秋月明，南山靜照烟霜色。"]'),
('a05a69c7-63ac-4c17-8c7f-5cb1e184507b','臨濟贊','釋如淨','宋','宋诗','song-poetry','','[]','捏箇空拳，嚇殺天下。',20,'全唐诗/poet.song.175000.json','["捏箇空拳，嚇殺天下。", "這般祖師，畜生馿馬。"]'),
('08b4f1ca-22ad-4d3a-8d08-f54e9337b4b5','濟顛贊','釋如淨','宋','宋诗','song-poetry','','[]','天台山裏五百牛，跳出顛狂者一頭。',32,'全唐诗/poet.song.175000.json','["天台山裏五百牛，跳出顛狂者一頭。", "賽盡烟花瞞盡眼，尾巴狼藉轉風流。"]'),
('5311a615-fbc7-4bcc-a480-b7a1b288136d','無用頂相贊','釋如淨','宋','宋诗','song-poetry','','[]','打殺宣州花木瓜，爆出越州翁木大。',54,'全唐诗/poet.song.175000.json','["打殺宣州花木瓜，爆出越州翁木大。", "血滴滴風衮劍輪，黑漫漫彌天罪過。", "咦，描邈者箇賊頭，三千里外誰耐面熱而汗迸流。"]'),
('0eda523a-62d6-4fb0-a331-25d6cf7c7a68','自贊  其一','釋如淨','宋','宋诗','song-poetry','','[]','烏龜殻空索索，打一鑽響剝剝。',44,'全唐诗/poet.song.175000.json','["烏龜殻空索索，打一鑽響剝剝。", "也是張拳嚇野狐，描邈出來增醜惡。", "雖然三十年後，只管有人卜度。"]'),
('527e87ec-b6b0-4d20-9b32-36e93ea06866','自贊  其二','釋如淨','宋','宋诗','song-poetry','','[]','突出娑婆世界，一枚真箇村頭。',104,'全唐诗/poet.song.175000.json','["突出娑婆世界，一枚真箇村頭。", "行脚都無用處，推倒只好做牛。", "釘雙角，插條尾，綠楊芳草春風裏。", "可殺有力會耕田，賣與閻王還飯錢。", "不然掣電幾先喫，痛拳無明業識幢。", "豎起漫天黑，一句不相當。", "拳頭飛霹靂，咦，老婆心切血滴滴。"]'),
('cdf8a5ad-d8c3-4d27-82c2-f9d43f38ef8d','源山主求贊頂相','釋如淨','宋','宋诗','song-poetry','','["\u897f\u6e56"]','箇是淨慈毛和尚，口言禍福有定當。',189,'全唐诗/poet.song.175000.json','["箇是淨慈毛和尚，口言禍福有定當。", "逐日隨緣去赴齋，是謂兩脚功德藏。", "彫裝千佛，布砌兩廊。", "判斷一切魍魎鬼，主管五百羅漢堂。", "至於修橋造路，與夫浴主街坊。", "聞一切善事如蠅見血，聞一切惡事似蟹落湯。", "有時隨摟搜，若萬回老子懽喜。", "有時放歇蹶，若布袋和尚顛狂。", "得一文錢不曾落地，合十爪掌常乃謝天。", "只一味朴直，無些子壒塵。", "所以打動好事檀那，畫出這般面觜。", "且道如何比擬，八月十五中夜凉，一輪月照西湖水。"]'),
('8acf750b-751b-4d5e-be8f-fd6f015d1067','幹藏','釋如淨','宋','宋诗','song-poetry','','[]','瞿曇老賊口親屙，馿屎相兼馬屎多。',32,'全唐诗/poet.song.175000.json','["瞿曇老賊口親屙，馿屎相兼馬屎多。", "打作一團都撥轉，潑天臭惡惱娑婆。"]'),
('4eebddf6-20d9-4898-aeba-0ad14dc81bbc','化炭','釋如淨','宋','宋诗','song-poetry','','[]','一刀兩段沒商量，透出無明大火坑。',32,'全唐诗/poet.song.175000.json','["一刀兩段沒商量，透出無明大火坑。", "再入死灰烹得活，歲寒聲價轉崢嶸。"]'),
('28f1aa40-e641-4f60-a73e-af5016f5132d','起淨慈方丈','釋如淨','宋','宋诗','song-poetry','','[]','方方一丈牯牛欄，佛祖驅來要透關。',32,'全唐诗/poet.song.175000.json','["方方一丈牯牛欄，佛祖驅來要透關。", "聊借眉毛相架搆，遮天蓋地黑漫漫。"]'),
('1444f3d3-b26c-48f0-88e7-2f7de50ecaf8','牧翁','釋如淨','宋','宋诗','song-poetry','','[]','自家鼻孔自家穿，自家繩索自家牽。',32,'全唐诗/poet.song.175000.json','["自家鼻孔自家穿，自家繩索自家牽。", "自家忽地都忘却，一笛清風送楚天。"]'),
('af546b20-f4e8-4d92-8e35-f873fbbea953','講人更衣','釋如淨','宋','宋诗','song-poetry','','[]','老胡教網漫天闊，當甚多年椀脫丘。',32,'全唐诗/poet.song.175000.json','["老胡教網漫天闊，當甚多年椀脫丘。", "勘破轉關千聖外，別行條貫結冤讎。"]'),
('eaa07c92-b5a8-4e42-b135-0c0d07076fcf','風鈴','釋如淨','宋','宋诗','song-poetry','','[]','通身是口掛虛空，不管東西南北風。',32,'全唐诗/poet.song.175000.json','["通身是口掛虛空，不管東西南北風。", "一等與渠談般若，滴丁東了滴丁東。"]'),
('3384a11f-e98a-439f-8fda-c591a0d87e47','拄杖頌寄松源和尚','釋如淨','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','七尺烏藤掛東壁，春風忽來生兩翼。',64,'全唐诗/poet.song.175000.json','["七尺烏藤掛東壁，春風忽來生兩翼。", "鞭起飛龍趁不得，洞庭攪碎琉璃碧。", "去兮去兮明歷歷，梅花影裏休相覓。", "爲雨爲雲自古今，古今寥寥有何極。"]'),
('c49597ce-a648-42b2-8939-48b70fd3a5cd','敬溪翁','釋如淨','宋','宋诗','song-poetry','','[]','揭翻古剡岸雲開，峻發清機劈箭來。',32,'全唐诗/poet.song.175000.json','["揭翻古剡岸雲開，峻發清機劈箭來。", "裂轉面皮乾剝剝，萬山奔浪笑咍咍。"]'),
('1910c289-23f6-407f-a393-eac828951756','送亮藏主謁碧雲','釋如淨','宋','宋诗','song-poetry','','[]','咬狗豬漢爛泥團，撮著參天劍刃寒。',32,'全唐诗/poet.song.175000.json','["咬狗豬漢爛泥團，撮著參天劍刃寒。", "轉入春風開笑眼，桃花紅照碧琅玕。"]'),
('b1e0dd75-b94e-4da6-8f63-4368f4833f84','送僧見明極和尚','釋如淨','宋','宋诗','song-poetry','','[]','機絲抽盡萬緣平，休倚寒岩轉路程。',32,'全唐诗/poet.song.175000.json','["機絲抽盡萬緣平，休倚寒岩轉路程。", "千聖不携無影像，那邊借伴月華明。"]'),
('a238576c-a34c-441a-8c5d-58b5eb6b8f1b','送僧','釋如淨','宋','宋诗','song-poetry','','[]','生逼猢猻坐鐵砧，一槌天地盡崩沈。',32,'全唐诗/poet.song.175000.json','["生逼猢猻坐鐵砧，一槌天地盡崩沈。", "橫來豎去呵呵笑，喫飯噇眠邁古今。"]'),
('30235e38-285c-4bb1-9919-c781d695e7b1','送覺兄歸洞庭','釋如淨','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','覺盡還源見本心，洞庭無蓋碧沈沈。',32,'全唐诗/poet.song.175000.json','["覺盡還源見本心，洞庭無蓋碧沈沈。", "衲僧不作這伎倆，浪急風高意轉深。"]'),
('d51eabeb-7e3c-4192-8f17-e88d97074bd7','提舉太尉張求頌','釋如淨','宋','宋诗','song-poetry','','[]','平生道德邁前賢，著漢衣冠拜漢天。',32,'全唐诗/poet.song.175000.json','["平生道德邁前賢，著漢衣冠拜漢天。", "自是名高閑不得，阿難依舊世尊前。"]'),
('823aed8f-2181-47ed-b420-9fc03fbdf7f0','觀使太尉張求頌','釋如淨','宋','宋诗','song-poetry','','[]','居士眼睛吞佛祖，衲僧鼻孔透乾坤。',32,'全唐诗/poet.song.175000.json','["居士眼睛吞佛祖，衲僧鼻孔透乾坤。", "眼睛鼻孔初無間，萬古宗門結痛冤。"]'),
('02897ddf-97ff-4232-ba41-33cb4a740ad3','相士','釋如淨','宋','宋诗','song-poetry','','[]','月落滄溟夜渺漫，衲僧面目太寒酸。',32,'全唐诗/poet.song.175000.json','["月落滄溟夜渺漫，衲僧面目太寒酸。", "擬將禍福輕偷眼，惡浪狂風衮亂山。"]'),
('f3040ef6-c0ef-4457-b799-f0acf248457b','牛圖','釋如淨','宋','宋诗','song-poetry','','[]','柳堤煙斂春風靜，鼻孔遼天一牯牛。',32,'全唐诗/poet.song.175000.json','["柳堤煙斂春風靜，鼻孔遼天一牯牛。", "拽轉通身依舊黑，野花芳草轉風流。"]'),
