('ea9c70d5-f27b-492f-8592-21f84f18ed4c','塗田','釋如淨','宋','宋诗','song-poetry','','[]','劄斷潮頭大海枯，十方公界佃官租。',32,'全唐诗/poet.song.175000.json','["劄斷潮頭大海枯，十方公界佃官租。", "寥寥萬古平如掌，不許傍人揚契書。"]'),
('5e4e5082-bc0f-4c24-b074-d48ca21e8e91','送蜀僧得母書歸鄉','釋如淨','宋','宋诗','song-poetry','','[]','雁落秋空剝萬金，寥寥一片老婆心。',32,'全唐诗/poet.song.175000.json','["雁落秋空剝萬金，寥寥一片老婆心。", "先天後地難回互，風急恩深冤亦深。"]'),
('3d2d8580-c2e3-4a58-abd2-ec47d8d932d4','接待','釋如淨','宋','宋诗','song-poetry','','[]','飯籮無底乾坤窄，舀出炎炎熱鐵丸。',32,'全唐诗/poet.song.175000.json','["飯籮無底乾坤窄，舀出炎炎熱鐵丸。", "爛斷饑腸重瞥地，佛魔無處辨來端。"]'),
('8cd31c30-9042-4174-9ed2-afca442d3677','禮真歇塔','釋如淨','宋','宋诗','song-poetry','','[]','歇盡真空透活機，兒孫相接命如絲。',32,'全唐诗/poet.song.175000.json','["歇盡真空透活機，兒孫相接命如絲。", "今無倒指空腸斷，杜宇血啼花上枝。"]'),
('a4e9c741-a21b-4692-a6c8-f23d8c0cda31','辭世頌','釋如淨','宋','宋诗','song-poetry','','[]','六十六年，罪犯彌天。',30,'全唐诗/poet.song.175000.json','["六十六年，罪犯彌天。", "打毬𨁝跳，活陷黄泉。", "咦，從來生死不相干。"]'),
('e7343a20-b237-4672-a2cc-2cc029104eba','偈頌十六首  其一','釋如淨','宋','宋诗','song-poetry','','[]','靈靈而時時昧，不得月隨流水。',28,'全唐诗/poet.song.175000.json','["靈靈而時時昧，不得月隨流水。", "歷歷而處處混，不得雨逐行雲。"]'),
('23eebaef-8f5b-41bb-ad7c-e250f49cb8cd','偈頌十六首  其二','釋如淨','宋','宋诗','song-poetry','','[]','山披錦雲而爛成春意，水含碧月而淡存秋容。',44,'全唐诗/poet.song.175000.json','["山披錦雲而爛成春意，水含碧月而淡存秋容。", "恁麽也恁麽，說似曾不中。", "黄頭并碧眼，消息子難通。"]'),
('23fcb0ee-f68e-41cb-97da-0d475edda884','偈頌十六首  其三','釋如淨','宋','宋诗','song-poetry','','[]','是不是是江光鋪練，非不是非花岳疊錦。',36,'全唐诗/poet.song.175000.json','["是不是是江光鋪練，非不是非花岳疊錦。", "舉竟合成什麽邊事，三界無法何處求心。"]'),
('5cf918a7-7d36-49a8-80b9-6745e0f4a7dd','偈頌十六首  其四','釋如淨','宋','宋诗','song-poetry','','[]','金牛弄得爛銀蹄，耕破劫空田地開。',32,'全唐诗/poet.song.175000.json','["金牛弄得爛銀蹄，耕破劫空田地開。", "不带泥痕今古路，牧童疎笛入雲來。"]'),
('95e833c8-d315-4bed-b5a1-daf111b42fd6','偈頌十六首  其五','釋如淨','宋','宋诗','song-poetry','','[]','善行者不移雙足，善入者不動雙扉。',32,'全唐诗/poet.song.175000.json','["善行者不移雙足，善入者不動雙扉。", "清秋夜冷波心月，誰問安禪友亦稀。"]'),
('e9d07381-f7f1-44ff-8288-c9e746dbca9d','偈頌十六首  其六','釋如淨','宋','宋诗','song-poetry','','[]','不勞澄九鼎，流動百花新。',24,'全唐诗/poet.song.175000.json','["不勞澄九鼎，流動百花新。", "木雞前樹報，月磨蘿鏡輪。"]'),
('47e6af54-6c71-4500-a2de-f27900ce9d22','偈頌十六首  其七','釋如淨','宋','宋诗','song-poetry','','[]','一花開五家宗要，一葉綴九室訣機。',32,'全唐诗/poet.song.175000.json','["一花開五家宗要，一葉綴九室訣機。", "朝朝暮暮只斯是，何用瓊林覓玉枝。"]'),
('58d9acf5-e03b-4eae-85ab-57c1c3e19636','偈頌十六首  其八','釋如淨','宋','宋诗','song-poetry','','[]','一機織作錦衣裳，是可太平君子牀。',32,'全唐诗/poet.song.175000.json','["一機織作錦衣裳，是可太平君子牀。", "只許寶山堆這裏，細把玉鍼貞上方。"]'),
('f21af887-9c8b-4249-af90-4dc90f23e9a1','偈頌十六首  其九','釋如淨','宋','宋诗','song-poetry','','[]','時節因緣佛性義，共移靈棹渡頭舟。',32,'全唐诗/poet.song.175000.json','["時節因緣佛性義，共移靈棹渡頭舟。", "玉麟带月離雲漢，金鳳啣花下彩樓。"]'),
('20e59d39-a9a9-4a5c-9b1b-b8f999be5f4a','偈頌十六首  其一○','釋如淨','宋','宋诗','song-poetry','','[]','無明暗室勿入近，暮日江山相映紅。',32,'全唐诗/poet.song.175000.json','["無明暗室勿入近，暮日江山相映紅。", "處處煙塵收不得，早來晚去失真風。"]'),
('2eafd429-ce62-416f-ab22-6757853d1a18','偈頌十六首  其一一','釋如淨','宋','宋诗','song-poetry','','[]','雲形水意擁通身，德用不孤道正親。',32,'全唐诗/poet.song.175000.json','["雲形水意擁通身，德用不孤道正親。", "年少風流猶一段，花棚鋪錦蝶飛頻。"]'),
('804b560e-e210-4315-81e4-1cb3fb0a4760','偈頌十六首  其一二','釋如淨','宋','宋诗','song-poetry','','[]','心田法地有靈苗，不動金鋤耕步休。',32,'全唐诗/poet.song.175000.json','["心田法地有靈苗，不動金鋤耕步休。", "何事長松脩竹下，風師雨客逐春秋。"]'),
('5d1cf7c9-aec2-4ac8-8326-6895c1089148','偈頌十六首  其一三','釋如淨','宋','宋诗','song-poetry','','[]','淨妙妙時解活計，露堂堂處有家風。',32,'全唐诗/poet.song.175000.json','["淨妙妙時解活計，露堂堂處有家風。", "須知脫體卓然道，廓落圓通是箇宗。"]'),
('9bf69a29-d504-40cb-a7d8-811b54c406b2','偈頌十六首  其一四','釋如淨','宋','宋诗','song-poetry','','[]','如何是四稜蹈地，入三摩存分別智。',32,'全唐诗/poet.song.175000.json','["如何是四稜蹈地，入三摩存分別智。", "若是有事而不通，知未知伊彼元氣。"]'),
('8dd03ebc-e099-4523-ad88-25b166deb042','偈頌十六首  其一五','釋如淨','宋','宋诗','song-poetry','','[]','到純無學處，語路若何生。',24,'全唐诗/poet.song.175000.json','["到純無學處，語路若何生。", "意氣天然別，神筆畫不成。"]'),
('f7de7bdc-8ccc-49ad-a9b5-09bcfdbeff9b','偈頌十六首  其一六','釋如淨','宋','宋诗','song-poetry','','[]','一粒曾生無相田，異苗繁茂試機先。',32,'全唐诗/poet.song.175000.json','["一粒曾生無相田，異苗繁茂試機先。", "莊嚴劫佛借他力，雙樹蔭凉本自然。"]'),
('2e62598a-3685-48a8-91d7-de9118d27ef4','頌古五首  其一','釋如淨','宋','宋诗','song-poetry','','[]','無憂樹下浴嬰孩，清曉薔薇带露開。',32,'全唐诗/poet.song.175000.json','["無憂樹下浴嬰孩，清曉薔薇带露開。", "轉過衲僧相見處，後槽馿馬出胞胎。"]'),
('afa099ec-ec3e-483c-9330-12faaf3d7065','頌古五首  其二','釋如淨','宋','宋诗','song-poetry','','[]','六年落草野狐精，跳出渾身是葛藤。',32,'全唐诗/poet.song.175000.json','["六年落草野狐精，跳出渾身是葛藤。", "打失眼睛無處覓，誑人剛道悟明星。"]'),
('24a2639d-0c1a-43dd-be9a-b71dc16d946b','頌古五首  其三','釋如淨','宋','宋诗','song-poetry','','[]','金烏飛上玉闌干，黑漆崑崙對面看。',32,'全唐诗/poet.song.175000.json','["金烏飛上玉闌干，黑漆崑崙對面看。", "畢竟這些傳不得，落花流水太無端。"]'),
('40b9c3ab-9a1f-4dde-818f-025ee60e413f','頌古五首  其四','釋如淨','宋','宋诗','song-poetry','','[]','一橈劈口虛空破，三點馿頭覆却船。',32,'全唐诗/poet.song.175000.json','["一橈劈口虛空破，三點馿頭覆却船。", "父子至今俱不了，江湖波浪錯流傳。"]'),
('5653df8f-cb55-4a07-8ea0-7f8178fe8187','頌古五首  其五','釋如淨','宋','宋诗','song-poetry','','[]','衲衣下事火燒山，臘月家貧徹骨寒。',32,'全唐诗/poet.song.175000.json','["衲衣下事火燒山，臘月家貧徹骨寒。", "堪笑連延曾未息，眉毛焦赤面皮乾。"]'),
('761b05be-6d4e-40e0-99e6-9fff10261072','春晝','韓淲','宋','宋诗','song-poetry','','[]','青春白晝永，一日如兩日。',48,'全唐诗/poet.song.175000.json','["青春白晝永，一日如兩日。", "平心得淑景，佳思入詩律。", "湖山氣姿媚，海汐聲蕩潏。", "迴旋且迴旋，楊花滿書室。"]'),
('a9876e28-05b8-4645-808b-b77e0d143a80','春陰','韓淲','宋','宋诗','song-poetry','','[]','春雨發山溜，花事回綠陰。',48,'全唐诗/poet.song.175000.json','["春雨發山溜，花事回綠陰。", "東家舉杯酒，爲我成芳斟。", "蝶遶鶑流音，輕雲晚沉沉。", "揮手惜素心，入林驚未深。"]'),
('646f47e6-aaea-48e8-a120-8d6504496732','苦陰','韓淲','宋','宋诗','song-poetry','','[]','梅熟麥秀時，濃陰多轉晴。',48,'全唐诗/poet.song.175000.json','["梅熟麥秀時，濃陰多轉晴。", "礎潤雷掣電，溝壑須臾平。", "清風四起處，鬰蒸或不輕。", "今茲冷氣深，經旬壓簷聲。"]'),
('dc478251-12a8-477c-9ed8-23a71e5efdaf','正月二十七日','韓淲','宋','宋诗','song-poetry','','[]','晨興啟蓬門，綠樹有啼鶑。',48,'全唐诗/poet.song.175000.json','["晨興啟蓬門，綠樹有啼鶑。", "山風遠遠來，墟煙低低橫。", "水寫蔽芾影，岸束湍瀨聲。", "春事曾幾何，孤花尚含情。"]'),
('b1939ddd-33b6-412d-8f81-4833d1d75030','春晚','韓淲','宋','宋诗','song-poetry','','[]','餘靄淨麥岐，流暉轉蘭臯。',48,'全唐诗/poet.song.175000.json','["餘靄淨麥岐，流暉轉蘭臯。", "燕壘落梁塵，漁舠激碕濤。", "芳斟競飛斝，綺思歸摇毫。", "良燕氣清和，物色如春韶。"]'),
('2064c6d1-0b89-4abf-b65c-0b9bcde6a774','春分前一日  其一','韓淲','宋','宋诗','song-poetry','','[]','沉沉聽雨坐，瓶花養香梅。',48,'全唐诗/poet.song.175000.json','["沉沉聽雨坐，瓶花養香梅。", "鼻觀得此供，息定本氣回。", "春陽已大壯，陰雲尚難開。", "小窗千葉黄，眼塵一清哉。"]'),
('b7b7b54c-efd5-47f0-904b-038320e9db18','春分前一日  其二','韓淲','宋','宋诗','song-poetry','','[]','青青葉中蘭，庭幽有餘芳。',48,'全唐诗/poet.song.175000.json','["青青葉中蘭，庭幽有餘芳。", "新葩明輕莖，知我春晝長。", "安得滋九畹，命騷與爭光。", "風泛不須紉，深林宜永藏。"]'),
('b0ab884e-69de-4a21-a1c4-2b672bd5341b','春分前一日  其三','韓淲','宋','宋诗','song-poetry','','[]','細雨桃樹枝，依流欲舒紅。',48,'全唐诗/poet.song.175000.json','["細雨桃樹枝，依流欲舒紅。", "水深相發揮，倍覺多春工。", "從渠武陵源，不與人跡通。", "馮生天地間，我汝俱樊籠。"]'),
('e7a7abc0-3fc6-4544-9d43-e9a445f6009e','春分前一日  其四','韓淲','宋','宋诗','song-poetry','','[]','柳已綠可愛，溪風更摇之。',48,'全唐诗/poet.song.175000.json','["柳已綠可愛，溪風更摇之。", "人居春氣中，安知物熙熙。", "常年二三月，醉眼不自持。", "摩挲此瞢騰，老去今其時。"]'),
('08a67090-f7a2-4595-ab05-6f44dd0a3164','春分前一日  其五','韓淲','宋','宋诗','song-poetry','','[]','草色老春薺，氣數戚已分。',48,'全唐诗/poet.song.175000.json','["草色老春薺，氣數戚已分。", "流光生鬢絲，日暮江東雲。", "故交本不多，零落那忍聞。", "牆陰雨凄凄，夕陽何時熏。"]'),
('76d92c5c-5be1-4e63-9192-6a2a3a148f7d','避暑','韓淲','宋','宋诗','song-poetry','','[]','亭午暑未凉，竹陰訪泉石。',48,'全唐诗/poet.song.175000.json','["亭午暑未凉，竹陰訪泉石。", "泉源徹底清，石色半痕碧。", "幽處鳥聲流，閑中人意適。", "風微一幅巾，林深轉虛寂。"]'),
('709c00c1-f603-42cc-b8e4-940440ac17e2','秋意','韓淲','宋','宋诗','song-poetry','','[]','秋意不堪老，宦情惟自悲。',48,'全唐诗/poet.song.175000.json','["秋意不堪老，宦情惟自悲。", "蕭蕭風雨中，吟哦漫尋詩。", "古來騷雅士，常恐歸計遲。", "此事不難辦，無語王謝兒。"]'),
('009914af-be60-4b4a-a504-6313d9a33505','二十九日寒食','韓淲','宋','宋诗','song-poetry','','[]','花間雨未乾，强飲食猶寒。',48,'全唐诗/poet.song.175000.json','["花間雨未乾，强飲食猶寒。", "山澗得名流，豈曰俗相看。", "晉文綿上田，往事今鼻酸。", "江南好風景，且取文酒懽。"]'),
('959247b9-0bf3-4970-a2c0-b2cfb0632bd2','清明','韓淲','宋','宋诗','song-poetry','','[]','既喜寒食晴，復值清明雨。',72,'全唐诗/poet.song.175000.json','["既喜寒食晴，復值清明雨。", "山空洗雨花，零落蔽泥土。", "脩林發新葉，青綠粲莫數。", "雖云風日異，景物俱可覩。", "犂鉏動遠村，愈覺愛農圃。", "形跡欣得閑，持醪醉爲主。"]'),
('1a83ddc6-301d-477f-9a63-4bd0a3e6e40a','上饒禊飲','韓淲','宋','宋诗','song-poetry','','[]','流芳報花信，暢敘記東晉。',36,'全唐诗/poet.song.175000.json','["流芳報花信，暢敘記東晉。", "何知胸崔嵬，未覺景急峻。", "泛觴河陽春，庶且雅俗鎮。"]'),
('b2560a74-22e2-40bd-a66a-ec2b51da0800','九日錢塘江','韓淲','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','九日風凄緊，扁舟發龕山。',48,'全唐诗/poet.song.175000.json','["九日風凄緊，扁舟發龕山。", "龕山正自佳，況復江水間。", "吳歌動兩槳，泝洄過滄灣。", "雖無菊可把，矯首雲斑斑。"]'),
('9bac3cb1-da6b-411e-a588-1dc1a18d5e9b','九日次前韵答賦德久','韓淲','宋','宋诗','song-poetry','','[]','客裏素秋節，誰復同襟期。',120,'全唐诗/poet.song.175000.json','["客裏素秋節，誰復同襟期。", "黄花雖滿眼，何意采摘之。", "古今曠達人，把此顔爲怡。", "謂可制頹齡，屬興深于茲。", "淵明南山下，放浪東籬枝。", "白衣縱莫至，自惜草木姿。", "斯辰天陰陰，雲深翳晴曦。", "更想杜陵老，抱病登臺時。", "我欲事嘯歌，舒憂以娛悲。", "悠悠時序心，摇毫漫致詞。"]'),
('a3ebfd26-c644-437b-ba2d-b9278d9681c1','九日次陶韵','韓淲','宋','宋诗','song-poetry','','[]','草木易黄落，倏然時序交。',96,'全唐诗/poet.song.175000.json','["草木易黄落，倏然時序交。", "豈無素心人，松柏不改凋。", "今日我重九，惘然風度高。", "起尋得良覿，南鴈將橫霄。", "夸毗信誰子，短世亦已勞。", "旱暵乃天運，惔焚禾穀焦。", "一歌百世蘇，重歌千載陶。", "唱予而和汝，其雨復崇朝。"]'),
('85d65fa7-3640-4ed0-be90-a244e5b3a337','九日  其一','韓淲','宋','宋诗','song-poetry','','[]','悠悠兩高峰，眇眇見落木。',84,'全唐诗/poet.song.175000.json','["悠悠兩高峰，眇眇見落木。", "病餘老身倦，登樓謾伸蹜。", "茲晨有何味，酒面欲汎菊。", "常年得重九，高興必徵逐。", "誰知嬾出門，搔髮鬢已禿。", "子雲雖識字，君平唯賣卜。", "坐久風頗怒，新霜夜來肅。"]'),
('b67077f1-4b76-42d7-8993-2137db1de7a2','九日  其二','韓淲','宋','宋诗','song-poetry','','[]','野色荒荒白，嵐光隠隠青。',48,'全唐诗/poet.song.176000.json','["野色荒荒白，嵐光隠隠青。", "家鄉未千里，客路復長亭。", "絕景詩難狀，多愁酒易醒。", "西風攪黄葉，興寄託鴻冥。"]'),
('de482570-6c99-414e-bf46-be0268c03ba2','除夕前兩日示秉','韓淲','宋','宋诗','song-poetry','','[]','雪風吹溪雲，晝刻催歲律。',108,'全唐诗/poet.song.176000.json','["雪風吹溪雲，晝刻催歲律。", "歡傳頌椒花，餞歲欲何出。", "舉頭荒山廬，冰澗溜凄瑟。", "兩鬢已顛童，種種不滿櫛。", "題輿得斯文，愛士欲黼黻。", "團呼一樽酒，清言了人物。", "四座各盡情，燭跋屢剪拂。", "如愚於席間，踸踔倍勃窣。", "授簡而供令，古興亦豈不。"]'),
('932c42d1-afde-4d0f-a3b7-e8126ab0a9c5','二十五日','韓淲','宋','宋诗','song-poetry','','[]','焚香得深居，清風養幽抱。',48,'全唐诗/poet.song.176000.json','["焚香得深居，清風養幽抱。", "杜鵑來何遲，鴻鴈去常早。", "微瀾響溝流，積潤滑磴道。", "綿綿百草長，春風雨中老。"]'),
('02a0f216-1a14-402f-9be0-af94f6db7774','三月八日  其一','韓淲','宋','宋诗','song-poetry','','[]','晝閑春婉婉，草樹轉花事。',84,'全唐诗/poet.song.176000.json','["晝閑春婉婉，草樹轉花事。", "人誰用吾情，我自順吾意。", "江山不徒吟，城郭亦可醉。", "陰陰起晴風，相賞豈云易。", "方齋既虛清，山堂亦深翠。", "來燕翩翩歸，啼鵑眇眇至。", "時物付芳華，所惜者風誼。"]'),
('96937f0c-9b35-4841-bc9c-4186ff29f796','三月八日  其二','韓淲','宋','宋诗','song-poetry','','[]','春濃自徘徊，我歌亦其事。',84,'全唐诗/poet.song.176000.json','["春濃自徘徊，我歌亦其事。", "崢嶸眼中人，磊磈言外意。", "何哉非達也，拂石醒小醉。", "棋枰隨圓方，目擊勝敗易。", "冷齋芹泮地，坐久濕空翠。", "了無官曹塵，所以野老至。", "汎乎不繫舟，未數長沙誼。"]'),
('f472ee58-25ba-4a93-8f02-df7598299e91','三月八日  其三','韓淲','宋','宋诗','song-poetry','','[]','所貴知者希，初不與人事。',84,'全唐诗/poet.song.176000.json','["所貴知者希，初不與人事。", "飄風擊墜瓦，彼豈有本意。", "百爾我所思，豈必待熟醉。", "烈士徒殉名，歸潔似圖易。", "鱣鯨困螻螘，蘭苕巢翡翠。", "廣心之昭融，巽語之極至。", "何若於燕閒，相與談仁誼。"]'),
('1c9e8709-d16e-4b5f-922c-aba509c2847c','初九日','韓淲','宋','宋诗','song-poetry','','[]','山空草木長，明日欲立夏。',60,'全唐诗/poet.song.176000.json','["山空草木長，明日欲立夏。", "俄頃一蟬鳴，節物便相亞。", "平心閲四時，益覺運而化。", "殘杯了清晝，新香度深夜。", "風雨陰陽間，悠悠嬾悲咤。"]'),
('d70d0f8c-edea-45d1-a011-0700e72370bd','十月初十日','韓淲','宋','宋诗','song-poetry','','[]','南窗午逾暖，日氣烘人衣。',48,'全唐诗/poet.song.176000.json','["南窗午逾暖，日氣烘人衣。", "徒有蒼蠅聲，甚無鴻雁飛。", "老身漫自伸，老眼其疇依。", "摩挲根塵間，瓦溝霜已晞。"]'),
('8e43af1f-ac5a-4f0d-b0be-2ff1cb3473f8','晦日即事示同遊','韓淲','宋','宋诗','song-poetry','','[]','閒居誰與娛，寂歷滿黄葉。',240,'全唐诗/poet.song.176000.json','["閒居誰與娛，寂歷滿黄葉。", "冬晴日氣午，乘暖得步屧。", "兒僕爲遊園，俛仰纔自愜。", "親朋忽過我，少坐情意浹。", "烹茶味既爽，穿林景逾接。", "縱遊星居寺，僧房頗稠疊。", "隨流覺路熟，更見沙觜涉。", "道院出香鼎，春山弄書篋。", "留連一兩杯，設飯羹用筴。", "亭虛列峰巒，溪淨映城堞。", "躋攀重閣晚，覽句費目睫。", "歸歟語河梁，分手興未帖。", "吾衰子俱壯，歲莫何術業。", "從來評道德，亦必在耕獵。", "好惡空紛拏，利害漫懾怯。", "郡國有惠養，朝家有調燮。", "孫臏爲斷足，范雎至折脅。", "尚能變軒昂，未信祇萎苶。", "莊知冥靈春，佛說惡濁劫。", "無視霧氣蒸，飛鳶墮跕跕。"]'),
('90695fed-4b4f-42d5-8217-7d2413ea17c6','十二月二十八日','韓淲','宋','宋诗','song-poetry','','[]','寂寂園中林，脈脈林下泉。',120,'全唐诗/poet.song.176000.json','["寂寂園中林，脈脈林下泉。", "蕭閑歲云暮，老身欲何言。", "不畏日月駛，但笑霜雪繁。", "人生本非惡，往往迷宿愆。", "昏明夜復旦，寒雲滿空山。", "瓶儲粟粒罄，交舊無往還。", "塵埃豈不知，冠緌易牽纏。", "五鼎食與烹，寸景能幾年。", "心境互生滅，雅俗相移遷。", "危坐明檠燈，爐香更清然。"]'),
('5a9c9535-9183-4b9d-bc1c-e9e0df6df1bb','日長','韓淲','宋','宋诗','song-poetry','','[]','日長林影聚，早暮氣彌清。',48,'全唐诗/poet.song.176000.json','["日長林影聚，早暮氣彌清。", "既自罕人跡，而猶聞市聲。", "物生各有態，境異俱忘情。", "門前酒誰來，吾其撞餘醒。"]'),
('a6dc0394-c161-447d-8874-cc00b59b13fa','落日','韓淲','宋','宋诗','song-poetry','','[]','落日青松間，疎明山翠寒。',48,'全唐诗/poet.song.176000.json','["落日青松間，疎明山翠寒。", "誰於元氣中，弄此赤玉丸。", "我心本清陽，陰濁不可干。", "虞淵下可取，快飲盃勿乾。"]'),
('6ca0b7ea-d975-4ebd-977e-9de581135ffe','喜晴','韓淲','宋','宋诗','song-poetry','','[]','積日困秋雨，曉起天開明。',72,'全唐诗/poet.song.176000.json','["積日困秋雨，曉起天開明。", "披軒納晴光，樹影當階橫。", "遥聞玄蟬急，忽見翠羽輕。", "整衣聚足坐，似覺天籟清。", "身形百年爾，衣食苦强營。", "運化有理道，超然得此生。"]'),
('79211eb4-7b11-4cce-9582-b9fd1ed64fee','晚晴','韓淲','宋','宋诗','song-poetry','','[]','兩年元日陰，今年元日晴。',48,'全唐诗/poet.song.176000.json','["兩年元日陰，今年元日晴。", "微霜起清寒，人物多歡聲。", "行都占江海，魚鹽易經營。", "何時復三京，萬世開太平。"]'),
('1b4ea8db-0bd8-426b-b0c3-1fd64d7bad94','掩關月色滿窗宴坐久之','韓淲','宋','宋诗','song-poetry','','[]','雲窗月當午，小醉人未眠。',48,'全唐诗/poet.song.176000.json','["雲窗月當午，小醉人未眠。", "兒童鼻鼾雷，聽息方綿綿。", "萬籟一以虛，性地開其天。", "入林山自深，金澗通瑶泉。"]'),
('6468e16f-0cd6-4bed-8a82-39c0c714bf5c','對月','韓淲','宋','宋诗','song-poetry','','[]','璇霄蕩凉颸，靜夜却團扇。',36,'全唐诗/poet.song.176000.json','["璇霄蕩凉颸，靜夜却團扇。", "幽人醉未醒，月色窗戶轉。", "起舞步高寒，借我蟾宮便。"]'),
('c0569e53-5b00-42b0-81d0-df32b01a4c46','十六夜看月','韓淲','宋','宋诗','song-poetry','','[]','夜久羣動息，巡簷尚何觀。',60,'全唐诗/poet.song.176000.json','["夜久羣動息，巡簷尚何觀。", "庭空葉忽墜，琤若摧琅玕。", "芒寒星彩動，霜氣尤瀰漫。", "誰知太虛中，運此寶月團。", "須臾一雁叫，飛下溪流灘。"]'),
('6971640c-43cf-4e50-8d09-14a8e246c938','月過林端清甚','韓淲','宋','宋诗','song-poetry','','[]','月出雙樹間，營魄何流光。',48,'全唐诗/poet.song.176000.json','["月出雙樹間，營魄何流光。", "初弦還當午，凈極涵莽蒼。", "溪虛響城角，露重天欲霜。", "送客出籬門，共立古道長。"]'),
('ff7da185-d73a-4513-ac0f-51cac34b509d','玉溪樓看月','韓淲','宋','宋诗','song-poetry','','[]','山晴夜自明，草樹遥可矚。',48,'全唐诗/poet.song.176000.json','["山晴夜自明，草樹遥可矚。", "樓頭春已非，尚有月如玉。", "胡爲乎來哉，可謂萬事足。", "溝流雜蛙黽，信閲人代速。"]'),
('cf66b8fc-667c-4e66-92db-0b4eb3d83998','夏夜翫月','韓淲','宋','宋诗','song-poetry','','[]','夜氣生微凉，山空步明月。',48,'全唐诗/poet.song.176000.json','["夜氣生微凉，山空步明月。", "飛光入人家，流影到林樾。", "零零白露滴，冉冉清思發。", "乘雲度罡風，天上有宮闕。"]'),
('54de8c77-092f-419b-90f1-f7967dfa0d19','方齋啟窗見月','韓淲','宋','宋诗','song-poetry','','[]','我豈不解飲，風軒乘月開。',48,'全唐诗/poet.song.176000.json','["我豈不解飲，風軒乘月開。", "細細春酌動，徐徐秋興來。", "俄而弄清影，自爾却氛埃。", "誰信城市居，野老爲裴回。"]'),
('d2b9a30d-d323-4ae5-b76e-9077d3173ea8','中夜危坐雨聲清甚','韓淲','宋','宋诗','song-poetry','','[]','倦卧一榻上，展轉不能寐。',48,'全唐诗/poet.song.176000.json','["倦卧一榻上，展轉不能寐。", "更聽蟋蟀吟，時時風雨至。", "披衣起趺坐，數息存妙寄。", "其生何用觀，夜氣吾已志。"]'),
('3c618c6f-908e-4e8a-accb-c0bbfa1fdbbd','八月初七日終夜大雷震雨如傾注風敗吾藩籬拔吾庭樹','韓淲','宋','宋诗','song-poetry','','[]','晴明天氣佳，草木浮光煇。',180,'全唐诗/poet.song.176000.json','["晴明天氣佳，草木浮光煇。", "珍禽各翔語，羣花競芳菲。", "人情春和時，怡遊類忘歸。", "常陽一以亢，旱甚翻歔欷。", "赤地至千里，焉有不年饑。", "家家望雲霓，想像陰雨霏。", "狂飈震雷吼，連夕恐非機。", "溪漲橋已解，拍岸欲平磯。", "所幸蛙黽爾，跳噪皆輕肥。", "居民其奈何，泥淖生理微。", "意欲問彼蒼，何日生清暉。", "由來此陰陽，歲事中和希。", "今年積秋熱，焦熬在郊圻。", "既雨復苦風，拔樹敗牆圍。", "后土無乾處，眇予將疇依。"]'),
('fa4842d2-4b85-4c76-af69-ef02cc4c26c6','雨後驟冷凄然','韓淲','宋','宋诗','song-poetry','','[]','天高氣蕭瑟，薄薄寒中人。',48,'全唐诗/poet.song.176000.json','["天高氣蕭瑟，薄薄寒中人。", "登山兮臨水，貧士志不平。", "惆悵徒自憐，羈旅誰友生。", "申旦耿不寐，淹留可無成。"]'),
('949b3b08-3ab0-4f75-bd38-e1a3c669c36a','梅雨','韓淲','宋','宋诗','song-poetry','','[]','山溪遶寒城，林園眇荒隅。',96,'全唐诗/poet.song.176000.json','["山溪遶寒城，林園眇荒隅。", "南枝小春梅，意似醉眼舒。", "雲陰冒霏霏，欲步雨如塗。", "人閒壓芳槽，洗酌留我娛。", "易齋誦銘語，耆英幾年無。", "吾儕老孫子，交契歲月徂。", "速飲付丘壑，微吟對江湖。", "何當暗香底，花影相持扶。"]'),
('ae412479-7907-4027-a43c-5c2bbda23930','微雨','韓淲','宋','宋诗','song-poetry','','[]','雲間度微雨，霑灑草木淨。',48,'全唐诗/poet.song.176000.json','["雲間度微雨，霑灑草木淨。", "披衣未盥櫛，失却體中病。", "屋角鳩鳴陰，是亦彼情性。", "今我睡既醒，豈不有孤詠。"]'),
('e5739a2c-853e-474d-bc35-b395900a3b56','夜雨','韓淲','宋','宋诗','song-poetry','','[]','卧聽空山雨，愁人春夜長。',84,'全唐诗/poet.song.176000.json','["卧聽空山雨，愁人春夜長。", "田蛙與水鳴，聒聒來耳旁。", "緬懷千載遥，賢達多遯藏。", "豈無命世才，所抱或沮傷。", "離家脫塵役，且憇雲水鄉。", "時運不我留，老去空彷徨。", "但恐壯志銷，放浪宜自彊。"]'),
('de7091ed-2b68-4ce9-a38d-4983efb2c233','午窗驟雨','韓淲','宋','宋诗','song-poetry','','[]','日暖石礎潤，雷雨響空山。',48,'全唐诗/poet.song.176000.json','["日暖石礎潤，雷雨響空山。", "草木盡披霏，雲氣滿窗間。", "我方岸幘坐，與客談笑間。", "會當乘少霽，午陰聽潺湲。"]'),
('39878e39-4a03-4dc0-846a-e37cf9ede292','急雨','韓淲','宋','宋诗','song-poetry','','[]','淫淫夏暑雨，小民惟曰怨。',48,'全唐诗/poet.song.176000.json','["淫淫夏暑雨，小民惟曰怨。", "連朝浸田塍，一夜倒河堰。", "尋常已食麥，積久況少飯。", "錢幣易低昂，亦合利商販。"]'),
('f8895cb8-83ba-41e4-a0bb-145690fc17a1','阻雨','韓淲','宋','宋诗','song-poetry','','[]','獨坐空堂上，憂來與誰語。',60,'全唐诗/poet.song.176000.json','["獨坐空堂上，憂來與誰語。", "出門欲遠遊，泥雨復艱阻。", "不見一人來，那逢會心侶。", "前除一幽禽，四壁響饑鼠。", "無以滌睡昏，春茶尚可煮。"]'),
('98d62dfc-038d-4c4e-b1db-c329ce250450','自清明後十日雨','韓淲','宋','宋诗','song-poetry','','[]','得雨宜秧田，久雨損麥隴。',72,'全唐诗/poet.song.176000.json','["得雨宜秧田，久雨損麥隴。", "日暖可成實，天寒妨出種。", "米麵世所資，敢爲一身奉。", "望眼冀晴色，深爲農夫恐。", "長林風颼颼，狹港水洶洶。", "閑謠不能歡，名與食孰重。"]'),
('d22fd740-8a31-4286-90d5-8c67cc738823','雨中作','韓淲','宋','宋诗','song-poetry','','[]','閔雨澗將涸，爲霖流復湍。',48,'全唐诗/poet.song.176000.json','["閔雨澗將涸，爲霖流復湍。", "聲來白浩浩，氣起清漫漫。", "隨山問本源，踏地觀狂瀾。", "隔水城市塵，了然不相干。"]'),
('27ee3845-a4a7-4d62-811c-cfaf606c6efe','初三日雨','韓淲','宋','宋诗','song-poetry','','[]','一林梅花雨，香濕煙冥濛。',48,'全唐诗/poet.song.176000.json','["一林梅花雨，香濕煙冥濛。", "水流澗底清，聲落前溪中。", "鳥飛既整暇，人意亦沖融。", "今歲春來早，新萱已滿叢。"]'),
('cbcb7072-5421-4be8-a089-d8dd153d0ba1','雨中','韓淲','宋','宋诗','song-poetry','','[]','山林得凉雨，倍覺十分秋。',48,'全唐诗/poet.song.176000.json','["山林得凉雨，倍覺十分秋。", "衡門籬落間，木槿上牽牛。", "霏微弄空明，炊煙澹飛浮。", "有酒不肯飲，南冠真楚囚。"]'),
('0e59a76b-8575-4405-9031-4594999699d9','夏雨','韓淲','宋','宋诗','song-poetry','','[]','已忻五月凉，連得六月雨。',60,'全唐诗/poet.song.176000.json','["已忻五月凉，連得六月雨。", "泉石養芝朮，甽澮長禾黍。", "病雖未能飲，起亦尚可句。", "凌晨百鳥啼，靜夜百蟲語。", "寺外鐘磬音，樵歌自來去。"]'),
('f5547968-4dc0-4c94-9bd3-7c8ba7d44bd0','陰雨','韓淲','宋','宋诗','song-poetry','','[]','變風忽交作，雨脚窗紙鳴。',48,'全唐诗/poet.song.176000.json','["變風忽交作，雨脚窗紙鳴。", "隘巷掩關坐，爐深沸瓶笙。", "豈不念故山，斗升聊自營。", "米貴薪炭少，天亦放我晴。"]'),
('01b4dedc-7821-4285-a7e4-df69bb619e7f','夜霜窗戶肅然嚴冷','韓淲','宋','宋诗','song-poetry','','[]','行都鎮東南，衣冠萃軒盖。',72,'全唐诗/poet.song.176000.json','["行都鎮東南，衣冠萃軒盖。", "文書漫穰穰，人物當藹藹。", "癡或不知止，隘即莫可奈。", "江山何清空，天地本正大。", "四更霜氣重，肅若起深籟。", "乃信埃𡏖中，此景終不害。"]'),
('643af4a3-d359-48ef-a75c-3dc174d7e241','雨後','韓淲','宋','宋诗','song-poetry','','[]','夜煖雨驟至，溝流起微湍。',48,'全唐诗/poet.song.176000.json','["夜煖雨驟至，溝流起微湍。", "一秋多苦晴，魚蝦生意艱。", "朝來清蛙鳴，便覺斗水寬。", "豈不念其涸，跳梁聊自歡。"]'),
('1c226ffd-13c5-4055-985a-b7c87c32a759','凉雨','韓淲','宋','宋诗','song-poetry','','[]','凉雨濯袢暑，中林動清觴。',48,'全唐诗/poet.song.176000.json','["凉雨濯袢暑，中林動清觴。", "一日亦易與，千古不可忘。", "人物信消長，治運空微昌。", "我有插架書，醉甚無慨慷。"]'),
('6dabdfe5-9385-4266-acce-40a6fc984943','社雨  其一','韓淲','宋','宋诗','song-poetry','','[]','空山水流澗，社雨掩籬門。',48,'全唐诗/poet.song.176000.json','["空山水流澗，社雨掩籬門。", "雲陰起微寒，藥爐自常溫。", "老懶一欠伸，開卷窗明昏。", "屋邊桃李蹊，飛飛亦無言。"]'),
('ad10e3f1-b81e-433f-adb1-c50c818b2c46','社雨  其二','韓淲','宋','宋诗','song-poetry','','[]','開簾卷書坐，燕聲煙雨中。',48,'全唐诗/poet.song.176000.json','["開簾卷書坐，燕聲煙雨中。", "時物依辰至，春社古所同。", "豈不知其然，歲月何匆匆。", "擁襟一閑謠，林花落簷風。"]'),
('b827748d-3fe1-430d-84ea-4c8bb1d19283','梅雪','韓淲','宋','宋诗','song-poetry','','[]','殘冬且論詩，豈待梅與雪。',48,'全唐诗/poet.song.176000.json','["殘冬且論詩，豈待梅與雪。", "雪固以水清，梅自惟花潔。", "玄機未易窺，聖解不難說。", "棄置便掃除，俗者慮上拙。"]'),
('16ba7ac7-f80f-4670-9e08-0510ba7a536b','松雪','韓淲','宋','宋诗','song-poetry','','[]','松雪照殘臘，溝流起輕冰。',48,'全唐诗/poet.song.176000.json','["松雪照殘臘，溝流起輕冰。", "倦身固蹣跚，睡眼猶瞢騰。", "塵埃與野馬，何急來相仍。", "東隣可以飲，一舉宜數升。"]'),
('a848dee7-6405-4155-bfc8-4f9433d57402','雪','韓淲','宋','宋诗','song-poetry','','[]','我枕麴藉糟，女爲彼玉雪。',36,'全唐诗/poet.song.176000.json','["我枕麴藉糟，女爲彼玉雪。", "驚心京索舊，流徙此越絕。", "霏霏醉飛花，堂上燭勿滅。"]'),
('7b6dd1e6-a0f0-45ff-a2f2-ffdd4acaa78d','積雪','韓淲','宋','宋诗','song-poetry','','[]','積雪有何好，照我窗牖明。',48,'全唐诗/poet.song.176000.json','["積雪有何好，照我窗牖明。", "窗明不能寐，披衣數寒更。", "带雨豈滅蹤，無風如有聲。", "荒荒山野人，渺渺江海情。"]'),
('a4e4cb8b-833d-4f49-b2f1-164ac785c8ab','坐想孤山雪竹壓籬礙過之勝','韓淲','宋','宋诗','song-poetry','','[]','詩亦常語爾，細思有何情。',48,'全唐诗/poet.song.176000.json','["詩亦常語爾，細思有何情。", "瞀瞀青眼收，種種白髮生。", "不如緘口住，時復信脚行。", "折竹松邊路，孤山籬雪清。"]'),
('9031c7c4-a39a-43e4-9b8d-b7b4fa8b6ee7','回路雪作野酤','韓淲','宋','宋诗','song-poetry','','[]','適俗心不夷，索隠山不深。',48,'全唐诗/poet.song.176000.json','["適俗心不夷，索隠山不深。", "駕言出春浦，回車已留陰。", "雪飛催我句，村酤且重斟。", "此致天所資，優哉有遺音。"]'),
('874f9062-7354-46c9-a1f9-84ab60f40f91','雪中  其一','韓淲','宋','宋诗','song-poetry','','[]','雪映山窗白，竹爐殘葉灰。',48,'全唐诗/poet.song.176000.json','["雪映山窗白，竹爐殘葉灰。", "寒垂紙帳低，起坐百念催。", "推枕理吾夢，栩栩鼻如雷。", "覺來神氣中，平旦陽明開。"]'),
('14fa7d14-971b-42f8-896f-78afc62f175a','雪中  其二','韓淲','宋','宋诗','song-poetry','','[]','淨業與穢業，交戰則我微。',48,'全唐诗/poet.song.176000.json','["淨業與穢業，交戰則我微。", "未能滌玄覽，前識相依違。", "玄冬霜後雪，磵谷慵啟扉。", "天耶其人耶，咸言上上機。"]'),
('9e836fcc-39e8-4c5c-a277-b599dba756f0','雪中  其三','韓淲','宋','宋诗','song-poetry','','[]','今年已有雪，今年亦有梅。',48,'全唐诗/poet.song.176000.json','["今年已有雪，今年亦有梅。", "梅花與雪片，日夕相徘徊。", "失喜固莫爾，亡憂尚何哉。", "不與萬法侶，孔跖俱塵埃。"]'),
('54b862be-0f98-481f-a361-a72b6bafab53','雪中  其四','韓淲','宋','宋诗','song-poetry','','[]','涇渭本一水，濁清我何尤。',48,'全唐诗/poet.song.176000.json','["涇渭本一水，濁清我何尤。", "白雪固爲潔，老興開兩眸。", "須臾冥心坐，薪火時添抽。", "咄哉皆前塵，禿髮不滿頭。"]'),
('a3e2a948-973c-4ca0-8263-225a69ffa2b1','雪中  其五','韓淲','宋','宋诗','song-poetry','','[]','鳥聲已鳴春，磵廬雪色深。',48,'全唐诗/poet.song.176000.json','["鳥聲已鳴春，磵廬雪色深。", "紛綸五經笥，古人云鉥心。", "心本理和順，萬緣常逼侵。", "莫作斷滅相，明明去來今。"]'),
('2f91e49b-60e5-42a7-aef2-657b0fa6fca1','趙十有詩及高泉之行因思往年同遊青巖','韓淲','宋','宋诗','song-poetry','','[]','秋花滿青巖，禪榻如昨日。',144,'全唐诗/poet.song.176000.json','["秋花滿青巖，禪榻如昨日。", "舉眼曾幾何，歲月流電疾。", "君其壯藻思，我已老蓬蓽。", "誰云彼高泉，春晚又能出。", "寺底讀葉碑，祠前看周筆。", "夷猶慨以慷，緬邈咤而叱。", "思君弟行役，應惜良會失。", "朋從淫液之，於我豈固必。", "旁觀徵逐間，往往誚遊逸。", "相望一樽酒，朱絃理青瑟。", "墜緒或可尋，陳迹安可詰。", "澒洞塵瞇人，榮名真蟣蝨。"]'),
('56c9eb4c-ba80-4fd7-b4ec-d669f88dcbea','八月二十五日過南豅  其一','韓淲','宋','宋诗','song-poetry','','[]','凉雨忽不止，秋陰無奈何。',48,'全唐诗/poet.song.176000.json','["凉雨忽不止，秋陰無奈何。", "山根瀉新漲，小立玩流波。", "會逢其適爾，紫芝有奇歌。", "惜此未深密，時見人遊過。"]'),
('8844bd21-6e3d-4cc3-b747-6d671aa20a8d','八月二十五日過南豅  其二','韓淲','宋','宋诗','song-poetry','','[]','巖桂苦未花，尋香上扁舟。',48,'全唐诗/poet.song.176000.json','["巖桂苦未花，尋香上扁舟。", "溯洄得蹊間，微步理舊遊。", "鮮鮮見新枝，幽芳浩難收。", "回首城市塵，所憇因少留。"]'),
('ba468fb7-5d1f-4216-9af9-f30f9d73070b','八月二十五日過南豅  其三','韓淲','宋','宋诗','song-poetry','','[]','撫枕知夜永，淅淅過山雨。',48,'全唐诗/poet.song.176000.json','["撫枕知夜永，淅淅過山雨。", "淨聽秋氣還，清吟可無侶。", "年來幽興熟，心口自相語。", "我其內熱歟，何其未能處。"]'),
('0b86ae55-fab5-45be-baa7-815120628c72','題南豅','韓淲','宋','宋诗','song-poetry','','[]','南豅山下路，一眼煙雨昏。',48,'全唐诗/poet.song.176000.json','["南豅山下路，一眼煙雨昏。", "松篁葉滿地，楊柳條映門。", "此興非所難，吾道何由尊。", "鏗爾舍瑟希，带濕藏春痕。"]'),
('eab61dda-ba58-42cc-87f1-bac06ac0b3c8','遊南高峰下','韓淲','宋','宋诗','song-poetry','','[]','濛鴻山氣潤，噴薄澗水急。',60,'全唐诗/poet.song.176000.json','["濛鴻山氣潤，噴薄澗水急。", "殘花護新枝，春晚綠陰集。", "杖策一俛仰，挈榼共行立。", "路轉南高峰，窣堵正嶪岌。", "勝跡古今同，軒裳孰羈縶。"]'),
('1f092b43-2efa-4b3b-b37f-f8969094a37b','譚守約陳漕林宰同遊南巖得問字','韓淲','宋','宋诗','song-poetry','','[]','高情動巖壑，幽討忘遠近。',48,'全唐诗/poet.song.176000.json','["高情動巖壑，幽討忘遠近。", "追隨得秋日，挈榼多美醖。", "悠悠遠朝市，寂寂委時運。", "雨集星散間，他年或相問。"]'),
('dfc94cd4-ee84-4a89-9444-2fbd0fd1a992','霞山','韓淲','宋','宋诗','song-poetry','','[]','避喧甘猛虎，杜語誠有味。',156,'全唐诗/poet.song.176000.json','["避喧甘猛虎，杜語誠有味。", "況此古城遊，儘迥儘無畏。", "捫蘿魚貫登，犖确入荒蔚。", "俄而得峻極，天闕逼象緯。", "春風猶未旬，芳事已髣髴。", "憑虛了不寒，清淑滿腸胃。", "眼高物破碎，意廣身良貴。", "隘彼微塵歊，邑郭亦何謂。", "同來三二友，斯道久涇渭。", "偶然一尊携，物笑我頻喟。", "焉知酒行多，但覺飲之既。", "煙巒屏障環，秀潤仍蔽芾。", "更對西日紅，輪囷纏海氣。"]'),
('1f9c122b-7eb2-4a2d-8309-8dcadd863ff2','中平峰下巖可坐百客絕頂尤奇','韓淲','宋','宋诗','song-poetry','','[]','臨水既凝竚，望崖試徘徊。',96,'全唐诗/poet.song.176000.json','["臨水既凝竚，望崖試徘徊。", "榜舟一以渡，露晞嵐影開。", "矯首與人居，直上無飛埃。", "峭壁過鳥道，老樹相縈迴。", "下訪隠者廬，敗堵留巖隈。", "亂草蔽嵌空，停泉照崔嵬。", "因知勝絕地，使我心悠哉。", "誓當如龐老，舉家爲此來。"]'),
('6a1c1508-28da-46de-99a6-4fe54c7e857c','齋居湖寺晚對南屏疎鐘茂林霧氣蓊然','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南山起寒霧，雨氣蓊林木。',48,'全唐诗/poet.song.176000.json','["南山起寒霧，雨氣蓊林木。", "但覺白漫漫，不見山下屋。", "須臾逼昏黑，疎鐘度幽谷。", "寺冷西湖秋，齋房媚幽獨。"]'),
('d13b914b-3bab-4580-9b9f-4bcd4eb13463','步澗壑上山隠','韓淲','宋','宋诗','song-poetry','','[]','秋山響松竹，漠漠起雲陰。',48,'全唐诗/poet.song.176000.json','["秋山響松竹，漠漠起雲陰。", "褰裳過石瀨，望崖荒草深。", "誰家窗戶開，少寄閒澹心。", "茗醑無不可，所畏塵霧侵。"]'),
('b0729985-7b87-4b66-8c8a-11b973d00972','道場山山上有伏虎師宴坐巖寺中方池清深可愛','韓淲','宋','宋诗','song-poetry','','[]','翠麓轉危徑，清漣媚方池。',96,'全唐诗/poet.song.176000.json','["翠麓轉危徑，清漣媚方池。", "鐘魚鳴寶坊，窣堵高不危。", "憑軒眼力盡，晴色烟凄迷。", "秋原禾黍登，佳處端在茲。", "齋餘作茗事，晝寂香篆遲。", "當年伏虎師，此地嘗巖棲。", "高風動寥邈，勝跡窮險巇。", "回橈日已暮，悵望空自知。"]'),
('99fe88b3-fb3a-4bf0-adce-56b554638b94','茶山  其一','韓淲','宋','宋诗','song-poetry','','[]','人日遊茶山，點檢山下泉。',72,'全唐诗/poet.song.176000.json','["人日遊茶山，點檢山下泉。", "載惟兩賢祠，緬邈桑苧仙。", "豈無高潔懷，何有香火緣。", "雨晴動春事，草樹含芳妍。", "獨來宴坐久，湛然還惘然。", "扶輿度歸路，尋友了閒篇。"]'),
('5a131564-03f5-4b40-960c-25ffc6280669','茶山  其二','韓淲','宋','宋诗','song-poetry','','[]','南風滿脩竹，兩賢凜如生。',72,'全唐诗/poet.song.176000.json','["南風滿脩竹，兩賢凜如生。", "殘僧具湯餠，茗椀寒泉清。", "歸來涉城市，貨殖何縱橫。", "溪明漾長橋，履此復暢情。", "喧寂等一境，人世不足驚。", "北窗卧微凉，神思纔清平。"]'),
('0c6b1225-61f2-49df-a0c7-c01e30770a33','同尹一遊茶山齊賢繼來','韓淲','宋','宋诗','song-poetry','','[]','蒸雨隘閭巷，茶山午風清。',48,'全唐诗/poet.song.176000.json','["蒸雨隘閭巷，茶山午風清。", "同吟方齋人，禪老相送迎。", "隔城带湖光，更約暢敘情。", "輕雲轉雷晚，靜定天宇明。"]'),
('4db57559-2593-450c-a77c-1399fca070c6','東南一峰松雪明朗舍前甚可眺','韓淲','宋','宋诗','song-poetry','','[]','夜嚴風色冽，開門恍奇絕。',48,'全唐诗/poet.song.176000.json','["夜嚴風色冽，開門恍奇絕。", "誰將連日雨，幻此瓊玉屑。", "林深竹初折，澗淺冰復結。", "望久忽烟銷，山明見松雪。"]'),
('43885e4b-885f-4ce9-a82c-dcf1571803a2','四月十一日靈巖','韓淲','宋','宋诗','song-poetry','','[]','陟逕得遐矚，濯泉愜幽尋。',48,'全唐诗/poet.song.176000.json','["陟逕得遐矚，濯泉愜幽尋。", "禪窗坐來久，聊以娛客心。", "平田綠未整，湖色收晚陰。", "回橈繾綣餘，翔禽亦遺音。"]'),
('475f0f3c-4958-43a6-8201-6c5bb7817765','午日趙鈐轄同坐溪旁望靈山雲氣次韵','韓淲','宋','宋诗','song-poetry','','[]','塵俗自塵俗，幽奇自幽奇。',72,'全唐诗/poet.song.176000.json','["塵俗自塵俗，幽奇自幽奇。", "競渡殊污人，正爾無所之。", "城隅白雲堆，涌出靈山詩。", "不可磨滅者，天欲鑄偉辭。", "是大有佳趣，豈問庾元規。", "舉扇勿障風，吾與子同歸。"]'),
('ea3e8fe2-08c1-47cc-9032-096d058a62bb','雪觀  其一','韓淲','宋','宋诗','song-poetry','','[]','絕壑過蘭若，炷熏擁寒爐。',48,'全唐诗/poet.song.176000.json','["絕壑過蘭若，炷熏擁寒爐。", "稍收神觀明，時翻經與書。", "忘言忽自笑，得興將誰拘。", "雪雲起冰霜，是事俱澹如。"]'),
('3c220c94-1c13-4122-9418-d1a10f3a1510','雪觀  其二','韓淲','宋','宋诗','song-poetry','','[]','暮鼓朝鐘外，鼻端消息真。',96,'全唐诗/poet.song.176000.json','["暮鼓朝鐘外，鼻端消息真。", "靈山高溪南，而有彼上人。", "祝髮豈滅性，趺坐宜忘身。", "咄哉露地牛，染淨俱一塵。", "當年少林立，話頭猶許新。", "北風吹雨花，繽紛皓如銀。", "我來試標榜，此境何了因。", "無相亦無證，顰伸氣方勻。"]'),
('c56e535b-40ea-4480-83a5-17559cc7a651','秋日郊行題崇福寺大井','韓淲','宋','宋诗','song-poetry','','[]','秋暑未退舍，獨遊亭午時。',96,'全唐诗/poet.song.176000.json','["秋暑未退舍，獨遊亭午時。", "籃輿汗翻漿，陡覺回凉颸。", "青春十載前，此地嘗娛嬉。", "只今髮種種，蹉跎尚何之。", "懸崖多紫花，遶夜垂青枝。", "殘蟬猶爾噪，新鴈乃許遲。", "允矣原憲貧，異哉宋玉悲。", "酌泉揖老僧，清坐生佳思。"]'),
('b422e4e9-ffec-49d3-9ed4-3a04a09fe771','靈井','韓淲','宋','宋诗','song-poetry','','[]','靈井復何許，薰風度前林。',72,'全唐诗/poet.song.176000.json','["靈井復何許，薰風度前林。", "一筇爲蕭散，涉流殊匪深。", "山空人跡少，無言見鳴禽。", "嵌巖適所會，潺然送清音。", "宜我濯塵土，陶寫此胸襟。", "富貴本天命，得閑且幽尋。"]'),
('597074c6-7e7a-4dec-9374-8f4dad97ecfd','天竺靈隠觀鴻漸寺記白香山泉碑','韓淲','宋','宋诗','song-poetry','','[]','靈隠天竺山，清流潄奇石。',132,'全唐诗/poet.song.176000.json','["靈隠天竺山，清流潄奇石。", "草木鬰青葱，巖洞耀丹碧。", "有時閑聯騎，盡日爲散策。", "蕭條懷古心，髣髴問遺跡。", "勝士多去來，流年幾今昔。", "寺記喜逢陸，泉碑尚餘白。", "因知幽絕處，得之乃無歝。", "所以千載後，山名轉輝赫。", "二子有逸韵，煙霞本其癖。", "想當落筆時，無地著清適。", "嗟我復何人，長歌想英魄。"]'),
('b3bf27bb-64bf-48ee-82f9-44c076014ab1','參寥泉','韓淲','宋','宋诗','song-poetry','','[]','湖光佛寺古，山色泉水清。',72,'全唐诗/poet.song.176000.json','["湖光佛寺古，山色泉水清。", "蘇仙則已遠，名字空含情。", "西風動林松，琴瑟有餘聲。", "我來揖而酌，一飲百慮輕。", "朗吟兩石碣，脊記眼爲明。", "當年彼比邱，亦足得此生。"]'),
('1e4da185-983a-4b92-bbd7-2ba227c0b619','六一泉','韓淲','宋','宋诗','song-poetry','','[]','不見六一翁，但見六一泉。',108,'全唐诗/poet.song.176000.json','["不見六一翁，但見六一泉。", "得泉以思翁，昔僧何其賢。", "旨哉山中樂，合與蒼崖鎸。", "後來坡仙銘，空以文字傳。", "山林已禁苑，復與道院連。", "蘭若縱莫存，此水尤泠然。", "歲月誠易與，陵谷終變遷。", "薰風拂湖水，晚日明湖煙。", "回頭叫林逋，醉倒孤山前。"]'),
('b9a623ce-bad9-4309-ac6a-b435eef213fb','松竹堂次蕭宰相韵','韓淲','宋','宋诗','song-poetry','','[]','鳴琴意自永，小築松竹林。',72,'全唐诗/poet.song.176000.json','["鳴琴意自永，小築松竹林。", "公餘一委蛇，巡簷見遥岑。", "冰雪凜節操，晝寂綠陰陰。", "何事智與名，蕭散徵在今。", "當年山水間，讀書情致深。", "儀鳳覽德輝，終古存知音。"]'),
('047ece53-b2d8-4e52-a32d-60d41827de27','棲閑堂','韓淲','宋','宋诗','song-poetry','','[]','能棲不能閑，其心未可知。',132,'全唐诗/poet.song.176000.json','["能棲不能閑，其心未可知。", "能閑不能棲，其迹無已時。", "棲閑一以名，二者兼得之。", "昔春升其堂，尊酒飲于斯。", "昆山日夕佳，陂池清渺瀰。", "手植花柳間，田園粗充饑。", "潔哉兩龔家，異代猶許奇。", "夫豈忘治功，而故與世違。", "漢朝有蒲輪，用舍端不欺。", "三江五湖口，君子謹其儀。", "何以寫我歌，遥遥記所思。"]'),
('53785926-2e1c-42af-a5a8-8db9a4880a76','寄題壽樂亭','韓淲','宋','宋诗','song-poetry','','[]','蘭江生縠波，金華鬰嵯峨。',72,'全唐诗/poet.song.176000.json','["蘭江生縠波，金華鬰嵯峨。", "是中鶴髮親，贏得歲月多。", "時時著萊衣，兒嬉爲婆娑。", "撫掌問妻子，我意今如何。", "祥風動簷花，美日行庭柯。", "更覺山水外，一曲欵乃歌。"]'),
('450e6c94-d619-454e-9dd2-3df500f6dbef','過新安月夜步浮丘亭分韵賦詩得弄字','韓淲','宋','宋诗','song-poetry','','[]','平生風月懷，醉語或驚衆。',48,'全唐诗/poet.song.176000.json','["平生風月懷，醉語或驚衆。", "休傾袁紹杯，且卧畢卓甕。", "使君良不凡，客子恍如夢。", "對影將奈何，曉角梅花弄。"]'),
('2be03d9a-682f-4662-9eea-376547933d5d','同譚守登跨鶴臺','韓淲','宋','宋诗','song-poetry','','[]','昔守王道甫，作此跨鶴臺。',96,'全唐诗/poet.song.176000.json','["昔守王道甫，作此跨鶴臺。", "金行露氣高，嘗同斸蒿萊。", "九日長沙歸，晦翁命予杯。", "至今清夢長，寂寂令心哀。", "君侯我輩人，能賦有餘才。", "復茲菊花秋，登臨爲徘徊。", "子美高李句，萬里風雲來。", "世道古猶今，興也何悠哉。"]'),
('fdd62976-1cb6-476b-92d6-88cff464045f','浙江亭','韓淲','宋','宋诗','song-poetry','','[]','海風吹潮聲，過我欄檻外。',48,'全唐诗/poet.song.176000.json','["海風吹潮聲，過我欄檻外。", "不知地勢險，但覺天宇大。", "何時一壺酒，挂席上嚴瀨。", "班班雲壽陰，越山遠如带。"]'),
('af62ec89-5b06-4ea4-9472-1770d9ed135e','訪南岩一滴泉','韓淲','宋','宋诗','song-poetry','','[]','僧逃寺已摧，唯餘舊堂殿。',216,'全唐诗/poet.song.176000.json','["僧逃寺已摧，唯餘舊堂殿。", "顛倒但土木，彷彿昔所見。", "山寒少陽燄，崖冷盡冰線。", "曾無五六年，驟覺荒凉變。", "遺基尚可登，一滴泉自濺。", "憶昨淳熙秋，諸老所閑燕。", "晦庵持節歸，行李自畿甸。", "來訪吾翁廬，翁出成飲餞。", "因約徐衡仲，西風過遊衍。", "辛師倏然至，載酒具殽膳。", "四人語笑處，識者知歎羨。", "摩挲題字在，苔蘚忽侵徧。", "壬寅到庚申，風景過如箭。", "驚心半存沒，歷覽步徐轉。", "回思勸耕地，嘗著郡侯宴。", "今亦不能來，草木漫葱蒨。", "人間之廢壞，物力費營繕。", "不如姑付之，猿鳥自啼囀。"]'),
('e5cf0bbc-9d13-4072-92bf-69637ce94bd0','尋梅至梅嶺因遊紅羊石青楓峽','韓淲','宋','宋诗','song-poetry','','[]','衝寒步晴光，霜重積如雪。',48,'全唐诗/poet.song.176000.json','["衝寒步晴光，霜重積如雪。", "尋梅渡長溪，犖确路曲折。", "回風送灘聲，靜聽鳴復咽。", "當知我輩遊，名與山不滅。"]'),
('5fa330a9-e326-48c4-bf07-9a968db7ef0b','題姜堯章白石洞','韓淲','宋','宋诗','song-poetry','','[]','詩眼玩塵世，漫作威鳳鳴。',132,'全唐诗/poet.song.176000.json','["詩眼玩塵世，漫作威鳳鳴。", "經行苕溪水，乃見白石清。", "拂衣鑑須眉，喚起仙骨驚。", "胡爲隨人間，歎息百慮縈。", "洞中應笑我，何不高舉輕。", "明時樂未正，尚欲追英莖。", "它年淳氣合，肯有爵服情。", "癡人莫說夢，烈士徒殉名。", "轉庵偶饒舌，已足壓旦評。", "古來曠達者，談笑得此生。", "臨流賦招隠，一奏朱絃聲。"]'),
('9de3011e-c7fb-4aa1-9528-c0ccbe7c27e7','寄雪觀','韓淲','宋','宋诗','song-poetry','','[]','秋暑睡不美，但想雪觀居。',48,'全唐诗/poet.song.176000.json','["秋暑睡不美，但想雪觀居。", "焚香貝葉動，洗鉢伊蒲餘。", "應身了諸幻，起性包太虛。", "蓬蒿一水隔，吾豈愛吾廬。"]'),
('3983d154-1f18-400a-88f7-464f1ce1c6f5','寄題熊氏得要亭','韓淲','宋','宋诗','song-poetry','','[]','未踏得要亭，先寫得要詩。',72,'全唐诗/poet.song.176000.json','["未踏得要亭，先寫得要詩。", "識賞無遠近，渺然西江涯。", "薰風入山水，佳趣罔不宜。", "想見昏旦候，雲鳥日參差。", "主人應飄灑，何時同酒巵。", "三歎玉局仙，爲我先及茲。"]'),
('9ad36c9c-b741-4481-9073-37b8a2f51381','夜過潘樓','韓淲','宋','宋诗','song-poetry','','[]','雨多晴氣新，星彩動凉夜。',36,'全唐诗/poet.song.176000.json','["雨多晴氣新，星彩動凉夜。", "因人閑出門，尋詩稅吾駕。", "一杯小樓風，圖畫寄清暇。"]'),
('8e60ca6f-ec73-445b-a96b-4284eba3ca41','聚遠臺','韓淲','宋','宋诗','song-poetry','','[]','遥遥聚遠臺，是豈俗所要。',84,'全唐诗/poet.song.176000.json','["遥遥聚遠臺，是豈俗所要。", "只宜我行適，信得山水妙。", "地高出林表，眇邈有殊調。", "主人運心匠，擇勝出素料。", "陂陀闡微逕，俯視溪可照。", "匪云賦新詩，聊爾索言笑。", "三月青春深，風林杜鵑叫。"]'),
('92ae61bb-995d-48f8-9cae-af73ae195f7a','亭皋','韓淲','宋','宋诗','song-poetry','','[]','亭皋新雨沐，物物秋氣深。',60,'全唐诗/poet.song.176000.json','["亭皋新雨沐，物物秋氣深。", "著蕋木芙蓉，桂樹尤蕭森。", "豈伊酒可嘗，而我詩未吟。", "朅來六七輩，領會宜素衿。", "塵瞇共一掃，風乎出雲岑。"]'),
('0b905a23-9b37-4b52-b1ef-36e7b01ccf3b','會心堂','韓淲','宋','宋诗','song-poetry','','[]','胸中有天遊，寓外皆所嬉。',120,'全唐诗/poet.song.176000.json','["胸中有天遊，寓外皆所嬉。", "勝士固可逢，俗物亦可偕。", "杯酒得流行，放意而伸眉。", "茲辰我陽春，溪水多清姿。", "岸柳已青青，山花更暉暉。", "當筵主與賓，談妙尤克諧。", "雷聲忽送雨，雲風動情思。", "由來理性真，肯計志願違。", "松柏獨也正，造物付之誰。", "歡笑酬座人，長言其勿噫。"]'),
('fb0302b3-3d32-4ff3-9efb-c23e562360e1','題三茅堂讀放翁碑易道士設茗','韓淲','宋','宋诗','song-poetry','','[]','寶山最佳處，突兀三茅堂。',144,'全唐诗/poet.song.176000.json','["寶山最佳處，突兀三茅堂。", "幽襟翫岩穴，散脚登崇岡。", "梅亭雖未花，自覺草樹香。", "午陰布修幹，禽鳥時來翔。", "下視江海波，風煙渺茫茫。", "貞石披妙詞，摩挲有餘光。", "吾身已塵土，乃得閒相羊。", "羽人復能吟，煎茗邀山房。", "意勝神頓適，俗遠慮兼忘。", "乃知軒裳縶，自苦升斗藏。", "饑餓非難忍，歲月空帝鄉。", "揮手下山去，餘情滿秋陽。"]'),
('8d5f2371-0c4a-4ec1-96b6-8de7e21adcbe','溪山堂曾宏甫作徐師川呂居仁曾吉甫王元渤鄭顧道晁恭道王起巖吳傳朋徐明叔遊咏之地','韓淲','宋','宋诗','song-poetry','','[]','當年二三老，曾醉溪山堂。',72,'全唐诗/poet.song.176000.json','["當年二三老，曾醉溪山堂。", "至今月露底，草木有餘香。", "興言我良友，六月此追凉。", "還同章泉叟，訪之以相羊。", "夜久清輝寒，水際如雪光。", "誰知幽絕處，懷賢正難忘。"]'),
('2a124146-2db7-4b5c-b64d-8f8436272a38','拂松閣','韓淲','宋','宋诗','song-poetry','','[]','太白孰可作，五松自青山。',72,'全唐诗/poet.song.176000.json','["太白孰可作，五松自青山。", "關關鳥飛集，冉冉雲往還。", "時世有今古，客意徒悲歡。", "我來見令君，絃歌遊其間。", "醉袖舞回時，俗眼應不看。", "人韵乃如許，結閣橫朱欄。"]'),
('c9c43c91-ff2c-4edb-af3c-9cb9927049b7','伯輝竹林書院','韓淲','宋','宋诗','song-poetry','','[]','竹林彼一時，仲容乃此遊。',108,'全唐诗/poet.song.176000.json','["竹林彼一時，仲容乃此遊。", "寥寥千載後，忍曰爲良謀。", "古人心匪遐，用舍多風流。", "身容縱未老，歲月去不留。", "結茅我山椒，詩書尚何求。", "固將淑諸人，猶能誦軻丘。", "朅來南風薰，見子忘百憂。", "阮蓋青雲器，濤戎信其儔。", "取酒且勿飲，聽作商聲謳。"]'),
('61bb84cf-f6b9-4a52-a5da-597365ae1235','逍遥閣','韓淲','宋','宋诗','song-poetry','','[]','翁家爛柯橋，遊戲錢塘歟。',192,'全唐诗/poet.song.176000.json','["翁家爛柯橋，遊戲錢塘歟。", "昔賢有樂地，天與此屋廬。", "依依巷陌間，將鶴倒騎馿。", "流傳得佳聲，是時當國初。", "四方次第平，降王亦誅鉏。", "朝野多豪英，仲先頗知渠。", "相邀一夜話，華山圖匪虛。", "此州真可人，林逋復來居。", "一湖浸孤山，相望誠有餘。", "人生百年爾，貴賤空乘除。", "尚友千載上，是心良晏如。", "有手可持酒，有眼可誦書。", "結閣老樹高，扁榜聊自舒。", "方今開禧年，吳越都乘輿。", "我遯楚溪口，因名倍躊躇。", "既同逍遥吟，又且思莊樗。"]'),
('66195517-e328-4cb0-a100-3235ad886943','王右司家池閣','韓淲','宋','宋诗','song-poetry','','[]','寒日照竹色，老槐摇池光。',48,'全唐诗/poet.song.176000.json','["寒日照竹色，老槐摇池光。", "凭欄俯虛簷，忽此陶一觴。", "主人與客笑，萬事俱茫茫。", "回首十年夢，吹霜晚雲黄。"]'),
('b36846f3-a5c1-4a20-9e41-bbf34642be2a','守軒','韓淲','宋','宋诗','song-poetry','','[]','孟以身爲大，曾惟貴夫約。',48,'全唐诗/poet.song.176000.json','["孟以身爲大，曾惟貴夫約。", "况欲行之家，蓋亦念前作。", "誠齋彼何人，老筆乃揮霍。", "勿忘勿助長，世世可如昨。"]'),
('84c26cc6-d50d-4622-9f14-c3618b45e108','寄軒','韓淲','宋','宋诗','song-poetry','','[]','陶潛彭澤歸，豈敢傲一世。',48,'全唐诗/poet.song.176000.json','["陶潛彭澤歸，豈敢傲一世。", "聊從戶牖間，作計等蟬蛻。", "君乎得此心，名字置所憇。", "俛仰旦復昏，淺揭深則厲。"]'),
('aba470bd-1eab-4197-982f-20711931a917','恕齋','韓淲','宋','宋诗','song-poetry','','[]','公心不兩照，私意必四出。',96,'全唐诗/poet.song.176000.json','["公心不兩照，私意必四出。", "涖官行法間，要以身爲律。", "物物或藩籬，事事祇刀筆。", "由來貴仁賢，存之在勿失。", "美哉一言富，乃榜此書室。", "因利得行義，徇名豈忘實。", "君兮詩中仙，我語非秘密。", "三歎蓮幕地，退食有學術。"]'),
('aa72cf29-7559-4ced-baca-132d5a8a5eba','昌甫竹隠','韓淲','宋','宋诗','song-poetry','','[]','竹隠高深處，江南懷玉村。',96,'全唐诗/poet.song.176000.json','["竹隠高深處，江南懷玉村。", "此老已華顛，清門非市閽。", "緩步泉周遭，放眼雲吐吞。", "野馬閲衆甫，冥鴻本孤鶱。", "經年未能往，夢思疲我魂。", "是中夫如何，不以俗諦論。", "時來五七字，慘慘感慨存。", "想其樹扶疎，遶屋夏籜翻。"]'),
('03fd4f61-148b-4c9c-86b5-1f2ca0763692','田間','韓淲','宋','宋诗','song-poetry','','[]','烏麥相看種，黄秈已皆熟。',48,'全唐诗/poet.song.176000.json','["烏麥相看種，黄秈已皆熟。", "坳塘無賸水，古徑墮枯木。", "貧多收刈遲，勤有翻耕速。", "整履步大田，扶藜問幽谷。"]'),
('697696c1-cb6a-4ec3-9cc4-b0e2da59820a','餘干黄師求北窗詩','韓淲','宋','宋诗','song-poetry','','[]','陶令一北窗，今古自無對。',72,'全唐诗/poet.song.176000.json','["陶令一北窗，今古自無對。", "折腰豈爲米，歸來本非退。", "平生羲皇心，肯與時嚮背。", "當年五柳傳，誰云閉關輩。", "子能知其然，此意要常在。", "淵明不吾欺，是中誠可愛。"]'),
('16fd2577-7d6c-4c5b-b3a1-75b299af9a41','李禮侍石林','韓淲','宋','宋诗','song-poetry','','[]','磊磈著胸次，婆娑寄嶙峋。',84,'全唐诗/poet.song.176000.json','["磊磈著胸次，婆娑寄嶙峋。", "客來亦置酒，相與悅老身。", "晴風吹岷峨，浩蕩無邊春。", "巴江下吳波，軟紅生帽塵。", "回頭山房染，石也誠可人。", "不知幾千人，造化此一真。", "只恐斷取去，補天費精神。"]'),
('74d0a7c8-f6b5-434f-9a69-f2e23259dd40','官閑','韓淲','宋','宋诗','song-poetry','','[]','官閑讀書餘，倚杖看綠陰。',48,'全唐诗/poet.song.176000.json','["官閑讀書餘，倚杖看綠陰。", "黄鳥時飛來，臨風流好音。", "我亦爲之喜，夷猶情味深。", "世間事乃爾，回首生夕曛。"]'),
('2080a5c8-d4d5-44a8-9f66-b58e43e4c18d','休日靜居','韓淲','宋','宋诗','song-poetry','','[]','寒餓迫我出，忽忽兒女大。',72,'全唐诗/poet.song.176000.json','["寒餓迫我出，忽忽兒女大。", "原思樂商頌，宋玉悲楚些。", "吹面薰風來，刮眼春風過。", "飛鳴鵲遶樹，徵逐蟻旋磨。", "瀹茗銷夢事，凝香理經課。", "休澣得暫閑，棲深淨趺座。"]'),
('61ded565-ec08-410a-af93-7b4bb9353e79','叢薄','韓淲','宋','宋诗','song-poetry','','[]','叢薄欲微雨，絕壑留餘寒。',48,'全唐诗/poet.song.176000.json','["叢薄欲微雨，絕壑留餘寒。", "隴麥已黄熟，園梅尚青攢。", "宛宛路轉坡，激激流起湍。", "卧瓶擲酒椀，開奩理香槃。"]'),
('833c6149-94b0-479a-873a-0e78e758e1ea','十月旦日過雲林','韓淲','宋','宋诗','song-poetry','','[]','雲林起清霜，山寒紅日吹。',48,'全唐诗/poet.song.176000.json','["雲林起清霜，山寒紅日吹。", "城郭催租日，田家穫稻時。", "仲尼雖少賤，李廣漫多奇。", "好事能相覓，茅簷曝晴曦。"]'),
('83d6ed70-78fa-4967-bc90-0c72d826ad99','雲庵','韓淲','宋','宋诗','song-poetry','','[]','雲兮所怡悅，遂以庵我名。',48,'全唐诗/poet.song.176000.json','["雲兮所怡悅，遂以庵我名。", "時時簷下來，日日山畔生。", "和煙不知處，致雨非有情。", "龍鶴亦物耳，依乘定飛鳴。"]'),
('772727f3-45e7-4b00-b14e-176f6dbd7280','次韵伯皋真隠道院','韓淲','宋','宋诗','song-poetry','','[]','幽討過真隠，同抱白雲眠。',120,'全唐诗/poet.song.176000.json','["幽討過真隠，同抱白雲眠。", "夜呼醉道士，取琴咏琅然。", "松鳴簷外山，水落橋下淵。", "推窗挂星斗，清神浩無邊。", "是中宜共如，此外憑誰傳。", "孫登蘇門嘯，子猷剡溪船。", "古來賢達士，往往如春煙。", "浮名竟何益，畢世空林泉。", "縱觀彼斗筲，畏塗競爭先。", "輿馬能幾時，鼎鑊已在前。"]'),
('50eb6ddc-8cf2-4f04-b2c9-4c8d0628f82e','楚黄相廟','韓淲','宋','宋诗','song-poetry','','[]','開禧二年春，寂寂楚相廟。',84,'全唐诗/poet.song.176000.json','["開禧二年春，寂寂楚相廟。", "上書能說秦，將兵亦救趙。", "太子質不歸，變衣何其妙。", "因城吳故墟，宮室本照耀。", "寵辱一以驚，失計易貽笑。", "帳座神所嚴，香火忍興弔。", "但想荀蘭陵，朱英或同調。"]'),
('72b74585-b81f-4669-a3c5-8f553d2d89cf','夏日集報恩僧寺同莊賢良諸公分韵得餠字','韓淲','宋','宋诗','song-poetry','','[]','尋僧坐清晝，會友踐佳境。',144,'全唐诗/poet.song.176000.json','["尋僧坐清晝，會友踐佳境。", "興寄徒自深，遊觀轉便靜。", "荷翻一水香，柳散滿階影。", "相從解巾屨，愛此夏日永。", "熏罏鼻觀通，汲井齒頰冷。", "勞公具酒炙，餉我作湯餠。", "同時得二士，俊發錐露穎。", "高步不可攀，奇語尚堪省。", "徐郎招不來，悵望終耿耿。", "生平厭塵煩，老去合幽屏。", "豈無親朋樂，所慮乏規警。", "長歌及黄農，妙處亦深領。"]'),
('d94ae760-38ed-4e1c-ae7f-9a1ca7f9b0a1','寂照寺','韓淲','宋','宋诗','song-poetry','','[]','江西得名士，與我同山行。',72,'全唐诗/poet.song.176000.json','["江西得名士，與我同山行。", "老釋能追隨，醉眼增雙明。", "經時客吳會，雜遝塵務嬰。", "偶然汎孤舟，故人百里情。", "既已酒屢飲，亦復詩自成。", "盡日空翠間，冥鴻杳飛鳴。"]'),
('b1aa2d3e-b31c-4099-9cef-223f5f5809dd','祖印寺俗云嚴光寺考治平堂牒乃光嚴也又言有子陵墓因往弔之','韓淲','宋','宋诗','song-poetry','','[]','長溝流水急，荒塗少人跡。',48,'全唐诗/poet.song.176000.json','["長溝流水急，荒塗少人跡。", "扶輿問遺蹤，晶晶度秋日。", "子陵誰復知，墓古莽榛棘。", "傳聞雖未真，此意自無極。"]'),
('0bdc9dee-8fe2-4922-b486-7ea0b00ddf15','月林','韓淲','宋','宋诗','song-poetry','','[]','秋池浸秋月，梅影摇清流。',48,'全唐诗/poet.song.176000.json','["秋池浸秋月，梅影摇清流。", "數枝雖未花，橫斜已幽幽。", "白酒孰飲我，同來亦良謀。", "盃行景自佳，風葉何颼飀。"]'),
('98a17ebe-264a-43ee-8bde-fad04f0dde5c','林德九國錄作冰玉寮來索賦因寄五字','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','仇池蘇仙語，發揮我孤山。',120,'全唐诗/poet.song.176000.json','["仇池蘇仙語，發揮我孤山。", "孤山有何佳，林逋廬其間。", "風高氣化遠，庸販亦班班。", "是榮人爵歟，百世不可攀。", "沉冥愜幽性，道勝無戚顔。", "至今西湖西，眇彌尚滄灣。", "誰夫仕吳京，斂焉心肯閒。", "吟諷彼一詩，靜視觸與蠻。", "齋房如僧寮，熱客自塵寰。", "出處貴君子，安時諒非艱。"]'),
('cf135d1f-06ba-4193-8308-5e5a281321a3','周質夫山楹','韓淲','宋','宋诗','song-poetry','','[]','山楹非市廛，懸解於其表。',84,'全唐诗/poet.song.176000.json','["山楹非市廛，懸解於其表。", "灌木固蔽虧，閑雲定旋繞。", "廣厦千萬間，一架亦已了。", "坐起共炎冷，眠食易昏曉。", "偶然屋打頭，所處實在小。", "鷄鳴近相聞，鷗下復遠矯。", "尤當沃巵酒，忘却吟思悄。"]'),
('4e52298d-700d-4a5b-a4ce-817aa5fec53e','補籬','韓淲','宋','宋诗','song-poetry','','[]','補籬去惡竹，修逕護幽草。',48,'全唐诗/poet.song.176000.json','["補籬去惡竹，修逕護幽草。", "微風入庭榭，秋雨汎池沼。", "荷香浸狂瀾，林影動深窈。", "寬平日月閑，湫隘天地小。"]'),
('87409d49-c9fa-4364-9aff-dbd6309ddf9d','過永豐題','韓淲','宋','宋诗','song-poetry','','[]','落日洲渚明，水石鳴灘聲。',48,'全唐诗/poet.song.176000.json','["落日洲渚明，水石鳴灘聲。", "臨眺一何樂，共此人境清。", "游子未忘情，亦復小詩成。", "東風波粼粼，爲我吹酒醒。"]'),
('05f93e10-910a-4810-9197-accaf9b18160','夜過博山','韓淲','宋','宋诗','song-poetry','','[]','山行迫昏黑，乞火野人家。',72,'全唐诗/poet.song.176000.json','["山行迫昏黑，乞火野人家。", "陰風振林壑，水激溝港斜。", "扶輿聽鳴鐘，尚覺塗路賒。", "叩門得蘭若，僮僕欣不差。", "老僧爲作茗，趺坐談無涯。", "子夜各休去，幻境良可嗟。"]'),
('1e84b694-46d8-4955-ad7a-271a47125213','衝雨小舟上南港','韓淲','宋','宋诗','song-poetry','','[]','拖舟上寒瀨，冥冥吹雨來。',48,'全唐诗/poet.song.176000.json','["拖舟上寒瀨，冥冥吹雨來。", "連綿岸草合，斷落山林開。", "鴈鶩杳滅沒，鳬鷗正沿洄。", "艤舟見修竹，題句復尋盃。"]'),
('933dccaa-8314-4bb9-a8f3-543437d79063','過吳淞','韓淲','宋','宋诗','song-poetry','','[]','家住楚溪口，幾年卧雲峰。',120,'全唐诗/poet.song.176000.json','["家住楚溪口，幾年卧雲峰。", "春風此行邁，煙樹五湖東。", "無因見范蠡，危亭只垂虹。", "逃名匪難事，浪曰陶朱公。", "倉皇誠自污，商賈聊長雄。", "庶幾收伯圖，不見前日功。", "欲富果本心，是豈計未終。", "我疑滑稽甚，視彼如兒童。", "西子有底好，尚有歡笑同。", "扁舟汎長波，自足成老翁。"]'),
('255f86be-e5d4-4a80-af3b-6c712ed7f5e6','山口','韓淲','宋','宋诗','song-poetry','','[]','山口復谿口，飛花閑度柳。',48,'全唐诗/poet.song.176000.json','["山口復谿口，飛花閑度柳。", "不喜梅雨晴，清和猶在候。", "一日是一日，青鬢對皓首。", "朋來方齋家，杯行莫停手。"]'),
('36d65745-af23-4581-888f-f71f43abac94','德源道中','韓淲','宋','宋诗','song-poetry','','[]','數鴨汎寒塘，前後相參差。',48,'全唐诗/poet.song.176000.json','["數鴨汎寒塘，前後相參差。", "不知已嚴冬，但謂水自如。", "貪生處塵世，大抵多類斯。", "木葉風下來，紅綠雜萍蕪。"]'),
('4adb97b9-bbe2-48e0-8090-d617b0819bc2','靈鷲道中','韓淲','宋','宋诗','song-poetry','','[]','霜林落衰草，遊子歎道途。',48,'全唐诗/poet.song.176000.json','["霜林落衰草，遊子歎道途。", "豈不念急景，冉冉塵務俱。", "閑寫僧寺幽，髣髴摩詰圖。", "風前鴻鴈來，日下鶬鴰呼。"]'),
('b2da4b03-4ab2-420e-b8aa-a2ef52b522d9','樓窗靜對頗快','韓淲','宋','宋诗','song-poetry','','[]','奔忙九衢裏，無處著兩眼。',48,'全唐诗/poet.song.176000.json','["奔忙九衢裏，無處著兩眼。", "樓高試推窗，可以得笑莞。", "東方接瀰茫，西地列𡾰嵼。", "心中與之然，不記倒手板。"]'),
('dc94d9d1-f4f3-499a-866d-63c92e574c32','晚訪斯遠村塢','韓淲','宋','宋诗','song-poetry','','[]','沿流出山來，度橋向城去。',48,'全唐诗/poet.song.176000.json','["沿流出山來，度橋向城去。", "晃朗雨復晴，崢嶸歲云暮。", "閑常稱心言，孰是得力句。", "塢靜見高明，林深認幽趣。"]'),
('6926c080-3aeb-4843-9b11-3c7d7522e24b','地偏','韓淲','宋','宋诗','song-poetry','','[]','地偏塵自銷，風扉亦常關。',48,'全唐诗/poet.song.176000.json','["地偏塵自銷，風扉亦常關。", "不知芳草多，但與落花閑。", "紅日到碧澗，白雲在青山。", "懷人長言之，老子何癡頑。"]'),
('86616720-6a85-4dfe-b70a-c27d5d10c06d','大滌翠蛟寺','韓淲','宋','宋诗','song-poetry','','[]','山以水而勝，水以人而清。',48,'全唐诗/poet.song.176000.json','["山以水而勝，水以人而清。", "人水亦何事，乾坤無限情。", "酒好滿杯飲，詩到一篇成。", "杜鵑風外啼，青林開晚晴。"]'),
('1459ac51-8996-4592-ae04-13cdac71e8cf','對雪思山居之時','韓淲','宋','宋诗','song-poetry','','[]','煙迷南屏山，凍壓竹落磵。',48,'全唐诗/poet.song.176000.json','["煙迷南屏山，凍壓竹落磵。", "幽人紙被軟，卧起日已晏。", "藩籬鳥雀噪，亦復斷藜莧。", "慘淡詩未成，詩成復何患。"]'),
('91215732-7f96-4c0d-8f72-7dd9e1b1db3e','散步','韓淲','宋','宋诗','song-poetry','','[]','世道日狹隘，無地可自容。',48,'全唐诗/poet.song.176000.json','["世道日狹隘，無地可自容。", "豈不有崖壑，樂此林下風。", "乘晴氣清和，試聽飛流淙。", "憑軒得名酒，老我時一中。"]'),
('591c8cc7-10ca-4914-8194-ad7e7ec71a3a','秋興家山之咏','韓淲','宋','宋诗','song-poetry','','[]','塵埃困小官，忍窮未爲長。',96,'全唐诗/poet.song.176000.json','["塵埃困小官，忍窮未爲長。", "勿苦問窮達，當與貧相忘。", "幽棲吳山底，偶占大隠坊。", "晨興到藥局，夜坐唯書房。", "俯仰亦已安，怳然如山莊。", "巷僻遠市語，窗明摇燈光。", "不覺西風起，鴈飛草木黄。", "澗下有敝廬，懷哉付饑腸。"]'),
('e307166a-bb07-4328-998b-4dd517f71f9e','招隠','韓淲','宋','宋诗','song-poetry','','[]','浩歌以求志，徜徉山水幽。',72,'全唐诗/poet.song.176000.json','["浩歌以求志，徜徉山水幽。", "松柏蒼蒼山，水石泠泠流。", "山深集飛鳥，水淺下輕鷗。", "好花不多聞，長煙渾未收。", "往來有樵釣，俛仰徂春秋。", "我輩滿宇宙，其能知此不。"]'),
('c03f0ef5-1eb6-43cb-add4-045c97bbca2e','閑泊東窗爲靜寄','韓淲','宋','宋诗','song-poetry','','[]','吾愛陶詩中，靜寄東軒語。',48,'全唐诗/poet.song.176000.json','["吾愛陶詩中，靜寄東軒語。", "試取作佳名，朝夕相與處。", "薰風一榻閑，轉覺遠煩暑。", "試問軒外人，紛華今幾許。"]'),
('45481d05-cf3d-493c-b3d5-e061ad5f8d49','雨乍霽散步村野山谷間','韓淲','宋','宋诗','song-poetry','','[]','幽居喜乍晴，閑步轉山麓。',96,'全唐诗/poet.song.176000.json','["幽居喜乍晴，閑步轉山麓。", "塘坳過兩家，山嘴見一屋。", "坡陀上平崗，窈窕入深谷。", "時時看採桑，往往值播穀。", "鷄飛田婦呼，牛走牧兒逐。", "路平豁呈露，地僻杳藏伏。", "風物晚春時，但見青草木。", "無爲扣角歌，但賦采薇曲。"]'),
('08ae564b-c330-4a60-80b9-9df2b9f9de0f','水村','韓淲','宋','宋诗','song-poetry','','[]','露荷煙柳外，月上山翠寒。',48,'全唐诗/poet.song.176000.json','["露荷煙柳外，月上山翠寒。", "水際一斷橋，籬落小欄干。", "剝啄喚我友，共此懷抱寬。", "興盡出城去，兩耳清流灘。"]'),
('1beed418-a439-4e8d-8293-131f38ec2fd8','十五日齋素','韓淲','宋','宋诗','song-poetry','','[]','清晨却葷茹，茗事煎胡麻。',48,'全唐诗/poet.song.176000.json','["清晨却葷茹，茗事煎胡麻。", "豈無素心人，潔齋避風沙。", "月已秋氣中，能來我山家。", "凉襟何待吹，宴坐且勿譁。"]'),
('b07652f7-a65b-4d4a-a0aa-4c66f7c0d7b8','午步','韓淲','宋','宋诗','song-poetry','','[]','氣晴天惟澄，春物自朝暮。',48,'全唐诗/poet.song.176000.json','["氣晴天惟澄，春物自朝暮。", "沿流陟危磴，絕壑理幽步。", "雲根見泉脈，僧房杳回互。", "豈無我同心，杯來飲爲度。"]'),
('7744cbe6-eb4e-46a5-846d-ef974ad9197a','雪觀晚步','韓淲','宋','宋诗','song-poetry','','[]','山梅占殘雪，晚色轉幽徑。',48,'全唐诗/poet.song.176000.json','["山梅占殘雪，晚色轉幽徑。", "塵銷水石潤，所至集虛聽。", "僧窗話未圓，茗椀味初定。", "澹泊歲寒心，浮空殷鐘磬。"]'),
('28c4193b-28da-4664-87bc-73f4bd941e50','晚步','韓淲','宋','宋诗','song-poetry','','[]','萬木山彩翠，一水澗淪漪。',48,'全唐诗/poet.song.176000.json','["萬木山彩翠，一水澗淪漪。", "放步且曳杖，有懷還賦詩。", "我之所安適，人以爲娛嬉。", "南風送晚雨，何處不相宜。"]'),
('c572ddd8-7425-4dc5-9f72-2961c48219c7','放步','韓淲','宋','宋诗','song-poetry','','[]','家家芙蓉開，步步木犀香。',48,'全唐诗/poet.song.176000.json','["家家芙蓉開，步步木犀香。", "流黄朝絳節，空碧按霓裳。", "急景奚足競，良辰不可忘。", "玉階明露盤，珠宮結雲房。"]'),
('b4024cca-4a17-4ea0-be6a-aa47ba91603b','晚興','韓淲','宋','宋诗','song-poetry','','[]','林蟬動微暑，風影摇東軒。',48,'全唐诗/poet.song.176000.json','["林蟬動微暑，風影摇東軒。", "山近鬰巃嵷，澗長瀉潺湲。", "閉關誦古書，時時一逢原。", "撫卷得閑樂，老境俱忘言。"]'),
('35c54286-d5f4-4a91-9b39-0ce5672bd880','夜坐  其一','韓淲','宋','宋诗','song-poetry','','[]','經年仕吳會，風埃滿書劍。',48,'全唐诗/poet.song.176000.json','["經年仕吳會，風埃滿書劍。", "迢迢秋夜長，靜坐生百念。", "浮榮本何益，微祿已屬饜。", "露氣入窗寒，青燈散餘焰。"]'),
('fab0789f-8c07-41f6-ad86-ed41ca812ed2','夜坐  其二','韓淲','宋','宋诗','song-poetry','','[]','吳山歲夜雨，巷深雜泥土。',48,'全唐诗/poet.song.176000.json','["吳山歲夜雨，巷深雜泥土。", "白髮倚高樓，長吟自懷古。", "人人尋酒杯，處處亦歌舞。", "萬事付燈檠，寒爐聽更鼓。"]'),
('437c5a47-f180-494b-b765-0cae19cb7b68','夜坐  其三','韓淲','宋','宋诗','song-poetry','','[]','夜時對青燈，朝晨向紅日。',84,'全唐诗/poet.song.176000.json','["夜時對青燈，朝晨向紅日。", "渴飲一杯湯，饑餐兩器食。", "榮衰受榮衰，得失順得失。", "一事到眼前，一事與擘畫。", "不到眼前者，空思亂胸臆。", "非惟昏人神，且是長戚戚。", "吾今知此愆，念之戒勿失。"]'),
('7665d1c9-6954-49f3-b91a-9b6c2a2251ed','題錢塘三賢堂','韓淲','宋','宋诗','song-poetry','','[]','暑雨過林壑，青青發幽香。',144,'全唐诗/poet.song.176000.json','["暑雨過林壑，青青發幽香。", "徘徊湖水邊，路轉山橫崗。", "朱門嚴古祠，中有水仙王。", "配食者誰子，三賢坐高堂。", "當年處士廬，鬰然眇相望。", "故侯白與蘇，龍章照錢塘。", "人生死即已，姓字何芬芳。", "修名貴自立，隠德千古光。", "文章發政事，百世胡能忘。", "因看游魚潛，更想冥鴻翔。", "微官得休沐，况復五月凉。", "茲遊獲勝踐，不覺歌聲長。"]'),
('629c3516-126f-4e30-95d4-6d67f1895c6a','清桐','韓淲','宋','宋诗','song-poetry','','[]','清桐發初葉，朝景散輝蔭。',48,'全唐诗/poet.song.176000.json','["清桐發初葉，朝景散輝蔭。", "幽人獨步久，興寄頗自任。", "薰兮一以風，山鳥孰知禁。", "平流走亂石，可潄尤可枕。"]'),
('80216d9d-5575-46b3-91e1-1e4909d0f0a5','田里間見荷花','韓淲','宋','宋诗','song-poetry','','[]','避暑暑復至，乘凉凉未來。',48,'全唐诗/poet.song.176000.json','["避暑暑復至，乘凉凉未來。", "平生欲快意，命也何疑哉。", "駕言田里間，薰風動蒿萊。", "小池其誰家，亦有荷花開。"]'),
('af849493-f930-4d09-88f9-33c85b25f825','芍藥','韓淲','宋','宋诗','song-poetry','','[]','庭中鮮香起，猶覺春有餘。',72,'全唐诗/poet.song.176000.json','["庭中鮮香起，猶覺春有餘。", "豈謂衆芳歇，而乃自發舒。", "溫風拂波軟，朗日明林虛。", "盤盂作態度，翡翠爲襟裾。", "一枝已惱我，滿欄無奈渠。", "偶爾著醉目，何礙幽人居。"]'),
('41e62f2b-12fc-49ef-8d77-efda2651bb71','露菊','韓淲','宋','宋诗','song-poetry','','[]','英英輝叢菊，重露滋其花。',48,'全唐诗/poet.song.176000.json','["英英輝叢菊，重露滋其花。", "移來秋已深，不飲亦已嘉。", "小檻憑虛簷，山迥無風沙。", "霽色寒未生，此地玉溪家。"]'),
('c6d5a3ba-d43e-4965-9862-98cc24c6e2d1','塹花香盛','韓淲','宋','宋诗','song-poetry','','[]','不奈蒸溽氣，試度清微風。',48,'全唐诗/poet.song.176000.json','["不奈蒸溽氣，試度清微風。", "浮梁水南北，天以語句同。", "塹花吹郁郁，岸柳垂濛濛。", "抵手今何夕，酒過面亦紅。"]'),
('e9954bb4-75fd-412e-be0b-77dbe2bf9412','瓶中花','韓淲','宋','宋诗','song-poetry','','[]','枝持三數花，已著風露香。',48,'全唐诗/poet.song.176000.json','["枝持三數花，已著風露香。", "而復滿把來，汲瓶置書房。", "身心我身心，染淨皆秋光。", "今夜月圓明，更妙非紅黄。"]'),
('acb99530-1b8e-4f12-a2f5-cba5fa7c8b08','周景瑜置酒東園看海棠分韵得上字','韓淲','宋','宋诗','song-poetry','','[]','春光作花事，領略過溪上。',96,'全唐诗/poet.song.176000.json','["春光作花事，領略過溪上。", "寒凄風雨餘，草樹亦舒放。", "紅深海棠徑，蜀錦開步障。", "得酒一以醉，幽情爲之暢。", "主人良好事，舉白欣相向。", "坐間多豪英，笑倒語彌壯。", "歸塗踏微潦，滿目列青嶂。", "顧予何爲者，追隨生悵望。"]'),
('fbb4f24a-63f9-4aad-a5c4-0ff2b991b6d6','蘇堤芙蓉','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖八九月，蘇堤賞芙蓉。',144,'全唐诗/poet.song.176000.json','["西湖八九月，蘇堤賞芙蓉。", "艷艷風日美，鮮鮮霜露濃。", "今年開最繁，映水自爲容。", "十里爛成錦，紅綠花重重。", "錢塘盛吳會，昭代多鼎鍾。", "遊人醉不歸，車馬如游龍。", "里巷達廊廟，歌酒日相從。", "千鍾不憚費，一笑無留蹤。", "勝踐窮耳目，樂事開心胸。", "東遊將百年，兵農晏提封。", "四境復豐穰，物色近初冬。", "作詩代華黍，皇風正時雍。"]'),
('68977600-a378-45c7-8b82-bbb424a7fb2b','牆外芙蓉初過其一尚可玩','韓淲','宋','宋诗','song-poetry','','[]','日晚山氣寒，芙蓉表孤花。',48,'全唐诗/poet.song.176000.json','["日晚山氣寒，芙蓉表孤花。", "亭亭萬綠中，紅鮮照萎葩。", "不與時物遷，肯以顔色誇。", "立而望之徧，落葉徒泥沙。"]'),
('22a33c6f-21e8-4a48-a59c-9efff1c2190b','池上菊爛然','韓淲','宋','宋诗','song-poetry','','[]','彼美黄金花，爲我遶池游。',72,'全唐诗/poet.song.176000.json','["彼美黄金花，爲我遶池游。", "十月無清霜，尚作重陽秋。", "胡廣潭何爲，陶潛籬何求。", "人物偶相值，終古評不休。", "興愜景勿違，語到氣自遒。", "小摘問頹齡，記取南山幽。"]'),
('aa518261-f6e0-49b8-807d-51e1aaf6f938','九日無菊月半後始有市者','韓淲','宋','宋诗','song-poetry','','[]','前年重陽時，黄華正紛披。',108,'全唐诗/poet.song.176000.json','["前年重陽時，黄華正紛披。", "去年近九日，已有菊盈枝。", "誰知今年晚，節後纔見之。", "高低燦羣葩，可受霜風吹。", "淵明心事老，借此吟吾詩。", "彭澤賦歸來，草木應差差。", "人苦不解事，謂渠愛東籬。", "芳草喜尚濃，色澤愁漸萎。", "欲醉可不飲，泛酒因兒嬉。"]'),
('b6c55330-35fb-4803-b215-a900f8e768c4','對菊讀韋蘇州詩','韓淲','宋','宋诗','song-poetry','','[]','結綬二十載，屢爲塵事嬰。',84,'全唐诗/poet.song.176000.json','["結綬二十載，屢爲塵事嬰。", "蹉跎入兩鬢，霜雪亦漸盈。", "曠然仕京國，頗以歲序驚。", "寂寞起凉颸，時菊忽已榮。", "依叢思濁醪，餘馥襟神清。", "樂幽愜理性，貧蹇安物情。", "休沐得殊賞，感茲寵辱輕。"]'),
('99d8b426-26a9-436c-aea0-428e48ff4d68','十二月旦禪月臺問梅','韓淲','宋','宋诗','song-poetry','','[]','山臺見疎梅，野氣挾寒力。',48,'全唐诗/poet.song.176000.json','["山臺見疎梅，野氣挾寒力。", "春從花際來，晃漾水南北。", "吟邊人已深，妙處我已得。", "鴈裂一聲中，蒼然起暮色。"]'),
('48548447-91a9-4a00-86dd-57cde094d32e','東山看梅','韓淲','宋','宋诗','song-poetry','','[]','臘近山放梅，霜餘竹支逕。',48,'全唐诗/poet.song.176000.json','["臘近山放梅，霜餘竹支逕。", "坡陀斜日晚，葱蒨孤煙暝。", "人行興將闌，鳥語棲未定。", "更踏野橋歸，風回滿清聽。"]'),
('65cf46bf-b7db-401c-84c7-86889d0570ea','梅花一一可愛','韓淲','宋','宋诗','song-poetry','','[]','點點草際梅，橫斜風弄影。',48,'全唐诗/poet.song.176000.json','["點點草際梅，橫斜風弄影。", "秋老揫斂時，而復有此景。", "天地欲回春，不礙霜露冷。", "林逋亦癡人，有句不堪省。"]'),
('2bd6f189-be25-40a9-a671-e32af6150438','蠟梅','韓淲','宋','宋诗','song-poetry','','[]','家山蠟梅開，歷歷水邊樹。',96,'全唐诗/poet.song.176000.json','["家山蠟梅開，歷歷水邊樹。", "故園不可見，胡能寫吟句。", "隨風惜其姿，破霧得其趣。", "淋漓銜一杯，錯莫展數步。", "不道緇塵中，惱我尚沉痼。", "瓶簪良自佳，但恐失平素。", "香傳疑麝煤，體弱豈金鑄。", "我居小窗橫，幽懷眇回互。"]'),
('0e53493f-401e-4adc-b035-b02286d5a0f1','買梅花木犀海棠橘栽置庫中','韓淲','宋','宋诗','song-poetry','','[]','護此數寸根，待彼數枝花。',96,'全唐诗/poet.song.176000.json','["護此數寸根，待彼數枝花。", "何時春風來，老眼易橫斜。", "桃紅與李白，長安事芳華。", "買栽恐無地，識者能幾家。", "家山對石澗，冬日百樹梅。", "梅花已一開，無時不持盃。", "客至雖留連，客去轉徘徊。", "今棲省戶間，一株手親培。"]'),
('29591d47-a77d-4f97-8f29-1a2c74ab2978','同鄭子華棋局作梔子詩','韓淲','宋','宋诗','song-poetry','','[]','郊居多幽香，衣被風雨之。',48,'全唐诗/poet.song.176000.json','["郊居多幽香，衣被風雨之。", "樵青採掇歸，清氣尤華滋。", "枰棋了勝敗，蠻觸彼一時。", "鮮鮮何滿叢，瑶葩賦山梔。"]'),
('9ad41474-44c6-40ff-ba2e-a8cbb842b2e3','梔子戎葵','韓淲','宋','宋诗','song-poetry','','[]','芬香得薝蔔，色澤有蜀葵。',48,'全唐诗/poet.song.176000.json','["芬香得薝蔔，色澤有蜀葵。", "雨露既濡矣，風日還過之。", "紙窗無畏景，石檻發凉思。", "艷艷紅花蘂，幽幽青碧枝。"]'),
('0583a45d-3075-4ea1-b43c-ad67f07ab070','初七夜半月色皎然忽聞吳山上鶴鳴','韓淲','宋','宋诗','song-poetry','','[]','雨止結霜華，片月載寒魄。',48,'全唐诗/poet.song.176000.json','["雨止結霜華，片月載寒魄。", "光芒星自稀，氣宇天更碧。", "何處孤鶴鳴，聲落吳山側。", "坐久神觀清，樓高夜方闃。"]'),
('3deacb0c-1aa5-4c47-af16-e7c2769026ff','鷹盤風','韓淲','宋','宋诗','song-poetry','','[]','寂寂鷹盤風，擾擾燕衝雨。',48,'全唐诗/poet.song.176000.json','["寂寂鷹盤風，擾擾燕衝雨。", "空梁如有言，廣野亦疑舞。", "豈不營窠巢，何嘗畏羅罟。", "仰視復行看，衡門室環堵。"]'),
('da4b1c35-2fb8-4b29-91b8-4643240cc578','聞啼鳥','韓淲','宋','宋诗','song-poetry','','[]','禽啼聲嚶嚶，泉流音琤琤。',48,'全唐诗/poet.song.176000.json','["禽啼聲嚶嚶，泉流音琤琤。", "微風摇青林，何其煙輕明。", "尋芳渾無花，春深尚含情。", "浮生無浪悲，誰知山中清。"]'),
('d0b99c1d-53c3-43d7-b31b-ab6ccb8df48e','午坐聞鵝鳴','韓淲','宋','宋诗','song-poetry','','[]','深居耳識迥，斂此神氣精。',48,'全唐诗/poet.song.176000.json','["深居耳識迥，斂此神氣精。", "窗簷隔林塘，杳杳鵝鸛鳴。", "數聲徹我聽，益養閑適情。", "更覺瓶中梅，於人有餘馨。"]'),
('8387af0f-2c74-482a-8afb-add3ad6bfd71','養魚莊呈余馮二友','韓淲','宋','宋诗','song-poetry','','[]','湖山晴已佳，交遊老逾永。',72,'全唐诗/poet.song.176000.json','["湖山晴已佳，交遊老逾永。", "以茲登臨心，相彼昏旦景。", "風前午方睡，雪後晚猶冷。", "徘徊既良久，放浪亦俄頃。", "花林想鶑聲，水葉亂魚影。", "酒到俱勿辭，詩成獨重省。"]'),
('042c8d08-2ab8-4a02-90dc-178a98683f0d','南屏山看金鯽魚思東坡','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南屏金鯽魚，蘇仙昔嘗觀。',96,'全唐诗/poet.song.176000.json','["南屏金鯽魚，蘇仙昔嘗觀。", "後來臨池人，誰能散餘餐。", "西湖多勝處，見此心獨寬。", "乃知賢達遊，百世留清歡。", "我來秋初晴，凉風動澄瀾。", "洋洋復潑潑，兩兩時單單。", "相彼纖介爾，賞音猶獨難。", "士生天地間，寂寞何足嘆。"]'),
('2ab971ae-9029-4973-a1d5-f4de8469c38d','送潭帥朱晦翁先生赴經筵','韓淲','宋','宋诗','song-poetry','','[]','度江今幾時，恐同元祐初。',168,'全唐诗/poet.song.176000.json','["度江今幾時，恐同元祐初。", "中間一報復，河洛已丘墟。", "先生講金華，此意將何如。", "君子與小人，似難動誅鋤。", "要使各當位，正論常有餘。", "幸哉邊陲靜，羣蠻亦安居。", "大是民力窮，郡邑困軍儲。", "又且士氣弱，虛言多闊疎。", "先生其扶持，行顧平日書。", "西風動召節，帥閫來徐徐。", "經行得古臺，逸攬志愈攄。", "孺子守窮巷，敢負師訓歟。", "殷勤拜席間，別語不暇舒。", "斐然忽成章，先生其念諸。"]'),
('745071be-d939-42ea-87b8-0a3fee9180be','送周次公入浙','韓淲','宋','宋诗','song-poetry','','[]','衝風霜雪繁，澗路少行迹。',132,'全唐诗/poet.song.176000.json','["衝風霜雪繁，澗路少行迹。", "相望一山爾，那知有行役。", "人常畏違離，我懷復難釋。", "歲晚欲晤言，門前尚誰客。", "臨安至山陰，玉室多仙宅。", "酒船尋賀老，才大今詩伯。", "東方諸侯上，千騎森華戟。", "村館足奇士，龍門可奪席。", "優遊何當還，梅花正云白。", "無令詩囊空，但恐酒杯窄。", "斯時定何時，臘月哉生魄。"]'),
('31cf0640-4be2-4b4b-85b3-0b8957e7c63d','送錢清遠','韓淲','宋','宋诗','song-poetry','','[]','出宰清遠縣，且燒清遠香。',48,'全唐诗/poet.song.176000.json','["出宰清遠縣，且燒清遠香。", "斂收平生心，豈謂蠻瘴妨。", "拖舟過高溪，話舊持酒觴。", "雁翔白雲飛，秋思不可忘。"]'),
('35a7e6db-3644-4bc7-a6fa-dd0c5abbb90e','送仲至長樂帥幕','韓淲','宋','宋诗','song-poetry','','[]','文筆擅名第，當置臺館中。',192,'全唐诗/poet.song.176000.json','["文筆擅名第，當置臺館中。", "不合大雅尚，天怒令詩窮。", "昔年弄水亭，一見知不同。", "繼而靈山陽，示我所作工。", "豈期江海上，浩然復相從。", "小篇清且麗，大篇疏而通。", "尚友梅都官，不但楊陸翁。", "和平事淡泊，志意驚盲聾。", "時時寫幾句，豈只凡馬空。", "又喜富收拾，錦繡紛青紅。", "决定得名世，挽回正始風。", "岑岑閩嶺山，連帥鼓角雄。", "幕府少爲貧，因與了事功。", "地煖罕霜雪，榕陰荔枝叢。", "不妨資食啖，閒遊佛老宮。", "萬一遇真隠，識賞無匆匆。"]'),
('905ee0f9-fb59-46f6-a240-ba0a640f17dc','送余子壽暫回上饒','韓淲','宋','宋诗','song-poetry','','[]','尋常五六月，弄泉南澗幽。',108,'全唐诗/poet.song.176000.json','["尋常五六月，弄泉南澗幽。", "微步匝山影，餘凉撫茶甌。", "低回金輦塵，固爲升斗謀。", "雖無啼饑阻，捫腹已白頭。", "汗漿走弊輿，漫刺何所求。", "看君已通籍，合上東觀游。", "弦歌指秣陵，袖手遠急流。", "又乘舶䑲風，嚴灘理還舟。", "寄謝我猿鶴，行藏儘悠悠。"]'),
('4906d0af-b33f-4c71-bd02-4215930543c5','送趙推官衡州','韓淲','宋','宋诗','song-poetry','','[]','著眼塵網外，納身詩社中。',168,'全唐诗/poet.song.176000.json','["著眼塵網外，納身詩社中。", "樂哉萬好庵，劉驥尊酒同。", "此事非外假，千載揚清風。", "冰溪瑞峰高，更是章泉翁。", "永貞志獨礪，探賾雅用充。", "不知羣兒愚，一洗凡馬空。", "祝融石鼓江，舊觀多巨公。", "興懷南渡初，此地驚盲聾。", "只今兩英蕩，遊宦未易逢。", "所惜一未面，舊好本家通。", "盡其我職學，公車自旌弓。", "煌煌太宗業，樹立甚宏雄。", "更願常用賢，更願常和戎。", "官閒莫興寄，因來莫匆匆。"]'),
('59fa6858-9e37-43b7-b41c-6ea506242ef5','送四叔辰州推官','韓淲','宋','宋诗','song-poetry','','[]','離別不作惡，豈是人真情。',144,'全唐诗/poet.song.176000.json','["離別不作惡，豈是人真情。", "作惡既已久，此情何由平。", "昔我少年時，與居多戲爭。", "雖曰諸父行，同隊猶弟兄。", "先公最憐君，訓告尤丁寧。", "豈知十載後，星散各經營。", "往年招真巖，君嘗送我行。", "夜飲不計酒，曉騎馳霜明。", "今我髮漸白，煢然對空觥。", "君乃辰州去，迢迢湘水清。", "一官會自奮，唾手收功名。", "如何還送君，溪頭舟已橫。"]'),
('d901c489-95ad-48e2-9246-218f775e1da8','成季小泊南池將往建昌','韓淲','宋','宋诗','song-poetry','','[]','相望南池上，悠悠我所思。',132,'全唐诗/poet.song.176000.json','["相望南池上，悠悠我所思。", "凌晨理短髮，青鏡滿鬢絲。", "間闊將一年，欣喜纔見之。", "春風旬日爾，又去不在茲。", "人生易爲別，心事多參差。", "有才豈能閒，君達信無疑。", "爲我謝知舊，所困非衰遲。", "尚于吟諷間，暢敘一伸眉。", "若懷平昔交，同里今是誰。", "立丘眇何地，章泉遠莫追。", "山風吹雪雲，歲月密推移。"]'),
('37cb1e59-dfc0-491a-8064-666abe90792c','送吳推官','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','執友曹器遠，高才步瑶京。',192,'全唐诗/poet.song.176000.json','["執友曹器遠，高才步瑶京。", "許予非詞伯，隻字罔敢輕。", "因君官玉溪，乃曰能詩聲。", "夢寐於蘇黄，處家義利明。", "尺書既宛轉，滿紙仍丁寧。", "自是得往還，吟邊亦飛觥。", "苦值公事勞，無暇詳考評。", "但知醉言舞，談諧到忘形。", "忽焉秩滿歸，歲月流電經。", "懷抱信舒卷，物態何枯榮。", "新凉起風檣，石淺灘瀨清。", "推蓬試躊躇，正爾候蟲鳴。", "行行錢塘湖，悠哉故人情。", "器遠如相忘，爲說華髮生。", "君之趙子野，惜未同鷗盟。", "所賦定益奇，南北兩山橫。"]'),
('26ab9146-8335-4213-8522-2a2a850da3ac','送王景育弋陽尉官滿入吳','韓淲','宋','宋诗','song-poetry','','[]','天下之好事，不我則彼爲。',144,'全唐诗/poet.song.176000.json','["天下之好事，不我則彼爲。", "何必獨我出，然後爲得時。", "但恐才學短，講論日以卑。", "豈止身非賢，君民何所宜。", "我雖無用處，連蹇於茅茨。", "所幸眼未昏，英妙見于斯。", "君學既不器，君才復不羈。", "一尉已三年，東上不可遲。", "國家仁德深，丕冒及四夷。", "中間臺閣尊，政事多臯夔。", "拔茅果彙征，四夷易鞭笞。", "薰兮方南風，聽我歌此詩。"]'),
('a1cb77f6-9dca-44fe-80a1-fe6e4de4b832','送子壽入吳改秩','韓淲','宋','宋诗','song-poetry','','[]','昔也壽皇時，蓋以戰而守。',156,'全唐诗/poet.song.176000.json','["昔也壽皇時，蓋以戰而守。", "强敵難得志，和書驛使走。", "持循四十年，罔敢爲戎首。", "世道倏升降，甲兵忽在手。", "輕舉將畧疎，彼彊反歸咎。", "遂令北伐篇，小大皆滅口。", "不憚累金繒，祇願和好久。", "廟算屬仁賢，尊事貴黄耈。", "祖宗締創深，施澤等高厚。", "朝班上青瑣，憂國合細剖。", "行行遠家林，寒露濕蕪柳。", "無惡夸毗兒，無哂拓落叟。", "何須莫吟詩，何須力飲酒。"]'),
('e8cc7a7f-c9eb-466c-b320-8d3e109a37eb','送舒同安監暫回上饒','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','秋入玉山靜，羨君乘歸軒。',108,'全唐诗/poet.song.176000.json','["秋入玉山靜，羨君乘歸軒。", "曉凉紅蓼渡，晚晴黄葉村。", "兒女羅酒漿，歡呼爭候門。", "家人有真情，巷黨無雜言。", "豈不念別久，三年在真源。", "幸從帝里回，有命須騰騫。", "嬉遊且卒歲，餘事不足論。", "予方仰寸祿，日日思故園。", "西湖雖云樂，而多車馬喧。"]'),
('6147a69c-22f0-4e23-897a-93018acc4805','送昭武蔡倅','韓淲','宋','宋诗','song-poetry','','[]','春陰生曉寒，澗空雨冥冥。',132,'全唐诗/poet.song.176000.json','["春陰生曉寒，澗空雨冥冥。", "草迷側徑滑，車馬誰肯經。", "敲門有嘉客，故家駕屏星。", "道舊相□□，百年之典刑。", "昔我伯祖翁，忠惠與齊齡。", "契不減歐陽，驟語人解聽。", "昭武六百石，便當歸明廷。", "至今弦歌地，玉水流餘馨。", "君侯真不凡，山峙而淵渟。", "盤盤龜曳尾，昂昂鶴梳翎。", "東風吹眼明，倏然如酒醒。"]'),
('b9bacc44-6c60-4797-8391-ac927064e109','送八歌歸寓里','韓淲','宋','宋诗','song-poetry','','[]','我覺日已老，夢寐思故山。',120,'全唐诗/poet.song.176000.json','["我覺日已老，夢寐思故山。", "故山修竹多，春流正潺湲。", "喜汝調官歸，尚得年歲閒。", "爲我守墳墓，經理田舍間。", "四時溫飽外，尋幽可怡顔。", "出入更擇友，勢利常懷姦。", "因風頻寄書，慰此雙鬢斑。", "潮橫漁浦渡，水滿龍山灣。", "離眼望征棹，形滯心已還。", "誰憐輦轂吏，青衫裹癡頑。"]'),
('8d3956d7-a9a4-4b92-903e-f385be9705b4','送黄監稅之官沙縣','韓淲','宋','宋诗','song-poetry','','[]','國家右文時，子可謂不遇。',108,'全唐诗/poet.song.176000.json','["國家右文時，子可謂不遇。", "相從今幾年，猶記弄章句。", "神州久陸沉，赤子欲誰訴。", "隆興淳熙初，幾載駕戎輅。", "主聖難其臣，後來忽多故。", "方今恢天運，子復策仕路。", "惜乎視征榷，韜畧未闊步。", "男子志四方，周王亦一怒。", "慘別無它言，閩山眇回互。"]'),
('0ec4bfce-b9dd-4793-93ed-212042e91d39','送致道','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','君家兄弟賢，四海得師友。',96,'全唐诗/poet.song.176000.json','["君家兄弟賢，四海得師友。", "卜居赤城霞，山水照戶牖。", "宗盟懶致身，時務能袖手。", "紛綸五經笥，聖處端不朽。", "每切鄉往之，喜從仲氏後。", "青春錢塘湖，僅爾一杯酒。", "微吟已相和，要論合深扣。", "調官復東還，知我離索否。"]'),
('aa85502c-957e-4225-b798-ff50487d1f85','送行甫','韓淲','宋','宋诗','song-poetry','','["\u592a\u6e56"]','師門講絕學，淡泊易荆榛。',84,'全唐诗/poet.song.176000.json','["師門講絕學，淡泊易荆榛。", "錙銖利害牽，不暇能親仁。", "君侯志意高，面無三斗塵。", "越從武夷來，邂逅京華春。", "抵掌顧我談，文彩天麒麟。", "歸哉吳閶門，太湖漾無垠。", "修名恐不立，何必問屈伸。"]'),
('b068f3c5-7db6-4d99-aa9d-e7bca884731a','送曾甥八三哥','韓淲','宋','宋诗','song-poetry','','[]','文家渺江海，事物隘天地。',96,'全唐诗/poet.song.176000.json','["文家渺江海，事物隘天地。", "不患寡所識，要在索其至。", "聖賢力已到，螟蜾世名利。", "堂堂一唯翁，守約妙洙泗。", "眷言汝少年，趣向已知意。", "相從匝寒暑，愧我有事累。", "歸舟江風急，惜別重增喟。", "約己能自修，它年幸相記。"]'),
('858850a5-ee85-46cb-b085-2b28a33d7922','送敬之','韓淲','宋','宋诗','song-poetry','','[]','一笑招真巖，屈指如昨日。',132,'全唐诗/poet.song.176000.json','["一笑招真巖，屈指如昨日。", "梅雨打溪船，回路頓蕭瑟。", "豈知數載後，相逢仕塗出。", "復是暮春時，薰風轉呂律。", "武夷山甚高，千丈聳崷嵂。", "昧者信誰知，見者多自失。", "名父難爲子，世論莫深詰。", "要使學力健，用則定爵秩。", "我亦理征帆，相將坐林密。", "先乃送君歸，斑衣入堂室。", "從容奉親歡，豈但文度膝。"]'),
('a8405488-9deb-4845-87d0-2cca91be6975','送子應丈兼懷元默兄','韓淲','宋','宋诗','song-poetry','','[]','去年風雪夜，高樓醉題詩。',96,'全唐诗/poet.song.176000.json','["去年風雪夜，高樓醉題詩。", "今年風露秋，把酒看木犀。", "懷人在何許，分教大江西。", "掩關正愁予，公來殊好奇。", "故交非不多，那有此襟期。", "徘徊僅三日，歸舟又前溪。", "凄凄木葉飛，荒山夜猿啼。", "公住無庸歸，人生休別離。"]'),
('b2b3c751-2a6d-4ee3-bf06-a63eb570980c','送周叔謹','韓淲','宋','宋诗','song-poetry','','[]','學行世所稀，到眼發孤咏。',120,'全唐诗/poet.song.176000.json','["學行世所稀，到眼發孤咏。", "聞君欲高卧，當不與物競。", "師從既名德，朋友且多令。", "堂堂麗澤公，沉潛率理性。", "武夷老仙伯，辯析至於命。", "願言融液之，此意千載盛。", "相逢復相別，一進當一慶。", "波流易蕩委，山立要持正。", "剡中山水窟，眼界可便靜。", "因風時寄音，各各藥其病。"]'),
('91a82cec-6b56-4aeb-8bb4-b52ad6727d1e','送王安行','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖非不佳，草木已變衰。',96,'全唐诗/poet.song.176000.json','["西湖非不佳，草木已變衰。", "芙蓉花雖紅，奈逼清霜時。", "昔見决科日，春酣桃杏枝。", "今從秣陵來，我乃官于茲。", "紛紛許史家，悠悠王謝兒。", "吾儕撫書劍，百事胡能知。", "蕪湖連大江，風煙蕩灣碕。", "子歸但飲酒，可逭寒與饑。"]'),
('b631da59-e164-4471-9896-6318e85be93a','送魏兄','韓淲','宋','宋诗','song-poetry','','[]','霜空愛日起，林葉翻階鳴。',48,'全唐诗/poet.song.176000.json','["霜空愛日起，林葉翻階鳴。", "藹藹故人意，依依遊子情。", "臨離一杯酒，遠作數宿程。", "聞詩佚老堂，寄言寸心傾。"]'),
('acac3ced-30d9-4bf0-8b87-1f160de9dc79','重送仲至聞得祠','韓淲','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','殘春叫鶗鴂，百草爲不芳。',120,'全唐诗/poet.song.176000.json','["殘春叫鶗鴂，百草爲不芳。", "錢塘江漲沙，往往變田桑。", "一風或十雨，冷煖殊未嘗。", "起視天宇高，俛知人世長。", "俄而登大樓，老面各已蒼。", "慨予復何言，忘却離思傷。", "振衣問荒野，稅駕辭康莊。", "細收篋裏詩，盡秘囊中方。", "山堂有故園，絕出名利場。", "頤神以養壽，更炷琳宮香。"]'),
('99152cb3-34c8-41af-a2a6-54b297f450c1','王教授將考試它州偶得五字送之','韓淲','宋','宋诗','song-poetry','','[]','常年寡游從，所值必名勝。',144,'全唐诗/poet.song.176000.json','["常年寡游從，所值必名勝。", "歷談或忘言，分袂每敗興。", "旁觀固多賢，此唱彼不應。", "十手競譏笑，薰蕕亦其稱。", "豈謂落市朝，失馬同墮甑。", "棲遲理舊廬，竹几得深凭。", "君侯意有餘，能來步幽磴。", "譬如須陀洹，果位當自證。", "可無一言要，開我所愚懜。", "相看檄司文，何由駐征鐙。", "無酒信云乏，有酒又若剩。", "積雨凉氣新，老病眼空瞪。"]'),
('e8cdae87-4f13-4b0a-af0e-584be5a7f930','載酒送昌甫至十許里分韵得送字','韓淲','宋','宋诗','song-poetry','','[]','翁歸章泉山，我以一尊送。',72,'全唐诗/poet.song.176000.json','["翁歸章泉山，我以一尊送。", "荒流忽逢梅，孤峭費嘲弄。", "情親闊別去，旋即墮幽夢。", "風生千樹春，寒入萬木凍。", "杯行二三子，醉語或驚衆。", "歲晚夫如何，塵外無倥傯。"]'),
('142dd6f6-498d-4aab-b994-2d538b30550b','送彭世昌回自武夷','韓淲','宋','宋诗','song-poetry','','[]','愚聞象山翁，雄辯欲明道。',120,'全唐诗/poet.song.176000.json','["愚聞象山翁，雄辯欲明道。", "君嘗升其堂，叩擊務深造。", "晚開山水窟，謂此可忘老。", "從容能幾何，翁已終壽考。", "遺文力披尋，古制資探討。", "想君念師門，沒世耿懷抱。", "近從武夷伯，舊話益可考。", "豈惟翁所親，蓋自世之寶。", "歸來過玉溪，惜別爲傾倒。", "樂地無古今，春風動花草。"]'),
('6cb27054-8580-4f85-8e92-7cf82771c8f2','送十哥歸宣城','韓淲','宋','宋诗','song-poetry','','[]','送子歸何許，家在宛水邊。',96,'全唐诗/poet.song.176000.json','["送子歸何許，家在宛水邊。", "相看敬亭在，鳳凰應相連。", "松楸鬰已拱，我老心凄然。", "乃祖儒業盛，爾父還能賢。", "汝復舉進士，筆勢方翩翩。", "六年北闕場，一笑兩周旋。", "道舊感存沒，離懷偶成篇。", "功名有康莊，少壯宜加鞭。"]'),
('4440916a-210f-44c0-a3c9-a377c91bf8c1','送胡教授秩滿東歸','韓淲','宋','宋诗','song-poetry','','[]','煙塵暗江淮，風雪到溪澗。',96,'全唐诗/poet.song.176000.json','["煙塵暗江淮，風雪到溪澗。", "交遊人復去，荏苒歲云晏。", "山空歸飛鴉，洲靜起宿鴈。", "浮生貴壯圖，流俗厭末宦。", "相期豈輕肥，自笑祇藜莧。", "三年疏數中，一旦遠近間。", "老身要長健，他事誠易辦。", "升沉由遇合，出處付譏訕。"]'),
('9b89f27d-0cf8-421e-85be-f4f45bd7e416','送鄭元老教授衡州','韓淲','宋','宋诗','song-poetry','','["\u8861\u5c71"]','三代之學廢，專門競成家。',240,'全唐诗/poet.song.176000.json','["三代之學廢，專門競成家。", "經隔千百年，孔廟徒奢誇。", "我朝跨兩漢，斯文惟有涯。", "天下書院中，賜書幾五車。", "石鼓亦佳處，湘流带長沙。", "衡山爲其衝，南國無以加。", "猗與慶曆盛，風化浹邇遐。", "州縣俱養士，開設始足嘉。", "或困舉子習，沉思實堪嗟。", "公卿比塗出，歆艷孰敢譁。", "淳熙二三賢，使節連帥牙。", "葺彼舊遺事，丘記鎮淫哇。", "青春復來守，講道方萌芽。", "古意忽不嗣，政治由隆汙。", "只今數間屋，定知未傾斜。", "如君肯交我，分教且及瓜。", "杳渺上重湖，霜風動梅花。", "它鄉莫迴首，空使望眼賒。", "歲月信逾速，人事紛攫拏。", "勉勉儷前修，無繆毫釐差。"]'),
('d8bc5802-1a51-4d7d-9335-edb3fd59d5ec','送臨江時教授秩滿還婺兼寄鞏戴','韓淲','宋','宋诗','song-poetry','','[]','豈無戴在伯，亦有鞏仲至。',192,'全唐诗/poet.song.176000.json','["豈無戴在伯，亦有鞏仲至。", "兩賢夙所尚，離懷想憔悴。", "吁嗟同窗錄，英彥非一二。", "或富於詞章，或窮於道義。", "因君肯相過，重之寫吾記。", "浮楊清江柁，乃泊高溪地。", "停橈倚薰風，班荆坐蕭寺。", "匆匆復何言，但念宿昔事。", "金華紫崔嵬，少小得嬉戲。", "星回三十載，前哲日凋墜。", "傳聞築新祠，翻覆堪涕泗。", "只今臺閣尊，源流庶可嗣。", "君之內婣親，伯長最風誼。", "還鄉一杯酒，多謝熟致意。", "朝廷已更化，賢者必征彙。", "速下七里灘，得時須得位。"]'),
('48a69f27-fd76-4ad6-a65d-02a50c405e03','送余制幹赴四明','韓淲','宋','宋诗','song-poetry','','[]','鯨波環甬東，生犀駕鰍船。',108,'全唐诗/poet.song.176000.json','["鯨波環甬東，生犀駕鰍船。", "戈旗耀玄甲，聲震登萊邊。", "運柁指河洛，連檣擣幽燕。", "中堅有宗臣，重望推世賢。", "神機贊廟謀，天授黄石編。", "青春策名勳，幕府當慨然。", "英英臺閣姿，秉羽寧拘攣。", "賈勇出緒餘，一舉四海全。", "雲帆萬里風，杕杜歌勞還。"]'),
('3f9b4140-ab97-4cd3-8527-ac40e2301e44','初八日送章丘赴省','韓淲','宋','宋诗','song-poetry','','[]','國家翰墨場，用是得多士。',120,'全唐诗/poet.song.176000.json','["國家翰墨場，用是得多士。", "公卿才大夫，大抵每藉此。", "其如老伏波，非但一第爾。", "衆俊路方闢，天地亦清美。", "洋洋乃大對，聞者爲興起。", "冠冕鳴佩玉，鋒鏑櫜弓矢。", "成康庶幾及，武宣不必擬。", "目今有輿言，萬古有載史。", "我來見君行，榮名可以喜。", "闊步隨春風，東華軟紅裏。"]'),
('fc044567-4351-446a-abe9-83d056c30079','送徐斯遠從施樞帥隆興','韓淲','宋','宋诗','song-poetry','','[]','暮春雨乍歇，新晴綠陰生。',96,'全唐诗/poet.song.176000.json','["暮春雨乍歇，新晴綠陰生。", "啼鳥集幽聽，殘花愜閒情。", "惻愴百慮感，良友倏告行。", "牽衣坐已久，欲語聲不鳴。", "東湖波浩蕩，孺子名與清。", "今古信同調，下榻人自驚。", "公貧良可療，我志還當平。", "臨觴毋重辭，公亦爲我傾。"]'),
('89824c7f-572f-47aa-af40-20c28fdb9ba4','趙履常入建陽  其一','韓淲','宋','宋诗','song-poetry','','[]','文行士所貴，世或鮮知道。',72,'全唐诗/poet.song.176000.json','["文行士所貴，世或鮮知道。", "道通天地人，斯足爲我寶。", "文高多外馳，行實徒自保。", "意誠而動化，豈不在深造。", "其間有徑庭，一一宜探討。", "探討自得之，樂哉可忘老。"]'),
('a723695a-4204-4328-8774-53bad1caeb1d','趙履常入建陽  其二','韓淲','宋','宋诗','song-poetry','','[]','俗眼無特見，多以形似非。',72,'全唐诗/poet.song.176000.json','["俗眼無特見，多以形似非。", "波流一蕩靡，莽然渾無依。", "豈不有天才，又思衆所譏。", "蹉跎度歲月，竟作淺陋歸。", "隨世得富貴，事業徒纖微。", "偉哉六經書，聖賢所發揮。"]'),
('281700af-25c9-4db9-9029-c7cdab6f1e84','留永豐數日告歸偶成五字別文叔','韓淲','宋','宋诗','song-poetry','','[]','金飈肅商聲，皓魄麗清景。',132,'全唐诗/poet.song.176000.json','["金飈肅商聲，皓魄麗清景。", "思子淚成河，觸目意莫騁。", "故人有嘉招，庸敢憚造請。", "行行涉大川，往往度崇嶺。", "一登君子堂，彌旬獲規儆。", "小飲興頗濃，共學議尤炳。", "章泉來詩翁，此話亦雋永。", "人生長暌疎，聚集每俄頃。", "興言故山歸，旱暵憂復耿。", "此處雖未同，可昧寸心冏。", "世塗紛愛憎，吾儒挈裘領。"]'),
('8137196d-3d6a-491e-aada-447421e5b436','別斯遠','韓淲','宋','宋诗','song-poetry','','[]','卜居得幽曠，崇山倚長松。',84,'全唐诗/poet.song.176000.json','["卜居得幽曠，崇山倚長松。", "夜窗風雨來，歲事忽已冬。", "人或知子歟，我身爲從容。", "此閒豈有待，彼忙竟何逢。", "徒以蝸角微，展轉纏心胸。", "栽田藝禾黍，伏臘可粗供。", "功名不難辦，肉食皆鼎鍾。"]'),
('1be6cff3-9c50-44d1-bf1c-c7808e3572c3','別元默','韓淲','宋','宋诗','song-poetry','','[]','初不畏離別，亦不愛過從。',96,'全唐诗/poet.song.176000.json','["初不畏離別，亦不愛過從。", "周遊老江浙，風雪還窮冬。", "君侯故家秀，雅步非凡蹤。", "鳴絃寄真尚，萬古開心胸。", "胡爲憐我懶，縱論容愚憃。", "留連一再旬，欲去寒意濃。", "當知思齊賢，出處誠難逢。", "草木凍欲折，冬嶺惟孤松。"]'),
('532e2480-3685-45a6-9ab7-7b177174a88f','行甫載酒爲別','韓淲','宋','宋诗','song-poetry','','[]','霜天出晴日，山外看煙霏。',48,'全唐诗/poet.song.176000.json','["霜天出晴日，山外看煙霏。", "長松覆蘭若，酌我何當歸。", "人情令飄灑，世路徒依違。", "景曠詩自成，一觴還屢揮。"]'),
('baf94ccc-2357-4b92-b662-0eff97ae08c7','余子任訪章泉','韓淲','宋','宋诗','song-poetry','','[]','章泉天下翁，之子能幽尋。',168,'全唐诗/poet.song.176000.json','["章泉天下翁，之子能幽尋。", "謀道不謀利，耿耿秉此心。", "薰風四月凉，苔竹芾而森。", "恨我不嗣往，空多華髮侵。", "年來翁示疾，豈在藥石針。", "衆生煩惱盡，病苦當不深。", "慨焉紹興初，上饒聚纓簪。", "東萊曾空青，至今朱絃琴。", "零落一丘壠，佳話轉平沉。", "翁實獨遠紹，文獻所酌斟。", "詩乃其緒餘，歛收日行吟。", "子歸趣益勝，復逼我家林。", "清陰佇延賞，抵掌橫素襟。", "渺渺兮予懷，慎旃宜重欽。"]'),
('d14f7ce1-931d-479c-a64b-5bd669a3931a','送僧上懷玉','韓淲','宋','宋诗','song-poetry','','[]','渺渺楓樹秋，送僧上懷玉。',48,'全唐诗/poet.song.176000.json','["渺渺楓樹秋，送僧上懷玉。", "白雲度絕巘，清寒滿深谷。", "杖頭掛蘿薜，笠外見鴻鵠。", "却笑懶殘隘，隨緣受榮辱。"]'),
('2f100fd2-f432-4547-8d44-2cf34e41c36f','文叔爲糧料不月日求去作真州守','韓淲','宋','宋诗','song-poetry','','[]','杜老有新語，人生五馬貴。',96,'全唐诗/poet.song.176000.json','["杜老有新語，人生五馬貴。", "儀真亦不惡，溫飽可自慰。", "名宦百年爾，漸覺誠鮮味。", "才歸鵷鷺行，勇去復何謂。", "豈念師旅餘，淮民短生氣。", "瘡痍嘗撫摩，坐視或噓欷。", "挺身收左符，於此見洪毅。", "我爲一長吟，雅志其髣髴。"]'),
('19bc3cc0-0786-4134-8453-e789295204aa','宋倅告老得請而歸','韓淲','宋','宋诗','song-poetry','','[]','挂冠歸海嶠，樟坡可高亭。',240,'全唐诗/poet.song.176000.json','["挂冠歸海嶠，樟坡可高亭。", "無愧邴曼容，如疏傅漢廷。", "廣平心鐵石，大雅非蠅營。", "靈山玉溪波，二年驚屏星。", "澹然每無競，舉足皆典刑。", "宦情隨牒移，蜀莊以沉冥。", "從他俗態度，衆醉惟獨醒。", "黄鍾鳴瓦釜，螭龍爲蝘蜓。", "衰容固兒戲，白眼孰肯青。", "吾儕安處順，抵掌即忘形。", "幽絕有烟霞，荒野多林坰。", "春澤可巾車，秋水可揚舲。", "耳畔震風雨，澒洞飛雷霆。", "黜陟既不聞，奚暇分渭涇。", "咄哉市朝子，車馬弗肯停。", "翻覆五鼎亨，葅醢而膻腥。", "歛收四方志，保息存黄庭。", "鷦鷯棲枝足，鵬運空南溟。", "我家澗谷底，公常念伶俜。", "祖帳爲長歌，乾坤本清寧。"]'),
('e23ce869-3ee3-4a43-88a2-28f5d55db61b','贈劉叔驥縣尉苕溪家也','韓淲','宋','宋诗','song-poetry','','[]','西風苕水清，春日卞山橫。',120,'全唐诗/poet.song.176000.json','["西風苕水清，春日卞山橫。", "莫問桃花紅，但說蓴菜生。", "騷人居是間，俛仰得其情。", "公家文章家，三世蜚英聲。", "爲予父子交，豈特青眼明。", "凄凉四十年，道舊誰復聽。", "只今冰溪水，流波照空城。", "公來坐澗谷，忍聞千載名。", "世道日澆僞，出語皆可驚。", "東望章泉山，尚足堅此盟。"]'),
('b93ae0fd-e5d6-448b-8a5b-eb061b592781','趙十讀通鑑有詩和韵贈之','韓淲','宋','宋诗','song-poetry','','[]','胸蟠萬卷富，莫受半點塵。',132,'全唐诗/poet.song.176000.json','["胸蟠萬卷富，莫受半點塵。", "治道雜朱紫，聖塗纏荆榛。", "誰將十七史，一筆能具陳。", "論說兼軻雄，紀載由周秦。", "首明禮與分，世變損益因。", "裕陵錫序尊，惟恐書易淪。", "後學今如何，識治宜蔚彬。", "區區李唐臣，魏陸猶言仁。", "南北固分合，夷夏寧屈伸。", "往哉涑水翁，元祐第一人。", "帝謂勝荀悅，我生豈不辰。"]'),
('9eb3f011-c4b7-4085-a59d-67e83e9db37c','呈周南仲推官併呈滕計度賢良','韓淲','宋','宋诗','song-poetry','','[]','老身泛吳淞，但覺靈岩高。',96,'全唐诗/poet.song.176000.json','["老身泛吳淞，但覺靈岩高。", "東風吹桃花，水流亦滔滔。", "豈不可揚舲，豈不可受篙。", "閒情未舒適，世慮非煎熬。", "奇哉又虎丘，眄焉首重搔。", "所愧塵埃人，周遊鮮此遭。", "景勝當領會，識淺泛鬰陶。", "只有歌永言，聊以相作勞。"]'),
('bf4af945-9d72-4309-a56d-4d2bbdb2db8b','贈潘德久舍人','韓淲','宋','宋诗','song-poetry','','[]','閒常喜哦詩，逢君了無句。',240,'全唐诗/poet.song.176000.json','["閒常喜哦詩，逢君了無句。", "豈不有所思，蓋噤莫敢吐。", "朅來吳山頭，汩沒時日度。", "悠悠衆交情，往往半親故。", "積陰盛暑寒，棲遲一筦庫。", "君侯謫仙人，邂逅辱雅顧。", "杯行閲新編，指點盡韶濩。", "不謂正始餘，得此諸老趣。", "慇懃復招喚，傾倒所藏聚。", "法書多海岳，掛壁徧毫素。", "中間出娉婷，清聲彩雲駐。", "倒指不數人，百年幾相遇。", "昨朝高軒過，隘巷亦驚謼。", "甆甌茗葉煎，石鼎柏子炷。", "幽窗坐談久，不覺晚橫霧。", "感君厚意長，因之寫欣慕。", "工夫未平夷，漫以懷抱賦。", "轉庵法眼正，逢場到朝路。", "終當入林密，共結茅屋住。", "安心參活法，一滌塵土污。"]'),
('31def036-53b4-46c7-ad35-1b30e5cf774f','贈孫尉','韓淲','宋','宋诗','song-poetry','','[]','人生貴相親，風味入杯酒。',108,'全唐诗/poet.song.176000.json','["人生貴相親，風味入杯酒。", "不在識面早，嘯歌而握手。", "樂哉唱酬富，且復知取友。", "茫茫江湖道，屈指誰耐久。", "吾行古贊州，溪山照窗牖。", "是中得雅士，意氣何深厚。", "便合置青瑣，誰云尚墨綬。", "隠吏有子真，相望千載後。", "凍雨古道長，微茫濕枯柳。"]'),
('c4fd4cbc-3f01-4daf-bcbb-63f2cfe966ed','贈趙景伯','韓淲','宋','宋诗','song-poetry','','[]','蜀道一琴鶴，高齋二百年。',204,'全唐诗/poet.song.176000.json','["蜀道一琴鶴，高齋二百年。", "中原之文物，諫疏慶曆傳。", "政塗竟以歸，虛白更安禪。", "嗚呼清風長，不與時俗遷。", "每行大夫墟，躊躇倍依然。", "或逢其耳孫，此意庶可宣。", "敢論家世舊，豈但婣戚聯。", "只今我衰微，青衫空裹纏。", "憂家復憂國，和戰何其偏。", "世臣匪喬木，休戚實共焉。", "君從鄭莊來，邂逅驚四筵。", "到我南溪上，訪我南澗邊。", "飲我一兩杯，和我三四篇。", "扶摇手中筆，湛如朱絲絃。", "公侯必復始，愛直爾青氈。", "要知先賢後，瓜瓞自緜緜。", "子産晉叔向，信矣仇池仙。"]'),
('d8bf2af5-352d-4719-a854-9fa68986273c','贈斯遠','韓淲','宋','宋诗','song-poetry','','[]','一自離城府，經年欲從遊。',96,'全唐诗/poet.song.176000.json','["一自離城府，經年欲從遊。", "豈曰秋氣高，粲然在林丘。", "酒熟未易飲，詩好未易酬。", "幽窗展席地，宛轉十日留。", "才如不羈馬，胸次貫九流。", "籋雲有霄漢，跼蹐不足憂。", "駕言驪駒歌，散處非阻修。", "鴻鴈天南飛，時當寄綢繆。"]'),
('ee7790bb-0f84-454c-8e75-eb53e26ab9d0','贈李孟達審計','韓淲','宋','宋诗','song-poetry','','[]','敬亭不可見，得見敬亭人。',72,'全唐诗/poet.song.176000.json','["敬亭不可見，得見敬亭人。", "寂寂紅塵裏，長安風日春。", "人生易爲感，華髮倏已新。", "從容一撫几，圖書正橫陳。", "臭味有美惡，風俗多澆淳。", "飄然湖海身，欲去還逡巡。"]'),
('94f8343f-24ab-4157-b0dd-0f2f22daa2dc','贈孔唐叟','韓淲','宋','宋诗','song-poetry','','[]','雲璈飲霞醖，時乘震初爻。',60,'全唐诗/poet.song.176000.json','["雲璈飲霞醖，時乘震初爻。", "潛天與孔聖，靜俟乾坤交。", "誰云星壇虛，可以共默朝。", "我爾一片合，雅俗非淳澆。", "御氣凌罡風，月暈意已消。"]'),
('3ccd97c3-33a4-45fb-98f4-5cccc7f81f88','柬仲至帑轄蹈中理丞','韓淲','宋','宋诗','song-poetry','','[]','三吳一都會，駕言舒我憂。',156,'全唐诗/poet.song.176000.json','["三吳一都會，駕言舒我憂。", "洞門儼彫戟，通術交華輈。", "清晨皇居開，五雲更飛浮。", "陽光從東升，星月爛欲收。", "垂紳奉明主，靡爵班徹侯。", "上擬成康隆，下則臯夔儔。", "弓矢既載櫜，禮樂次第修。", "子惠四海民，庶幾瘡痍瘳。", "眇歟蟣虱臣，守藏獨夷猶。", "交舊未忍遺，乘軒爲綢繆。", "適歌慨以慷，魯酒獻且酬。", "徂年倏已冬，禿髮不滿頭。", "如知山澤臞，昧昧徒好修。"]'),
('df58bbb0-c286-4bcc-b33f-3b82744e4d31','施教授到官兩載  其一','韓淲','宋','宋诗','song-poetry','','[]','雖爲三年淹，已有兩載速。',48,'全唐诗/poet.song.176000.json','["雖爲三年淹，已有兩載速。", "良晤不易逢，幽魂恐難續。", "青山照孤城，流水在空谷。", "忘機在白鷗，勿笑牽黄犢。"]'),
('74ede519-826b-4efc-8bca-7566be50221e','施教授到官兩載  其二','韓淲','宋','宋诗','song-poetry','','[]','青青水中芹，泮渙而樂羣。',48,'全唐诗/poet.song.176000.json','["青青水中芹，泮渙而樂羣。", "亦豈無他人，亦豈不在君。", "海嶠富術業，江湖稀見聞。", "其間名世者，餘子信紛紛。"]'),
('1473fd11-8431-4193-bf7e-994c9d9d8a7d','贈趙十有懷其兄','韓淲','宋','宋诗','song-poetry','','[]','伯氏心軒渠，其跡則隠耀。',60,'全唐诗/poet.song.176000.json','["伯氏心軒渠，其跡則隠耀。", "仲氏跡迴翔，其心則顯道。", "心跡亙乾坤，學力貴閫奧。", "吾非六十化，事物豈至到。", "宿簡流緒長，家國治誰告。"]'),
('047ff846-1641-4d8a-b957-4a3f611beb0d','呈昌甫斯遠','韓淲','宋','宋诗','song-poetry','','[]','二力扶輿去，荒尋何所之。',48,'全唐诗/poet.song.176000.json','["二力扶輿去，荒尋何所之。", "章丘菊已花，章泉梅欲枝。", "孰不有先友，我乃得舊知。", "塵鞅懶復整，且分魚計詩。"]'),
('72934d6d-8ae0-492f-a010-2d424a04f42b','寄胡桐廬','韓淲','宋','宋诗','song-poetry','','[]','西望子陵瀨，東下是漁浦。',72,'全唐诗/poet.song.176000.json','["西望子陵瀨，東下是漁浦。", "明明弦歌人，儒心正勞撫。", "豈無讀書林，松竹護庭宇。", "蓬萊歸路近，此去天尺五。", "不妨興寄深，霞佩整紳組。", "雪滿桐君山，桐仙照千古。"]'),
('050da415-8794-48ca-af99-c525f00be1f8','寄斯遠','韓淲','宋','宋诗','song-poetry','','[]','春風滿村塢，想見高人廬。',96,'全唐诗/poet.song.176000.json','["春風滿村塢，想見高人廬。", "示疾喜復愈，燕處當晏如。", "曉窗咏羲皇，午枕夢華胥。", "神彩一返元，意氣還凌虛。", "吾方入深山，囂塵厭城居。", "飛鳴侶禽鳥，上下看猿狙。", "澗飲無不足，木食還有餘。", "未得相勞苦，題詩寄勸渠。"]'),
('5ec19756-dced-419b-adce-173dc525f211','傚王靈溪詩寄文叔','韓淲','宋','宋诗','song-poetry','','[]','春風入湖團，暑雨來章泉。',48,'全唐诗/poet.song.176000.json','["春風入湖團，暑雨來章泉。", "如何越境出，俗吏定不然。", "見賢思樂地，談道明性天。", "遺民忽聞之，喜極爲詩傳。"]'),
('ac5154b3-749c-434d-8a5d-5e3d51907144','斯遠云閒睡醉天下之至樂也約各賦一首寄昌甫  其一','韓淲','宋','宋诗','song-poetry','','[]','卧聽青松吟，起看白雲生。',72,'全唐诗/poet.song.176000.json','["卧聽青松吟，起看白雲生。", "身心兩無累，所至輒暢情。", "豈特夸毗子，往往皆强營。", "淄澠雖異塗，匪利即徇名。", "誰云衡茅下，可以知枯榮。", "縱復逼饑寒，兒僕自春耕。"]'),
('8919d840-5307-40ff-b3ab-da1dfdc5e736','斯遠云閒睡醉天下之至樂也約各賦一首寄昌甫  其二','韓淲','宋','宋诗','song-poetry','','[]','神既不外騖，氣亦當自和。',72,'全唐诗/poet.song.176000.json','["神既不外騖，氣亦當自和。", "松牀薦石枕，偃仰得已多。", "鼻息出入通，呼吸相蕩摩。", "陽光塞天宇，一定消百魔。", "是事非所難，彼愚分奔波。", "曉夕無停晷，耗散歸蹉跎。"]'),
('9f8287ee-ac54-42e7-ae73-e93fec791847','斯遠云閒睡醉天下之至樂也約各賦一首寄昌甫  其三','韓淲','宋','宋诗','song-poetry','','[]','陶陶兀兀裏，渾涵忘所知。',72,'全唐诗/poet.song.176000.json','["陶陶兀兀裏，渾涵忘所知。", "恍如天地初，清濁未剖時。", "人苦前識爾，觸物勞心思。", "棄置便棄置，况此有酒巵。", "一酌入醺酣，重觴到淋漓。", "勿苦事邊幅，醒將何所爲。"]'),
('034fc5e4-69b9-4f06-a7b0-d76e3d71e191','寄秋塘','韓淲','宋','宋诗','song-poetry','','[]','寄語秋塘翁，謝借淵明詩。',156,'全唐诗/poet.song.176000.json','["寄語秋塘翁，謝借淵明詩。", "俄而兩三年，未嘗不誦之。", "翁昔遊錢湖，日日載酒嬉。", "我方坐筦庫，逐勢利奔馳。", "惟恐塵埃多，忘却山水奇。", "所以從翁借，欲公知我爲。", "秋塘夫如何，蒲荷淨漣漪。", "塘上客誰來，寧作宋玉悲。", "胸蟠夜光寒，健筆愈陸離。", "西風一吟諷，萬事都若遺。", "應笑我投閒，猶能詠於斯。", "淵明閉關輩，翁亦老苦錐。", "悵然復歸翁，起我百世思。"]'),
('60c1b41c-0eb7-4cbd-a84e-88112587ed00','孟守寄詩卷於斯遠','韓淲','宋','宋诗','song-poetry','','[]','人言詔節忙，我覺詩卷暇。',48,'全唐诗/poet.song.176000.json','["人言詔節忙，我覺詩卷暇。", "寄之章丘深，何其相慰藉。", "使君真不凡，往往凌鮑謝。", "傳觀俗眼驚，幽懷語寒夜。"]'),
('59418feb-3a9c-4c6f-aeb0-92549339ce25','舟至南豅且寄玉山聘君寺丞二徐丈','韓淲','宋','宋诗','song-poetry','','[]','宿雨起微潦，輕風生早凉。',96,'全唐诗/poet.song.176000.json','["宿雨起微潦，輕風生早凉。", "葉葉一飄蓬，溯浪開晴光。", "沿洄幾年汎，眼熟雲水鄉。", "常苦乏佳伴，無人與成章。", "望望指柏閣，遥遥近溪堂。", "南豅在中沚，停篙且翺翔。", "進棹君未已，爲我達衷腸。", "萬事本如昨，此適不可忘。"]'),
('be052e3b-43c6-4619-8488-8f7b7e8db4b6','寄宋君輔','韓淲','宋','宋诗','song-poetry','','[]','仕則有用舍，學則有舒卷。',156,'全唐诗/poet.song.176000.json','["仕則有用舍，學則有舒卷。", "但願培之深，名宦恐不免。", "范歐久逾新，黄俞近莫辨。", "後先行與靜，信各萬人選。", "自是有犂鉏，自是有軒冕。", "如聞復授徒，鄉里足稱善。", "青青謹對矣，話柄由我轉。", "杳邈天外心，其奈知德鮮。", "興言相逢時，一再僅游衍。", "夜來定何盃，午後亦何臠。", "達生恨弗果，情深話猶淺。", "東家山水窟，氣岸必洪展。", "綠草三逕春，幽光徧苔蘚。"]'),
('9da7be0d-5a5d-4e44-81c7-7cee9b5a594b','寄林教授','韓淲','宋','宋诗','song-poetry','','[]','題詩寄春風，問訊雲間翁。',48,'全唐诗/poet.song.176000.json','["題詩寄春風，問訊雲間翁。", "一月不相見，飄忽花事中。", "棲棲我山林，望望君頖宮。", "斆學游息外，還許知近功。"]'),
('c25e83a1-48cb-4d1b-a896-7082b7f48ac0','聞仲至雪峰有行記有詩擬歐陽體寄之','韓淲','宋','宋诗','song-poetry','','[]','百粵多名山，磅礴甚雄偉。',168,'全唐诗/poet.song.176000.json','["百粵多名山，磅礴甚雄偉。", "城邑所聚落，人物反無幾。", "吾嘗思其然，未嘗不憤悱。", "秀氣鍾洩處，名德當燁煒。", "乃爲仙佛廬，土木儼神鬼。", "其教又皆幻，其徒且不韙。", "無非索民財，聚食類螻螘。", "蓋本僭竊者，盜名恣蛇虺。", "徒欲覬冥福，締建罄箱篚。", "柰何習俗慣，後世尤亹亹。", "君登雪峰寺，逸覽應一唏。", "水石固清激，草木必芳菲。", "豈不念古道，胸次增礧磈。", "聞有記與詩，寄與定瑰瑋。"]'),
('c7d02030-5c7f-4b8a-acf1-d2b482473852','四月八日病中寄昌甫','韓淲','宋','宋诗','song-poetry','','[]','我毒發於腰，君瘡作於背。',48,'全唐诗/poet.song.176000.json','["我毒發於腰，君瘡作於背。", "君痛那可忍，我痛或可退。", "清和清潤時，晴雨在戶外。", "安得如前年，名勝一談會。"]'),
('04a9396f-555a-4558-873d-0622dcc7b0ea','寄文叔合肥令','韓淲','宋','宋诗','song-poetry','','[]','桓伊三弄笛，猶足戰淝水。',180,'全唐诗/poet.song.176000.json','["桓伊三弄笛，猶足戰淝水。", "談笑麾秦兵，所向皆披靡。", "追擊至青岡，堅亦中流矢。", "不經事少年，其壯乃如是。", "宜乎謝東山，喜甚折屐齒。", "只今所城邑，歷代幾遷徙。", "君懷覇王畧，宰邑當念此。", "南北雖堅明，風塵未遽起。", "士豈無奇氣，叱咤有摩壘。", "一從辛巳年，海陵擾北鄙。", "因循再結好，寧不有所俟。", "又三十八載，恐漸忘昔耻。", "吁嗟靖康變，北客思故里。", "君今臨淮垣，訪古欲何似。", "長嘯朔風寒，晉人亦人耳。"]'),
('ef1331f8-5084-4883-bd3f-1061a8b08660','寄趙十履道','韓淲','宋','宋诗','song-poetry','','[]','養疴倦還往，南山卧荒廬。',48,'全唐诗/poet.song.176000.json','["養疴倦還往，南山卧荒廬。", "風簷洒雲雨，急景歲序徂。", "曠焉親知樂，睇望東城隅。", "即事聊自吟，爰寂守玄虛。"]'),
('3e3ac72c-f019-40b3-ad96-4d369917dd41','寄王成叟','韓淲','宋','宋诗','song-poetry','','[]','復從章貢回，滿謂可邂逅。',120,'全唐诗/poet.song.176000.json','["復從章貢回，滿謂可邂逅。", "偶從青巖遊，失此一知舊。", "摩挲所留字，和韵若金奏。", "至今殷遺音，寤寐錯昏晝。", "人生竟何爲，妙處匪聲臭。", "空餘丘壑心，流枕而石潄。", "經年强飯否，安得日相就。", "市廛多犬雞，墟落易豺獸。", "源深則溪清，林迥山必秀。", "緘辭寄春風，思君令人瘦。"]'),
('d5d8efd2-56f0-40d0-aaa0-cd3593725b25','寄朴翁','韓淲','宋','宋诗','song-poetry','','[]','柳下葛徵君，受用得自在。',60,'全唐诗/poet.song.176000.json','["柳下葛徵君，受用得自在。", "宴坐孤山南，湖山自澎湃。", "不受爵服吞，蒙莊大塊噫。", "三年遥相望，妙寄入天籟。", "塵塵與剎剎，超出凈名外。"]'),
('e3d93514-ff79-4eb5-b149-29a47c957c2b','寄和卿丈','韓淲','宋','宋诗','song-poetry','','[]','去年中秋時，同上東大樓。',120,'全唐诗/poet.song.176000.json','["去年中秋時，同上東大樓。", "長風吹綠尊，溪光與雲浮。", "已而適異縣，弔古尋隠幽。", "豈伊邂逅懽，亦足寫我憂。", "嚴霜沍冬日，再會尤綢繆。", "平生無是夢，一旦眼底收。", "祇今孤山下，交遊如故不。", "蕭蕭丹葉飛，憑高眇離愁。", "諸老日凋謝，疇知敬前修。", "夫君從李呂，此意千載休。"]'),
('e5d8cda0-9129-4d47-a40e-156455309e85','寄潘文叔','韓淲','宋','宋诗','song-poetry','','[]','楊子江心水，可以共煮茶。',108,'全唐诗/poet.song.176000.json','["楊子江心水，可以共煮茶。", "鶴林招隠詩，不必問僧家。", "治中今如何，紬被聽報衙。", "去年崑山陽，春岸醉桃花。", "今年玉溪上，蚤忙看繅車。", "相思無賸語，作字只欹斜。", "暑雨障炎日，薰風散餘霞。", "君顔想渥丹，我髮亦已華。", "因詩一嘯吟，塵間事如麻。"]'),
('360efb74-4ea8-4607-b6d7-0668cbb92861','慶元己未二月戊子寄皖山隠翁史虎囊','韓淲','宋','宋诗','song-poetry','','[]','塵世離闊苦，一別易寒暑。',144,'全唐诗/poet.song.176000.json','["塵世離闊苦，一別易寒暑。", "彈指十五年，翁今定何許。", "聞在潛山頭，僧寺有誰語。", "方瞳狎鷗鳥，禿髮照獐鼠。", "蹣跚狹虎囊，借醉忘爾汝。", "平生心所尊，安得伴遊舉。", "我友余伯臯，遠遊復羈旅。", "當爲翁慨然，斗酒氣相與。", "旦夕廣文來，雅趣非凡侶。", "豈不能趨風，擊鮮宰肥羜。", "獨恨海潮邊，戀祿贍兒女。", "悵望春色深，風花暗吳楚。"]'),
('02129c97-2a75-451d-a09c-763cb2ad3a37','懷斯遠','韓淲','宋','宋诗','song-poetry','','[]','晴光雜空雲，青春轉寒谷。',48,'全唐诗/poet.song.176000.json','["晴光雜空雲，青春轉寒谷。", "眇眇兮章丘，所見惟我獨。", "灑然天地間，豈爲萬事足。", "曉風吹詩來，梅枝粲羣玉。"]'),
('fa3cd612-5a0c-48bc-a8ce-f0fbe7f29003','與春伯雩仲道舊','韓淲','宋','宋诗','song-poetry','','[]','八年閒放身，猶許時到門。',48,'全唐诗/poet.song.176000.json','["八年閒放身，猶許時到門。", "潺然一梅陂，湛寂非獨渾。", "坐客與我言，月色雲吐吞。", "是中只可醉，五經無紛綸。"]'),
('64e0dcd4-0fbd-4482-83cc-dd55b7f08d3b','簡趙十諸友  其一','韓淲','宋','宋诗','song-poetry','','[]','摇摇山上風，落落谷中雨。',48,'全唐诗/poet.song.176000.json','["摇摇山上風，落落谷中雨。", "迴谿少鷗鷺，曠野分豺虎。", "荒寒不可聞，慘淡不可睹。", "偪塞案上書，饑來尚堪撫。"]'),
('4d121708-21ba-46af-9cd9-d4915422a4fd','簡趙十諸友  其二','韓淲','宋','宋诗','song-poetry','','[]','門外長安道，轂擊人肩摩。',48,'全唐诗/poet.song.176000.json','["門外長安道，轂擊人肩摩。", "今時不云少，舊年不云多。", "市朝愚智爾，家國隆替何。", "組綬固若若，冠弁亦峩峩。"]'),
('95c11ee5-9601-47e5-bd04-e064562b6eb8','簡趙十諸友  其三','韓淲','宋','宋诗','song-poetry','','[]','臭味薰與蕕，意氣金與石。',48,'全唐诗/poet.song.176000.json','["臭味薰與蕕，意氣金與石。", "惟可以忘年，庶可以忘夕。", "投非膠漆堅，抱有冰炭厄。", "深憐眼終青，未厭髮已白。"]'),
('664f2e26-5c81-4188-98d6-1163135ae19d','乙翁來其父兄家行一年矣甚念之二首','韓淲','宋','宋诗','song-poetry','','[]','環中人所隘，方外我所敬。',48,'全唐诗/poet.song.176000.json','["環中人所隘，方外我所敬。", "世道無它塗，禪林有幽徑。", "煙崖寒自高，霜港晚逾靜。", "投我可忘言，乘閒了深定。"]'),
('02454975-1f7a-432b-9e59-2b8825d1d7cb','喜成季登科','韓淲','宋','宋诗','song-poetry','','[]','一門三昆季，六載兩科名。',156,'全唐诗/poet.song.176000.json','["一門三昆季，六載兩科名。", "士無速化塗，唱第聊代耕。", "或里選舉首，或賢關馳聲。", "落筆便離倫，鼓篋皆中程。", "煌煌藝祖業，中興費經營。", "東南將百年，雜遝幾公卿。", "事業固輝赫，議論時縱橫。", "如君英妙姿，文采玉溪生。", "膴仕既得路，壺酒爲我傾。", "春晴飛殘花，綠葉隨樹成。", "豈無好風景，黄鳥枝上鳴。", "吟亦不必和，醉亦不必醒。", "宿雨喜新漲，浮雲卷虛明。"]'),
('d2f0e98d-79f1-4adc-8d56-d03ae5927080','有懷昌甫','韓淲','宋','宋诗','song-poetry','','[]','三家我故舊，一士我久要。',72,'全唐诗/poet.song.176000.json','["三家我故舊，一士我久要。", "新冬過溪澗，山寒風葉飄。", "老眼爲之開，聊以永今朝。", "浮華眩鐘鼎，灑落忘簞瓢。", "古誼不勝俗，歲寒松後凋。", "共話詩翁歸，章泉如雲霄。"]'),
('5e13dba2-e476-4196-bed6-c8f818ffd80b','喜趙昌甫姪三哥登科','韓淲','宋','宋诗','song-poetry','','[]','我祖紹聖初，蓋亦登名第。',168,'全唐诗/poet.song.176000.json','["我祖紹聖初，蓋亦登名第。", "君家龍圖公，實托同年契。", "豈知渡江久，遊宦各零替。", "低頭藉世祿，悵望月中桂。", "宜爲俗輩嗤，敢作臺閣計。", "子方英妙時，文已合斯世。", "煌煌慶元春，南省果高綴。", "相看慈恩塔，益振子苗裔。", "如鳳千仞翔，如鶴九臯唳。", "從茲恢遠業，其肯負六藝。", "志尚昔之賢，仕明古之制。", "清明到華要，慶會屏氛翳。", "歎我正浮沉，期子轉磨礪。", "載詠章泉詩，詞林信根柢。"]'),
('078fa57b-d043-4e0b-b3b8-c020e00607f9','往年就祿南局謂違考亭得兩語感懷愴恨','韓淲','宋','宋诗','song-poetry','','[]','依世則廢道，違俗則多忤。',48,'全唐诗/poet.song.176000.json','["依世則廢道，違俗則多忤。", "先賢有遺訓，服之美無度。", "當年官藥曹，急景誠可怖。", "明明百世師，僊山武夷路。"]'),
('83c39020-83a9-4f32-a76a-72e2940d23c1','夜過斯遠聽琴','韓淲','宋','宋诗','song-poetry','','[]','琴聲類箏笛，俗手多一律。',144,'全唐诗/poet.song.176000.json','["琴聲類箏笛，俗手多一律。", "伊嚘悅兒女，焦急涴桐漆。", "予嘗爲作評，當是養心術。", "大絃寬而和，小絃精且密。", "製作務高雅，資材在清實。", "既鼓復以歌，其氣可平壹。", "昨從東海君，置酒風月室。", "歡然十指間，揮弄俄頃畢。", "灑落冰雪容，輝潤金玉質。", "人品既如許，古樂復在膝。", "顧予面生塵，見之頗自失。", "急歸卧南山，十日不敢出。"]'),
('8ef55ba1-ae98-4c40-a29f-e5989cb87a8b','過履道','韓淲','宋','宋诗','song-poetry','','[]','麥天氣清潤，磵道開午晴。',48,'全唐诗/poet.song.176000.json','["麥天氣清潤，磵道開午晴。", "箯輿度浮梁，我興隨所吟。", "書軒薝葡風，笑語亦揮觥。", "主人謂客何，歸路付醉醒。"]'),
('b74b14cc-b239-432e-82cc-b2bcb6e58381','過履道山堂及子潛家方齋','韓淲','宋','宋诗','song-poetry','','[]','盡日苦久旱，凌朝得微凉。',180,'全唐诗/poet.song.176000.json','["盡日苦久旱，凌朝得微凉。", "悠悠我所思，眇眇天一方。", "搔首亟盥沐，籃輿上河梁。", "城闍士如林，進取自行藏。", "孰甘尺蠖屈，孰羨鳴鳳翔。", "分寸絲忽間，膠擾互奔忙。", "唶嗟尚何詣，交誼或難忘。", "山堂兮方齋，城樹鬰葱蒼。", "豈無塵榻地，茗瀹容細嘗。", "放身易云晚，屋角下殘陽。", "虛明見雲風，從君以徜徉。", "須臾夜色起，片月翻流光。", "影靜理無違，語愜情不傷。", "相將得歲寒，留目禾黍場。", "可以飽喫飯，餘事掃粃糠。"]'),
('ac4cbdbc-58d8-44ca-99e4-bf1bfa135a38','喜趙十訪昌甫','韓淲','宋','宋诗','song-poetry','','[]','君再到章泉，我愧未能往。',72,'全唐诗/poet.song.176000.json','["君再到章泉，我愧未能往。", "玉田金仙路，薰風滿林蕩。", "殷勤好寄聲，不必論識賞。", "藥餌何關心，茶瓜姑抵掌。", "村虛曉霧昏，山危夜泉響。", "翁弟亦皤然，梅天苗更長。"]'),
('064f5d9d-6bb7-485a-b186-e0d6f69d7bd4','夜訪王丞','韓淲','宋','宋诗','song-poetry','','[]','吳會浩繁地，霜夜欲何之。',48,'全唐诗/poet.song.176000.json','["吳會浩繁地，霜夜欲何之。", "白髮湖海氣，良朋試尋詩。", "爾可收拾取，我亦爛漫題。", "只今歲闌時，孤山有梅枝。"]'),
('a79af059-c2b8-4b38-803b-e601c9b9119c','文叔見過山居斯遠亦來有懷昌甫','韓淲','宋','宋诗','song-poetry','','[]','薰風拂眼過，不知夏將深。',120,'全唐诗/poet.song.176000.json','["薰風拂眼過，不知夏將深。", "起視樹扶疎，聊以舒嘯吟。", "故人忽相過，我取酒同斟。", "凉夜月未落，相與試論心。", "溪淵有潛魚，山谷多翔禽。", "升沉本何意，能言不如瘖。", "斯遠居近市，昌甫棲遠岑。", "文叔宰百里，一一皆可欽。", "二子則良晤，一子當荒尋。", "詩罷予忽醉，掩關眠楮衾。"]'),
('b2a30155-11a3-4590-963b-8851d079de5f','管解元欲見巽伯','韓淲','宋','宋诗','song-poetry','','[]','春秋經世志，問取大愚家。',48,'全唐诗/poet.song.176000.json','["春秋經世志，問取大愚家。", "盤折入舉文，唾手爲國華。", "從容試講評，三傳寧浮誇。", "南渡今百年，中外義非賒。"]'),
('4e96aa1e-9952-469e-84b5-043dbbfbbd10','吳推官十五見過','韓淲','宋','宋诗','song-poetry','','[]','君來已三年，凡幾過澗上。',132,'全唐诗/poet.song.176000.json','["君來已三年，凡幾過澗上。", "杯酒逭我饑，言笑亦舒暢。", "同遊多時髦，意岸雜謔浪。", "倡優發俚曲，貌態或動盪。", "君今欲行矣，家山信無恙。", "人情久則疏，是乃流俗狀。", "吾儕遠逾密，此當足嘉尚。", "蕭條麥秋寒，烟雨寫青嶂。", "江空一水橋，城郭兩相望。", "他時延陵西，彼此記閒放。", "夜來夫如何，不和可無唱。"]'),
('ea75514d-ebac-46a5-91fc-dc6b8e230e6b','文叔入城夜半同斯遠見過蚤作聞而賦之','韓淲','宋','宋诗','song-poetry','','[]','西風勝士集，敲我月下門。',96,'全唐诗/poet.song.176000.json','["西風勝士集，敲我月下門。", "醉語驚童稚，今晨能具言。", "未知何許人，步武皆騰軒。", "顧非有逸韵，疇肯臨丘園。", "時予亦被酒，正爾飛夢魂。", "栩栩妙理熟，布衾清而溫。", "了不聞其然，醒來復何論。", "奇事既已失，躊躇黄葉村。"]'),
('88bf2ff1-f7e8-4260-b655-fcd747fab840','三十日邂逅柯錄同集希之月臺','韓淲','宋','宋诗','song-poetry','','[]','夜凉河漢迥，高風散梧桐。',48,'全唐诗/poet.song.176000.json','["夜凉河漢迥，高風散梧桐。", "危臺出塵埃，相與天壤中。", "把酒自蕭散，有句同從容。", "記取長安城，人海如魚龍。"]'),
('0d630281-faa7-45a7-98b8-2d24748030f0','同醉僧夜坐鄭一書房','韓淲','宋','宋诗','song-poetry','','[]','空山带荒溪，小窗語寒燈。',48,'全唐诗/poet.song.176000.json','["空山带荒溪，小窗語寒燈。", "寂歷歲云徂，醒眼猶拊膺。", "訪友得幽伴，無人醉閒僧。", "地爐火深紅，瓶梅影鬅鬙。"]'),
('4c77cc79-ba8b-424a-a061-1bce60a67b7a','過成季','韓淲','宋','宋诗','song-poetry','','[]','歲寒日之夕，疎籬梅放花。',48,'全唐诗/poet.song.176000.json','["歲寒日之夕，疎籬梅放花。", "池塘霜氣淨，柳带吐芳芽。", "山根擁殘雪，亂石逕橫斜。", "片帆下晴吹，行吟過君家。"]'),
('245286d1-1bad-4fd8-9075-4eee70a75065','薄暮一二鄰友見過','韓淲','宋','宋诗','song-poetry','','[]','燃燭熾爐炭，小雪冬已深。',48,'全唐诗/poet.song.176000.json','["燃燭熾爐炭，小雪冬已深。", "朋從把薄醪，不受寒暑侵。", "山空風夜號，落葉鵂鶹音。", "揮手語坐人，盡醉惜此心。"]'),
('3ed9dcfa-b9a1-4f16-9810-49e04c792be8','雪後過雨巖訪履道','韓淲','宋','宋诗','song-poetry','','[]','讀書了科詔，公子顯揚謀。',96,'全唐诗/poet.song.176000.json','["讀書了科詔，公子顯揚謀。", "歲寒松柏堅，高冢蔚而幽。", "書櫺耿冰硯，日屋嵐未收。", "上焉國脈壽，下焉民瘼瘳。", "父母凜遺體，操持夢前修。", "四載得重來，長言非燕遊。", "樵蘇行跡稀，雨巖丁嶺頭。", "共飯少徘徊，我志君勿求。"]'),
('b7a3ddf5-bdcc-42a3-9355-2aa5e5ed5a9c','二十八日過器遠是日生朝且有淮總之辟','韓淲','宋','宋诗','song-poetry','','[]','驅車吳山道，西指咸陽橋。',72,'全唐诗/poet.song.176000.json','["驅車吳山道，西指咸陽橋。", "南風吹酒醒，何以永今朝。", "主人千歲期，雙鬢綠不凋。", "良集紀初度，鵬翼當扶摇。", "京城峙三都，鬰乎何岧嶢。", "勉賦從軍詩，鐵馬鳴蕭蕭。"]'),
('f7397b59-06a2-46f8-8f3c-6e785f5db78a','約元立致道遊龍井各以事辭','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','平生荒野處，謂可開笑口。',84,'全唐诗/poet.song.176000.json','["平生荒野處，謂可開笑口。", "筇杖蘭槳外，忍復歎藜糗。", "春深西湖山，已落衆人後。", "尋幽欲吟搜，載酒拚醉嘔。", "今晨思一行，約友意復否。", "融融月穿樓，澹澹風動牖。", "放浪嵇阮流，不應獨古有。"]'),
('e08e086c-4125-4605-bdc2-90cbd9328823','二十五日文蔚携酒餌夜同訪鄭教授','韓淲','宋','宋诗','song-poetry','','[]','携酒問吾黨，有詩當歲窮。',48,'全唐诗/poet.song.176000.json','["携酒問吾黨，有詩當歲窮。", "城頭數疎更，窗外飛過鴻。", "悠悠澹澹裏，忽忽茫茫空。", "我爾且一杯，古今多三公。"]'),
('9c65edf7-2d40-4d7a-9a2b-ab25953d70f3','訪履常於斯遠所館書樓','韓淲','宋','宋诗','song-poetry','','[]','樓居兩仙人，冰雪玉鍊顔。',48,'全唐诗/poet.song.176000.json','["樓居兩仙人，冰雪玉鍊顔。", "整整羽袂飄，意象高且閑。", "塵眼一見之，竟日幾忘還。", "歸來山空寒，明月流松關。"]'),
('d04369c4-2441-4c06-a4ab-2f2a27e7bdd6','過釣瀨望方干故居','韓淲','宋','宋诗','song-poetry','','[]','今年第一詩，白雲詠玄英。',120,'全唐诗/poet.song.176000.json','["今年第一詩，白雲詠玄英。", "應知避人爾，老去何心情。", "烝哉文皇家，身世徒自驚。", "結廬釣臺下，偶然留姓名。", "蒼蒼雲山高，雪後江水清。", "崇朝起春寒，遥林舞風聲。", "扁舟轉晴午，餘思柔櫓輕。", "閒僧奉香火，客來亦逢迎。", "笑指嚴與方，可以觀我生。", "彼此各有時，三吳是神明。"]'),
('c980ce70-0b92-4492-963e-be940f1a1559','二十七日同鄭一尹一上高泉夜醉而作','韓淲','宋','宋诗','song-poetry','','[]','生死本一致，賢愚同一科。',48,'全唐诗/poet.song.176000.json','["生死本一致，賢愚同一科。", "高泉寺前水，春風靜流波。", "曳杖揖殘僧，奈此世諦何。", "棲賢堂外祠，莫待叩角欹。"]'),
('02610b1d-3ea7-4ad9-81c6-fe286ecbcd72','醉書','韓淲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','槌碎黄鶴樓，吸盡西江水。',48,'全唐诗/poet.song.176000.json','["槌碎黄鶴樓，吸盡西江水。", "索酒可以起，吹燈照無睡。", "夾城溪湯湯，負郭山靡靡。", "逢花其命乞，蓬心我蓬累。"]'),
('88cb38ed-2dde-410f-ad77-6ca7b01f7906','次韵斯遠同僧尋泉眼二首  其一','韓淲','宋','宋诗','song-poetry','','[]','幽尋誰與娛，巃嵸而𡾰嵼。',48,'全唐诗/poet.song.176000.json','["幽尋誰與娛，巃嵸而𡾰嵼。", "婣泉蒼蘚石，亦足理心眼。", "荒鋤本何好，所適謂可款。", "林叟忽相值，言笑不知返。"]'),
('4bed8ff9-8874-4bb7-b33e-b518b812a458','次韵斯遠同僧尋泉眼二首  其二','韓淲','宋','宋诗','song-poetry','','[]','上人何方來，解包與深遊。',48,'全唐诗/poet.song.176000.json','["上人何方來，解包與深遊。", "翩然松下吟，意行崖壑幽。", "淵淵水色古，疑卧蛟龍虬。", "雷雨當滿盈，奮動無此留。"]'),
('8f96c0a0-18f7-4c2e-a687-5ca2a5fee74d','餘杭拉趙履常昆弟同曾甥守約遊巽亭','韓淲','宋','宋诗','song-poetry','','[]','平湖溜清漲，亂石夾遠流。',48,'全唐诗/poet.song.176000.json','["平湖溜清漲，亂石夾遠流。", "洗盞與客言，展席愜我遊。", "人生貴自適，世道將焉求。", "晚峰忽前列，鳥鳴來白鷗。"]'),
('426f432c-f670-4f03-8673-5dd0fcd2f52a','初九日上南豅二十日同成季訪俞伯輝','韓淲','宋','宋诗','song-poetry','','[]','二士我所尚，得閒遂幽尋。',84,'全唐诗/poet.song.176000.json','["二士我所尚，得閒遂幽尋。", "盤桓南豅中，迤邐梅巖深。", "長日藴輕暑，宿雨收積陰。", "飄飄吹薄衣，遥遥豁煩襟。", "綢繆敦宿好，留連匪他心。", "泉石縱惟宜，爵服豈不任。", "天運每如此，歡言理清斟。"]'),
('666c5a87-8c6c-4511-9f10-f5ac152a1e6f','次公留飲','韓淲','宋','宋诗','song-poetry','','[]','清霜水南夜，海運一杯酒。',48,'全唐诗/poet.song.176000.json','["清霜水南夜，海運一杯酒。", "不知千古人，而得二三友。", "君未可青眼，我只是白首。", "吟哦醉夢間，共賦無何有。"]'),
('bffd7b58-99af-4431-b011-abaa5309b139','鄰並閒飲','韓淲','宋','宋诗','song-poetry','','[]','春泉滿山澗，春風到山家。',48,'全唐诗/poet.song.176000.json','["春泉滿山澗，春風到山家。", "蘭英已披逕，芹枝亦浮沙。", "我乘晴影步，所至憐物華。", "幽處有真意，避塵塵轉賒。"]'),
('b333fa88-0d5e-4008-adc6-317038841599','孫行之國錄相過同飲傳庵水閣因與王校棋','韓淲','宋','宋诗','song-poetry','','[]','春餘却掃坐，衡門車馬音。',48,'全唐诗/poet.song.176000.json','["春餘却掃坐，衡門車馬音。", "青雲有達士，意行來澗陰。", "言詩取酒飲，命友以棋吟。", "老懷爲相羊，無悶良在今。"]'),
('5a39ac17-a398-46b2-9a78-44830cddfa7e','尹一家同孔道士飲鄭一繼至','韓淲','宋','宋诗','song-poetry','','[]','歲暮出門去，玉溪城郭深。',48,'全唐诗/poet.song.176000.json','["歲暮出門去，玉溪城郭深。", "故家誠可數，高士亦過臨。", "坐久狂客來，身老皤鬢侵。", "咄咄酒未醉，諧笑方侵尋。"]'),
('8883dc82-29f1-4d21-a80f-0192e8598e68','同趙判院桂秀才過太霞廣信看雪因飲澗梅','韓淲','宋','宋诗','song-poetry','','[]','山色富昏曉，澗痕餘濁清。',48,'全唐诗/poet.song.176000.json','["山色富昏曉，澗痕餘濁清。", "惟詩是我興，不飲非人情。", "思仙窮有頂，入寺說無生。", "冷蘂疏枝底，夜歸虛籟聲。"]'),
('86492648-4a40-4296-9e8a-c72866bfb689','教授同太守過橫碧因留教授一飲','韓淲','宋','宋诗','song-poetry','','[]','班坐橫碧軒，便足了吾事。',108,'全唐诗/poet.song.176000.json','["班坐橫碧軒，便足了吾事。", "水南凍雨中，歲晚欲何爲。", "人生衰榮爾，翻覆當有自。", "使君真不凡，賓從隨聽視。", "偶然理窗楹，豈曰登臨地。", "呂曾骨已朽，方來重增喟。", "蕭閑著我老，婆娑恐容易。", "惜乎一盃酒，未敢駐千騎。", "梅花山翠寒，孤香發清吹。"]'),
('f868ac87-93fe-4b56-8830-296b11cc450d','昌甫再集橫碧  其一','韓淲','宋','宋诗','song-poetry','','[]','幽幽溪南山，古寺占巖曲。',48,'全唐诗/poet.song.176000.json','["幽幽溪南山，古寺占巖曲。", "昔人不可見，佳處欲何屬。", "素秋集今雨，清晝話前躅。", "因君重徘徊，煮餠飲醽醁。"]'),
('ccb3df27-9b69-4ea6-8a7f-30efd259a047','昌甫再集橫碧  其二','韓淲','宋','宋诗','song-poetry','','[]','青山如佳人，不暇相應接。',48,'全唐诗/poet.song.176000.json','["青山如佳人，不暇相應接。", "風軒一開明，烟巒幾重疊。", "云乎具尊酒，乃爾隨步屧。", "寺古天薄寒，窗前墮紅葉。"]'),
('6c2f2cff-469b-408e-951b-301605ffbe51','昌甫再集橫碧  其三','韓淲','宋','宋诗','song-poetry','','[]','士悲此凜秋，而且復季月。',48,'全唐诗/poet.song.176000.json','["士悲此凜秋，而且復季月。", "撫世徒紛華，徂年信飄忽。", "經行見登臨，道舊嘆存沒。", "不知其何心，予懷到明發。"]'),
('9da14e77-0227-49a7-9936-b626ab2cbe41','方齋子潜留瀹茗','韓淲','宋','宋诗','song-poetry','','[]','地瘴山氣昏，中夜雨忽作。',72,'全唐诗/poet.song.176000.json','["地瘴山氣昏，中夜雨忽作。", "霏霏曉猶濃，午后漸收脚。", "雲光散微日，風動葉初落。", "老身閒窗坐，觸事何厚薄。", "旨蓄思禦冬，爰寂復爰寞。", "鳥噪雞亂啼，爐湯茗徐瀹。"]'),
('dec1b9ae-0dbc-4d00-a705-ef05698cff4f','六月周次公俞伯輝余子壽共飲','韓淲','宋','宋诗','song-poetry','','[]','煮餠了長夏，飽外非所憂。',156,'全唐诗/poet.song.176000.json','["煮餠了長夏，飽外非所憂。", "既和以滑甘，亦用冷煖投。", "芼之蔬茹嘉，一筯真良謀。", "風軒置盆水，簾虛漾林幽。", "更催石鼎煎，瀹此茗雪甌。", "且足爲口腹，庶得少遲留。", "山房無六月，微凉已颼颼。", "庚伏始云中，不日天下秋。", "善來二三友，閒身宜自由。", "步可著兩履，汎可掉扁舟。", "破壁委窮巷，孤城带芳洲。", "初傳多黍稌，忽詔捕螟蟊。", "但畏妨我詩，恒饑思難抽。"]'),
('ba6253d4-49aa-4519-b592-19ae8112418d','謝章令率同官載酒','韓淲','宋','宋诗','song-poetry','','[]','宿麥雨可種，野梅凍欲坼。',168,'全唐诗/poet.song.176000.json','["宿麥雨可種，野梅凍欲坼。", "令君領賓從，假日訪幽僻。", "陽升正初辰，道泰知有日。", "觴行既頻屢，談至或憤激。", "眷言數君才，何乃辱此邑。", "大夫如豫章，建厦固所急。", "簿公名家駒，薦士宜首及。", "尉曹學省彥，求盜豈其職。", "征官偉丈夫，名宦終見迫。", "顧我獨亡頼，甘作山林役。", "定遷且半載，未有如□□。", "溪山爲欣豫，閭里爭誦說。", "意同邀陶潜，事異過執戟。", "人事果好乖，推遷已疇昔。"]'),
('e35241b7-731d-4227-b2fe-ef5ddd7719ca','邂逅一施二徐留飯','韓淲','宋','宋诗','song-poetry','','[]','深山固凉冷，荒塗秋尚炎。',48,'全唐诗/poet.song.176000.json','["深山固凉冷，荒塗秋尚炎。", "誰歟約僧窗，里彥長少兼。", "夜飯頻忘疲，片月忽滿簷。", "友賢吾敢棄，他事皆毫纖。"]'),
('ef48a1ac-5084-414c-98af-88a7bcfca578','對酒','韓淲','宋','宋诗','song-poetry','','[]','馬周新豐酌，誰能復悠然。',60,'全唐诗/poet.song.176000.json','["馬周新豐酌，誰能復悠然。", "孟公投轄飲，有客亦可憐。", "君當恕醉人，淵明真欲眠。", "速相就一斗，杜老青銅錢。", "何如山牖秋，指點鄰甕邊。"]'),
('725ba04c-4df2-48bd-9870-e6e5d363bdaa','趙將招飲南池','韓淲','宋','宋诗','song-poetry','','[]','暮春南池上，遊朋一追隨。',84,'全唐诗/poet.song.176000.json','["暮春南池上，遊朋一追隨。", "豈不能把酒，亦復多成詩。", "主人歌聲長，塵務誰思惟。", "握手到爾汝，却恨杯行遲。", "是身既長閒，便覺處處宜。", "秉燭夜向深，明月忽如斯。", "勿使兒輩覺，甚矣吾獨衰。"]'),
('65dbb0e1-8b33-45b6-8e58-50c13242f4c5','宿九峰次早黄八哥載酒來','韓淲','宋','宋诗','song-poetry','','[]','鷓鴣鳴山翠，松日行曉光。',48,'全唐诗/poet.song.176000.json','["鷓鴣鳴山翠，松日行曉光。", "一庵遠市廛，自惜宜自藏。", "瑟瑟聞人迹，熙熙見壺觴。", "老境爲獻酬，筆到詩成章。"]'),
('4739bc5a-ca2c-47ed-ba70-41a9b8cfaa84','九峰晨興','韓淲','宋','宋诗','song-poetry','','[]','方池貯新泉，高松發清吹。',48,'全唐诗/poet.song.176000.json','["方池貯新泉，高松發清吹。", "晨光散朝雲，日影倏然至。", "翔禽去復集，春聲競姿媚。", "宴坐香燧飄，是身吾所寄。"]'),
('8cca31be-898d-488b-a552-463f98151363','小酌山囿','韓淲','宋','宋诗','song-poetry','','[]','朔風起山霧，四望多浮陰。',48,'全唐诗/poet.song.176000.json','["朔風起山霧，四望多浮陰。", "人情逼歲除，梅花照高林。", "興言一樽酒，豈顧杯淺深。", "可醉便須醉，丘中有鳴琴。"]'),
('b48a2ec4-d160-4f27-bc37-97472113bdea','徐斯遠山囿','韓淲','宋','宋诗','song-poetry','','[]','誰歟步高丘，雲山以爲囿。',48,'全唐诗/poet.song.176000.json','["誰歟步高丘，雲山以爲囿。", "荒寒繞蒼碧，蓊密得深秀。", "清猿嘯後嶺，白鳥度前岫。", "是中可忘言，煎茶了閒晝。"]'),
('798ce3b9-eef4-46ed-ae44-57d8bb865d07','吳推官同昌甫諸人飲澗上','韓淲','宋','宋诗','song-poetry','','[]','世味嚼蠟爾，臨風强吟哦。',108,'全唐诗/poet.song.176000.json','["世味嚼蠟爾，臨風强吟哦。", "故人今誰來，門前車馬多。", "招邀忽聚集，款曲成婆娑。", "齒髮我已老，歲月如擲梭。", "有酒不爲飲，奈此好事何。", "分題詠清趣，但恐俗所呵。", "吳侯金閨彥，公餘乃相過。", "歡笑酬座人，時春復清和。", "濯我澗上泉，因之而嘯歌。"]'),
('c6ff84d1-9dde-451b-a028-eaa39a8cb4be','同景瑜諸人飲于橫碧  其一','韓淲','宋','宋诗','song-poetry','','[]','老我强言笑，因人閒往還。',48,'全唐诗/poet.song.176000.json','["老我强言笑，因人閒往還。", "凄風落寒雨，野寺藏空山。", "寄懷文字中，放手盃酒間。", "衰草翳石梯，長杉映柴關。"]'),
('7342b5a4-3038-4fa4-8a82-6f49fea6bf12','同景瑜諸人飲于橫碧  其二','韓淲','宋','宋诗','song-poetry','','[]','夜色起佛屋，遥遥一鐘鳴。',48,'全唐诗/poet.song.176000.json','["夜色起佛屋，遥遥一鐘鳴。", "年運今何時，共此觴咏情。", "竹爐熅深煖，紙窗留微明。", "舉手揖坐客，爲善無近名。"]'),
('d5ca5fa1-a5d7-42be-b8f7-6f3674212562','同景瑜諸人飲于橫碧  其三','韓淲','宋','宋诗','song-poetry','','[]','殘僧項黄槁，兀兀度朝昏。',48,'全唐诗/poet.song.176000.json','["殘僧項黄槁，兀兀度朝昏。", "摩指因睡眼，苦寒常閉門。", "爐熏柏子香，客來忘所言。", "試與之飲酒，亦盡一瓦盆。"]'),
('104b62fc-c0b9-4a42-ad4a-59dd533e7ee9','同景瑜諸人飲于橫碧  其四','韓淲','宋','宋诗','song-poetry','','[]','歲月不待人，初寒迫深冬。',48,'全唐诗/poet.song.176000.json','["歲月不待人，初寒迫深冬。", "慨予歌聲長，天地亦改容。", "歌罷擲酒盞，忽然動昏鐘。", "風餘雪霏霏，鴉棲鴈雝雝。"]'),
('6acc46a3-0fce-4bd9-a0e6-f692111f1886','次公書室小飲','韓淲','宋','宋诗','song-poetry','','[]','南屏有幽窗，焚香讀道書。',48,'全唐诗/poet.song.176000.json','["南屏有幽窗，焚香讀道書。", "林聲起肅霜，寒事亦淡如。", "安時可娛老，靜契心地初。", "誰歟主與賓，酒酌方舒徐。"]'),
('ee4a378b-1a16-4f12-843f-7553892b7e95','月夜散步浮橋因取酒與諸友小飲','韓淲','宋','宋诗','song-poetry','','[]','出谷秋水上，夜橋風月凉。',48,'全唐诗/poet.song.176000.json','["出谷秋水上，夜橋風月凉。", "斗柄插斜河，露氣垂雲光。", "取酒爲更酌，四顧一笑長。", "歸徑黄葉乾，雁鴻正高翔。"]'),
('2899502e-96ea-43be-a5b1-76d0ff7e9121','午窗羽客相訪','韓淲','宋','宋诗','song-poetry','','[]','客從赤城來，氣貌霜髮古。',48,'全唐诗/poet.song.176000.json','["客從赤城來，氣貌霜髮古。", "破裘傲寒色，忍與世仰俯。", "時能茹芝朮，謂可生毛羽。", "物外有高風，相期到瑶圃。"]'),
('a02a5748-d2b7-4b82-972e-cdb44fe905c6','舟中道士鄭谷耕摘阮咸清甚而雅放','韓淲','宋','宋诗','song-poetry','','[]','天台坐忘真，爲我洗俚耳。',84,'全唐诗/poet.song.176000.json','["天台坐忘真，爲我洗俚耳。", "浮舟作阮咸，坐客亦興起。", "此聲從何來，湖陰正清泚。", "孟公苦好客，下榻更奇士。", "盧遨踞龜殻，萬事俱不理。", "夏衣始輕體，蓮錢復靡靡。", "重酌黄冠師，依風且流徵。"]'),
('9903a3ed-5b69-45b1-935f-769e72af6b69','二十七日同伯皋宿真隠二十八日寒食觀昌甫詩恭叔所題字觀中兩樹辛夷花甚大道士撫琴試新茗','韓淲','宋','宋诗','song-poetry','','[]','風日明寒食，古觀辛夷花。',60,'全唐诗/poet.song.176000.json','["風日明寒食，古觀辛夷花。", "冉冉山勢轉，寂寂溪流斜。", "摩挲舊題字，故人天之涯。", "尚餘子臯子，與我同咨嗟。", "素抱安用攄，清彈啜新茶。"]'),
('3045542b-4412-4954-aa5a-c0eaad3a4648','中秋羽客相遇坐浮梁四鼓','韓淲','宋','宋诗','song-poetry','','[]','千古中秋月，夜深橋上看。',96,'全唐诗/poet.song.176000.json','["千古中秋月，夜深橋上看。", "玉溪湛無波，山靜天宇寬。", "同來得羽人，趺坐白雲寒。", "自謂脫塵鞅，誰知尚微官。", "隠隠見孤城，潺潺聞遠灘。", "是身吾所寄，仙去亦不難。", "光芒星斗稀，雲氣時瀰漫。", "歸來卧柴扃，形神轉清安。"]'),
('a3cef85a-b28a-4c79-97d1-e8ae337fedc2','酒熟','韓淲','宋','宋诗','song-poetry','','[]','意緒忽不整，甕頭新酒香。',48,'全唐诗/poet.song.176000.json','["意緒忽不整，甕頭新酒香。", "雨細起暝色，天低漏寒光。", "殘花菊枝短，老葉楓樹長。", "取醉乃吾事，山空欲清霜。"]'),
('33d43cfc-9c8c-42c1-ba65-53e050382e91','庵鄰王家兩送酒來','韓淲','宋','宋诗','song-poetry','','[]','渴飲對空觴，俛仰自長喟。',60,'全唐诗/poet.song.176000.json','["渴飲對空觴，俛仰自長喟。", "頼有田中鄰，時時遣酒至。", "歡言斟酌之，感彼勤重意。", "漂母哀王孫，從古多此類。", "澤畔且行吟，春風尚堪醉。"]'),
('73ece5ef-509b-444b-b2d2-b268da25edac','謝友人惠筍','韓淲','宋','宋诗','song-poetry','','[]','知我出山久，忘却山中味。',48,'全唐诗/poet.song.176000.json','["知我出山久，忘却山中味。", "持贈忽滿奩，不憚少破費。", "抽萌有生意，抱節無嫩氣。", "祇恐人已俗，食之又何謂。"]'),
('4099034b-2856-4ce5-a79a-67af721c55d0','鄰僧晚磬','韓淲','宋','宋诗','song-poetry','','[]','回風薄棲鴉，寒色倏已暝。',48,'全唐诗/poet.song.176000.json','["回風薄棲鴉，寒色倏已暝。", "禾收正行田，木落應掩徑。", "市聲頻年稀，人迹中夜定。", "心嬾隣更閑，僧窗有幽磬。"]'),
('30be8c17-6c47-4949-952e-8651b56dfc81','趙主簿以許旌陽李八百像刻來因得二首  其一','韓淲','宋','宋诗','song-poetry','','[]','眇眇西山路，誰知許旌陽。',72,'全唐诗/poet.song.176000.json','["眇眇西山路，誰知許旌陽。", "餘事斷蛟爾，劍氣聊自藏。", "羣陰養魑魅，往往常披猖。", "安得從其游，像刻不可忘。", "君能一弔古，摹遺勞持將。", "定非凡子須，相與彌慨慷。"]'),
('8ab18050-ce71-447c-8d42-cd0a9e267509','趙主簿以許旌陽李八百像刻來因得二首  其二','韓淲','宋','宋诗','song-poetry','','[]','蕭蕭八百洞，高安尚流傳。',72,'全唐诗/poet.song.176000.json','["蕭蕭八百洞，高安尚流傳。", "謂李脫亦可，貌出真神仙。", "洗我短世悲，遐哉謂之玄。", "安得從其遊，棄置塵垢羶。", "君能一弔古，摹歸遺何偏。", "澗頭霜葉寒，相與知其賢。"]'),
('208fe281-6076-4c56-8754-3c14e1ed9040','海運','韓淲','宋','宋诗','song-poetry','','[]','春山非隠淪，乃作養生計。',96,'全唐诗/poet.song.176000.json','["春山非隠淪，乃作養生計。", "豈無軒裳心，蓋欲了千歲。", "當其稟賦初，沖氣甚微細。", "誰知憂患多，坐使百脈滯。", "海仙用奇語，安眠可元契。", "因之地爐煖，綿綿見根蒂。", "乾坤一交泰，日月去昏翳。", "萬事俱若遺，一身且康濟。"]'),
('2139f2d2-56b0-4fd7-a7e0-b77b876e390f','祝融吟','韓淲','宋','宋诗','song-poetry','','[]','紹熙三年冬，二十有五日。',120,'全唐诗/poet.song.176000.json','["紹熙三年冬，二十有五日。", "良月信城西，一火近千室。", "其間邸店多，吾亦僅六七。", "暮收五百錢，旦爲十口實。", "茲乃例遭焚，隠忍不敢詰。", "閒常巷黨人，意謂頗豐逸。", "高者即見鄙，下者但相疾。", "終歲縱栖栖，疇肯顧蓬蓽。", "生産今泯焉，諸賢必能悉。", "祝融疑相吾，參元可同律。"]'),
('72dee71d-ab59-40b4-b366-4d4e95317169','溪汛浮橋屢解','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','潢潦漲梅潤，五月三解橋。',96,'全唐诗/poet.song.176000.json','["潢潦漲梅潤，五月三解橋。", "浸淫人尚可，恐汎新插苗。", "傳聞錢塘湖，閔雨宸慮焦。", "玉帛走羣望，虎頭潭蕩摇。", "如何千里間，陽陰猶未調。", "干戈或底定，豐穰蘇瘵凋。", "郊居茅茨濕，不過日寂寥。", "饑寒自常事，鷄鳴復蕭蕭。"]'),
('24e8124b-d4e2-41f8-948d-21d11ec4ad46','示兒','韓淲','宋','宋诗','song-poetry','','[]','士固貴誦說，人亦要力行。',48,'全唐诗/poet.song.176000.json','["士固貴誦說，人亦要力行。", "氣質到深厚，心術尤分明。", "貴賤易遷變，是非多戰爭。", "直宜剛且正，無復弱而平。"]'),
('0931120b-f57d-4303-8df0-5abe5d5acdbe','再示子文','韓淲','宋','宋诗','song-poetry','','[]','悌弟其誰家，懽然友于兄。',60,'全唐诗/poet.song.176000.json','["悌弟其誰家，懽然友于兄。", "飲我一盃酒，北客交舊情。", "凉雨清晚雲，庭柯澹陰陰。", "席間長少集，文獻各準繩。", "是豈小故哉，宜醉亦宜醒。"]'),
('3cd5c1ac-d85d-45fc-b10b-7dacc677adaa','叔逢尊兄同二猶子季夏奉先翁南山先生初忌祠事宿安固山房長姪賦詩和章盈握余時客峨下莫與省掃東望悲哽入秋廼能賡載隨韵寫情不敢自以爲詩也','韓淲','宋','宋诗','song-poetry','','[]','詩筒南山來，緘題手親揭。',240,'全唐诗/poet.song.176000.json','["詩筒南山來，緘題手親揭。", "三年蓼莪廢，楚愴不堪說。", "向來志顯揚，豈不願華燁。", "自量分予薄，斂退畏官熱。", "所冀短日延，得奉蘭羞潔。", "物聚斯有散，中豈長盍盍。", "吾翁燭此理，至言不苟發。", "謂宜發老更，前後祝哽噎。", "洞天俄趣還，玉鎖一笑掣。", "百年會歸盡，九原疑可作。", "傷心北岡松，長掛東嶺月。", "遥聞朱煒末，省掃俎豆列。", "我獨滯三峩，轉燭半年別。", "一生未禪悅，靜慮已朝徹。", "眷此顧復恩，追遠倍悽切。", "阿兄抱淵靜，諸阮更姱節。", "無忘溪翁銘，念念攸好德。", "靈源濬演迆，可使中遏絕。", "我雖懦不武，憤世能激烈。", "庶無忝所生，願賦濂溪拙。"]'),
('43663941-8bca-41c4-a378-857193b10ea4','晴窗','韓淲','宋','宋诗','song-poetry','','[]','晴窗已晨炊，趺坐焚清香。',48,'全唐诗/poet.song.176000.json','["晴窗已晨炊，趺坐焚清香。", "泥爐擁瓦缶，熟此蟹眼湯。", "茶甘泛松實，舌本味亦長。", "溫乎氣忽平，兀然夢相忘。"]'),
('450ab35a-8e1c-4dad-b58c-8dc1f3def753','壯志','韓淲','宋','宋诗','song-poetry','','[]','壯志老不已，撫劍斥宇宙。',48,'全唐诗/poet.song.176000.json','["壯志老不已，撫劍斥宇宙。", "日月倏過眼，孰得百歲壽。", "只今忍困苦，不必羨貴富。", "蓋代事業在，唾手可以就。"]'),
('cb934187-94e8-4fec-9fbd-93567aea8918','二十六夜坐','韓淲','宋','宋诗','song-poetry','','[]','初霜滌餘暖，山氣何其明。',84,'全唐诗/poet.song.176000.json','["初霜滌餘暖，山氣何其明。", "水痕亦漸收，澗淺流不聲。", "翔空有鳴鴈，肅肅已南征。", "人閒易爲老，物引誠可驚。", "憑窗既危坐，出門復安行。", "夜晚村微火，得酒承滿觥。", "且了讀殘書，理愜意逾平。"]'),
('9690a99a-7a71-487d-a292-fa4b4f69fdb3','身老','韓淲','宋','宋诗','song-poetry','','[]','酬應於外久，身老氣亦餒。',48,'全唐诗/poet.song.176000.json','["酬應於外久，身老氣亦餒。", "混淪一區宇，涵澄即淵海。", "雅俗詩書遷，炎冷歲節改。", "運轉大化間，壽者亦何待。"]'),
('aafb337b-df41-4d0e-b183-ec6a7a36b53d','老面','韓淲','宋','宋诗','song-poetry','','[]','老面見達官，强附終不近。',48,'全唐诗/poet.song.176000.json','["老面見達官，强附終不近。", "人之所以然，蓋我無令聞。", "安富是其時，尊榮本其分。", "只合坐茅廬，灰堆埋牛糞。"]'),
('4fc1475d-a5d8-40be-838d-e6d61f8d6840','袖手','韓淲','宋','宋诗','song-poetry','','[]','袖手坐春晝，淵淵古井水。',48,'全唐诗/poet.song.176000.json','["袖手坐春晝，淵淵古井水。", "倦漉淵明巾，姑隠子綦几。", "沉冥極顛末，昭徹貴表裏。", "裕矣得失心，隘哉洗其耳。"]'),
('79f8523a-84f5-4e61-9238-98faa0c44475','枕上','韓淲','宋','宋诗','song-poetry','','[]','收息卧曉枕，鴉聲報天明。',48,'全唐诗/poet.song.176000.json','["收息卧曉枕，鴉聲報天明。", "一簷隔市塵，便有嘈雜聲。", "今晨雪如何，云何蝗不生。", "且願蝗不生，明年穀價平。"]'),
('d459f784-6f66-4623-a0b1-ae1a8be013b0','清坐四鼓','韓淲','宋','宋诗','song-poetry','','[]','僧窗耿清燈，秋蟲入虛聽。',48,'全唐诗/poet.song.176000.json','["僧窗耿清燈，秋蟲入虛聽。", "風收松聲迴，夜息人籟定。", "清明養我神，湛寂見我性。", "萬有雖自然，唯樂獨也正。"]'),
('25c5ca78-d66a-4440-afce-70790922d1d3','危坐','韓淲','宋','宋诗','song-poetry','','[]','寒燈夢初覺，危坐收此心。',48,'全唐诗/poet.song.176000.json','["寒燈夢初覺，危坐收此心。", "心亦合自收，無念即清深。", "舉足塵埃起，盈顛霜雪侵。", "枯禪縛意馬，練養無胎禽。"]'),
('3086594b-f94b-4685-878b-f37e3aaeeb7a','偶興  其一','韓淲','宋','宋诗','song-poetry','','[]','少小住京邑，不識世寒煖。',84,'全唐诗/poet.song.176000.json','["少小住京邑，不識世寒煖。", "歡來上高樓，但愛湖水滿。", "所歷輒忘歸，其交亦常款。", "豈伊歲齒深，遂與境事斷。", "蕭蕭宋□宅，赫赫金張館。", "□堅多俠遊，隠約出幽伴。", "胡爲乎山中，長歌至於懶。"]'),
('6b37bfea-5347-467a-88a5-c66a330ce152','偶興  其二','韓淲','宋','宋诗','song-poetry','','[]','輕風度林杪，亂山啼子規。',48,'全唐诗/poet.song.176000.json','["輕風度林杪，亂山啼子規。", "流水去無迹，茅簷雨霏微。", "乍暖復薄寒，時時整巾衣。", "炊烟晚色起，呼童掩柴扉。"]'),
('74b625cf-18e7-4967-9895-336f977fe2ce','十四日推枕引酒信筆書此','韓淲','宋','宋诗','song-poetry','','[]','空云春晝長，明晦苦參錯。',84,'全唐诗/poet.song.176000.json','["空云春晝長，明晦苦參錯。", "連朝服衾枕，疲苶不可作。", "豈唯慮歸舟，去沒逢蛟鰐。", "卧聞耕桑家，種敗蠶栖箔。", "憂來故耿耿，政爾須杯勺。", "酸甜無正味，聊以慰寂寞。", "譬如無絃琴，亦寓山水樂。"]'),
('a119c70b-cb05-4868-8df1-5c9f530be818','偶成  其一','韓淲','宋','宋诗','song-poetry','','[]','南風吹時雨，襟抱忽然開。',96,'全唐诗/poet.song.176000.json','["南風吹時雨，襟抱忽然開。", "憑軒一長謠，清句亦滿懷。", "當年沮溺心，自覺未爲乖。", "桑麻澗上泉，何不返故棲。", "帝城塵埃中，隘巷多塗泥。", "擺落更奚道，强顔終莫諧。", "規規二十載，今日始知迷。", "仰視天宇高，歸雲去難回。"]'),
('935dc1ea-6f4a-4832-be2f-ba462a7bca90','偶成  其二','韓淲','宋','宋诗','song-poetry','','[]','淫淫梅子雨，靡靡上郭山。',48,'全唐诗/poet.song.176000.json','["淫淫梅子雨，靡靡上郭山。", "山既遶籬外，雨復濕窗間。", "林深葉葱蒨，地偏水潺湲。", "鵲噪雞鳴午，風定白雲還。"]'),
('4a6f0544-2e18-4263-bf2f-adb957d55680','偶成  其三','韓淲','宋','宋诗','song-poetry','','[]','逸此一寸心，養此七尺軀。',48,'全唐诗/poet.song.176000.json','["逸此一寸心，養此七尺軀。", "寒往則暑來，日居而月諸。", "萬古固寥遠，百年乃須臾。", "儀秦徒縱橫，唐虞祇都俞。"]'),
('4b36ad7c-8419-4c08-bc4f-ae5dba660c5e','偶成  其四','韓淲','宋','宋诗','song-poetry','','[]','重午是一節，芒種又一氣。',48,'全唐诗/poet.song.176000.json','["重午是一節，芒種又一氣。", "何因至怡悅，底事苦歔欷。", "園林無俗情，琴書有真味。", "貧者自爲貧，貴者自爲貴。"]'),
('6954d8ba-5437-4866-aaef-2753e5fc2522','偶感','韓淲','宋','宋诗','song-poetry','','[]','用物多則强，境熟氣易定。',108,'全唐诗/poet.song.176000.json','["用物多則强，境熟氣易定。", "壯膽騁寡見，迷情忽羣聽。", "茫茫可與否，沓沓賢且佞。", "名利纏古今，孰不墮此徑。", "驅馳每衝曉，展轉直至暝。", "固肥爾室家，端繫我朝廷。", "身無百歲長，事有一日罄。", "留侯李鄴侯，大似醉者醒。", "歷久只兩人，吾常喜深訂。"]'),
('b3b1c25b-3e25-4234-b516-34876e70c94e','夏日思家林','韓淲','宋','宋诗','song-poetry','','[]','籬門綠陰合，澗水通流泉。',48,'全唐诗/poet.song.176000.json','["籬門綠陰合，澗水通流泉。", "日影過屋外，風聲落山前。", "好客時時來，琴尊詠殘編。", "餘凉醒午醉，鳥語更清圓。"]'),
('f34d4e7d-474d-4a96-b2f0-d19471148f81','林下','韓淲','宋','宋诗','song-poetry','','[]','林下寂無事，坐對春風晚。',48,'全唐诗/poet.song.176000.json','["林下寂無事，坐對春風晚。", "杜鵑啼一聲，花落水流遠。", "琴書送日月，胡能計行遯。", "自是得棲遲，奚敢事偃蹇。"]'),
('3b30071f-ee48-4d0e-8921-0753cda1e0b8','雜興  其一','韓淲','宋','宋诗','song-poetry','','[]','清風穆然至，林影何其明。',48,'全唐诗/poet.song.176000.json','["清風穆然至，林影何其明。", "不知春已夏，池荷亦敷榮。", "展簟理竹榻，幽夢時自醒。", "起行散腰脚，氣適無留情。"]'),
('f8f067e2-d858-4fb0-938e-b494f5de2f3a','雜興  其二','韓淲','宋','宋诗','song-poetry','','[]','翾翾蝶粉白，氣化隨所之。',48,'全唐诗/poet.song.176000.json','["翾翾蝶粉白，氣化隨所之。", "人生事物間，自役應自知。", "賞心有餘樂，即目無足悲。", "天運非偶然，神釋形已疲。"]'),
('88fd65a4-2231-4d20-a689-98159f9d35bf','雜興  其三','韓淲','宋','宋诗','song-poetry','','[]','雲雷布凉雨，早稻葉翻翻。',48,'全唐诗/poet.song.176000.json','["雲雷布凉雨，早稻葉翻翻。", "携鋤走畦町，惜水不厭渾。", "吾方卧澗壑，人奚識丘園。", "望歲可以飽，高歌誦虞軒。"]'),
('d78720b5-66b7-4c8a-aff8-e60966d3b91d','雜興  其四','韓淲','宋','宋诗','song-poetry','','[]','長溝護流沫，沙石擁聲處。',48,'全唐诗/poet.song.176000.json','["長溝護流沫，沙石擁聲處。", "溯洄一鏡凈，更覺雲影住。", "不辭數魚蝦，甚欲下鷗鷺。", "夏氣忻已深，今古本如故。"]'),
('267d64e3-5134-42b5-a80c-ef69c01a8623','雜興  其五','韓淲','宋','宋诗','song-poetry','','[]','獨立看流水，草樹相因依。',48,'全唐诗/poet.song.176000.json','["獨立看流水，草樹相因依。", "清回灘聲長，碧下波影遲。", "人生老當斂，心口常自違。", "啼禽忽飛來，夏氣今如茲。"]'),
('38f2ed6c-c582-4802-b645-c4b47e259c3e','春日雜興  其一','韓淲','宋','宋诗','song-poetry','','[]','人多愁不達，達則定無愁。',48,'全唐诗/poet.song.176000.json','["人多愁不達，達則定無愁。", "不知所愁何，大半爲身謀。", "爵服縱可貴，事業終悠悠。", "以茲旦暮心，且從山水遊。"]'),
('aa35d793-8945-4acc-beea-cbe6ec9ae9a2','春日雜興  其二','韓淲','宋','宋诗','song-poetry','','[]','以我視彼心，當思我如彼。',48,'全唐诗/poet.song.176000.json','["以我視彼心，當思我如彼。", "未必有所益，徒更紛紜爾。", "世道升降間，古今只一理。", "昧不知其然，如是而已矣。"]'),
('6e274afd-c084-435b-b3f0-09ab974f3f80','春日雜興  其三','韓淲','宋','宋诗','song-poetry','','[]','當其未生時，孰知我能老。',48,'全唐诗/poet.song.176000.json','["當其未生時，孰知我能老。", "既老復須死，何其置懷抱。", "談空與說妙，終古吻不燥。", "此身無厭生，得酒醉亦好。"]'),
('a6559c85-7468-4fb0-9857-08aaf5fddbe9','春日雜興  其四','韓淲','宋','宋诗','song-poetry','','[]','儒者求專門，是豈爲我儒。',48,'全唐诗/poet.song.176000.json','["儒者求專門，是豈爲我儒。", "鄉願復不佳，必竟將何如。", "未有孔孟前，堯舜非著書。", "觀書亦不惡，塗轍亦差殊。"]'),
('f3dfaa0b-81b3-4558-b859-524cdf0a78bf','春日雜興  其五','韓淲','宋','宋诗','song-poetry','','[]','四時景自足，何必寫以詩。',48,'全唐诗/poet.song.176000.json','["四時景自足，何必寫以詩。", "詩成句讀間，不過我自知。", "但恐兩眼昏，心識如亂絲。", "血氣一耗散，逐物之所之。"]'),
('59e3ea28-16db-4ca3-b74e-8279d0ec20bf','春日雜興  其六','韓淲','宋','宋诗','song-poetry','','[]','種田圖得米，終歲亦勤勞。',48,'全唐诗/poet.song.176000.json','["種田圖得米，終歲亦勤勞。", "當春把鉏犁，和風滿東臯。", "豈忘水旱憂，流離至逋逃。", "未必可就食，往來徒嗷嗷。"]'),
('84700112-d137-4ea6-8a09-deb02aa0143c','春日雜興  其七','韓淲','宋','宋诗','song-poetry','','[]','士以科舉計，本避農與商。',48,'全唐诗/poet.song.176000.json','["士以科舉計，本避農與商。", "謀利則皆然，役役真可傷。", "周之士也貴，里選而論鄉。", "上人能用之，身尊道彌昌。"]'),
('6510d21f-ec96-4e0c-a74f-6adcb6873a9c','春日雜興  其八','韓淲','宋','宋诗','song-poetry','','[]','戎馬紛羣寇，殘害吾赤子。',48,'全唐诗/poet.song.176000.json','["戎馬紛羣寇，殘害吾赤子。", "被之以禮樂，庶使保生齒。", "如火熱水深，亦運之而已。", "治少亂則多，堯舜惟孝悌。"]'),
('a80b2b14-e931-46b1-902e-12a042f62647','春日雜興  其九','韓淲','宋','宋诗','song-poetry','','[]','幽草清更佳，被花多白紅。',48,'全唐诗/poet.song.176000.json','["幽草清更佳，被花多白紅。", "鳥啼蝴蝶亂，村村是春風。", "人無杯酒飲，不得此意融。", "春過夏將至，迤邐成秋冬。"]'),
('e4c5394a-3883-475a-8c1a-e0f3228b7ff0','春日雜興  其一○','韓淲','宋','宋诗','song-poetry','','[]','佛老多惰民，其書不如此。',48,'全唐诗/poet.song.176000.json','["佛老多惰民，其書不如此。", "儒者讀儒書，飲酒食肉耳。", "古人之糟粕，不過一片紙。", "不讀亦自佳，徒以資口耳。"]'),
('528663ef-dacb-4990-81f6-be2573d76dc6','春日雜興  其一一','韓淲','宋','宋诗','song-poetry','','[]','古人善爲治，焉得常繼之。',48,'全唐诗/poet.song.176000.json','["古人善爲治，焉得常繼之。", "施爲須臾間，亂之以參差。", "請觀一歲年，陰晴每如茲。", "大抵正自難，君子易憂思。"]'),
('30c48849-801b-4b51-ab33-7f0231ee84c4','春日雜興  其一二','韓淲','宋','宋诗','song-poetry','','[]','茫茫天地寬，山水多回礴。',48,'全唐诗/poet.song.176000.json','["茫茫天地寬，山水多回礴。", "一山復一水，又爾爲聚落。", "聚落成城郭，貴賤分憂樂。", "豈不知其然，何苦生厭薄。"]'),
('8d68c31b-011b-494d-9919-bdfbd2dd8d7a','秋日雜興  其一','韓淲','宋','宋诗','song-poetry','','[]','園荒無與鉏，草樹暗如織。',48,'全唐诗/poet.song.176000.json','["園荒無與鉏，草樹暗如織。", "披榛理幽步，野氣頗有力。", "坐令世網心，不動自然息。", "更見吾潩泉，無波瑩巖色。"]'),
('dd187c43-31ce-44cb-a4f1-3aaaec2f77b4','秋日雜興  其二','韓淲','宋','宋诗','song-poetry','','[]','木槿亞紅淡，牽牛蔓青滋。',48,'全唐诗/poet.song.176000.json','["木槿亞紅淡，牽牛蔓青滋。", "露晞凉風入，陡覺居處宜。", "巖桂中秋蘂，籬菊重陽枝。", "何必春始榮，物物有其時。"]'),
('c2080b84-df45-46bd-a5c8-8d193dc068c6','秋日雜興  其三','韓淲','宋','宋诗','song-poetry','','[]','開軒散幽帙，今昔隨所詣。',48,'全唐诗/poet.song.176000.json','["開軒散幽帙，今昔隨所詣。", "何如徹名色，庶不涴聲勢。", "撫几聊自怡，髮牙易凋弊。", "安得同心人，相忘可忘世。"]'),
('dd9ac8d0-63af-417a-b129-775a8640bbfc','秋日雜興  其四','韓淲','宋','宋诗','song-poetry','','[]','亭亭雞冠花，散出非所蒔。',48,'全唐诗/poet.song.176000.json','["亭亭雞冠花，散出非所蒔。", "色與秋日明，葉與秋庭媚。", "山閒人自稀，鴻鴈幾時至。", "境象吾素知，茅茨下清吹。"]'),
('564b620c-f382-4b6e-bb4f-683c550146a7','雨中雜興  其一','韓淲','宋','宋诗','song-poetry','','[]','獨吟不知秋，獨坐不知晚。',48,'全唐诗/poet.song.176000.json','["獨吟不知秋，獨坐不知晚。", "坐久頗撘陀，吟深或偃蹇。", "棲棲與世疎，默默去道遠。", "澄淵無起波，長谷有絕巘。"]'),
('adadc171-50d1-4aa4-aa53-70990447ddd8','雨中雜興  其二','韓淲','宋','宋诗','song-poetry','','[]','凉風固不惡，凉雨誠可佳。',48,'全唐诗/poet.song.176000.json','["凉風固不惡，凉雨誠可佳。", "庭空鳥雀至，籬破藤蔓斜。", "倦體得支吾，睡眼失昏花。", "門前客能來，我亦留茶瓜。"]'),
('6dad5f4b-f530-4057-8726-ce41279a9166','雨中雜興  其三','韓淲','宋','宋诗','song-poetry','','[]','蛩吟四壁立，月過一窗閒。',48,'全唐诗/poet.song.176000.json','["蛩吟四壁立，月過一窗閒。", "光明動音聞，此是我家山。", "才短仕固艱，氣餒髮亦斑。", "人物與天運，初不苦相關。"]'),
('f431263c-982f-44e7-8194-49eed2f459d4','雨中雜興  其四','韓淲','宋','宋诗','song-poetry','','[]','客來難共語，客去寧自孤。',48,'全唐诗/poet.song.176000.json','["客來難共語，客去寧自孤。", "未能高遠引，非斯其誰徒。", "寥寥同心人，一逝不可呼。", "淵明醉即眠，所以愛吾廬。"]'),
('b1045a25-420f-4a62-8ccb-93501021faa5','雨中雜興  其五','韓淲','宋','宋诗','song-poetry','','[]','枯禪未離喧，隨俗或安雅。',48,'全唐诗/poet.song.176000.json','["枯禪未離喧，隨俗或安雅。", "翻覆大化中，誰是長年者。", "同光須臾期，塵埃野馬也。", "風亭木葉下，村村又秋社。"]'),
('398ebf48-8dc3-47a8-9581-c8374bbdfbf3','春懷  其一','韓淲','宋','宋诗','song-poetry','','[]','蝴蝶爲莊周，黄粱熟邯鄲。',48,'全唐诗/poet.song.176000.json','["蝴蝶爲莊周，黄粱熟邯鄲。", "蘧然一夢覺，茫茫天壤間。", "相推明日月，來往成暑寒。", "山林與鐘鼎，胸中了不干。"]'),
('aa588533-d067-4440-b132-5317daa96883','春懷  其二','韓淲','宋','宋诗','song-poetry','','[]','東風已飛花，綠葉生晝陰。',48,'全唐诗/poet.song.176000.json','["東風已飛花，綠葉生晝陰。", "呼童整春服，清溪一嘯吟。", "時序遽如許，不知情淺深。", "夕陽忽在山，輕烟起沉沉。"]'),
('d4d2bc0b-1e9b-4af5-9833-914770e5d11e','春懷  其三','韓淲','宋','宋诗','song-poetry','','[]','單舸下長川，相與兩文士。',48,'全唐诗/poet.song.176000.json','["單舸下長川，相與兩文士。", "歡然叩舷歌，激激響風水。", "山頭秀松杉，城陰富桃李。", "周流至橋邊，興極笑而起。"]'),
('d27d9530-299c-4af0-8847-b088ed9906c9','春懷  其四','韓淲','宋','宋诗','song-poetry','','[]','澆淳固一致，大抵務歸厚。',48,'全唐诗/poet.song.176000.json','["澆淳固一致，大抵務歸厚。", "百年草棲塵，孔孟已無有。", "書不求甚解，又不喜飲酒。", "宦情隨牒移，庸能累身口。"]'),
('2dfc21da-0252-4835-8254-e8a267a916b4','春懷  其五','韓淲','宋','宋诗','song-poetry','','[]','潺潺澗聲清，杳杳一徑靜。',48,'全唐诗/poet.song.176000.json','["潺潺澗聲清，杳杳一徑靜。", "晴鳩喚雨鳩，屋角自相應。", "佳處無時無，領略在吾興。", "萬理鍾自然，名物可爭競。"]'),
('2c964455-7ac9-485d-a07e-8915bb628770','春懷  其六','韓淲','宋','宋诗','song-poetry','','[]','萬言一杯水，馳辯漫摛藻。',48,'全唐诗/poet.song.176000.json','["萬言一杯水，馳辯漫摛藻。", "飾智以驚愚，去盜亦有道。", "吾衰夢周公，青春鏡中老。", "富貴親戚畏，位高金多好。"]'),
('c3b1d882-bc29-4e1c-a0e9-8e1b69d48f0d','秋懷  其一','韓淲','宋','宋诗','song-poetry','','[]','人生一世間，百年幾晴陰。',84,'全唐诗/poet.song.176000.json','["人生一世間，百年幾晴陰。", "貴賤無定在，歲月徒自深。", "世路有夷險，宦業多升沉。", "未能率此性，于何不動心。", "在彼猶在己，視古猶視今。", "不須問行藏，且圖豁胸襟。", "鄰翁有酒不，對我成清斟。"]'),
('a075ff88-d5d9-4257-a65e-b5180023050c','秋懷  其二','韓淲','宋','宋诗','song-poetry','','[]','小雨不肯晴，烟中猶霢霂。',96,'全唐诗/poet.song.176000.json','["小雨不肯晴，烟中猶霢霂。", "出門泥未乾，枯柳弄微綠。", "皇皇欲何之，君子貴謹獨。", "屋上幸有山，屋邊亦種木。", "西風遶東籬，秋來更多菊。", "采擷升中堂，悠然興自足。", "斷絃尚何問，鸞膠有誰續。", "居今實思古，孜孜慕前躅。"]'),
('4fedb45c-eb03-4ed5-a77b-a8c0ade6922f','秋懷  其三','韓淲','宋','宋诗','song-poetry','','[]','虛堂倚修竹，冷冷自蒼翠。',84,'全唐诗/poet.song.176000.json','["虛堂倚修竹，冷冷自蒼翠。", "東軒亦不惡，小山發叢桂。", "殘蟬猶啾啁，新鴈已嘹唳。", "撫几憐歲華，何用苦文字。", "顔子曲肱眠，陶令日日醉。", "鄙哉乘時者，急急死名利。", "百年歸山丘，等無身口累。"]'),
('6b645ffc-2296-4230-90c2-68453adb9ad9','秋懷  其四','韓淲','宋','宋诗','song-poetry','','[]','我愛淵明詩，超出俗調度。',72,'全唐诗/poet.song.176000.json','["我愛淵明詩，超出俗調度。", "執卷良自羞，在手不忍去。", "有時成誦之，行歌倚松樹。", "好風從西來，瀟然尚何慮。", "三歎或已暮，不知衣上露。", "俗物忽敗人，蒼茫認歸路。"]'),
('bdab595a-8cdf-4093-89df-21347071170d','秋懷  其五','韓淲','宋','宋诗','song-poetry','','[]','秋月從天來，照人光清寒。',72,'全唐诗/poet.song.176000.json','["秋月從天來，照人光清寒。", "起舞或四顧，夜色明飛欄。", "舉杯與之笑，不知頹玉山。", "醉倒復自起，揮手捫天關。", "衡門終局促，空戴頭上冠。", "焉得萬里沙，校獵馳雕鞍。"]'),
('950e6be9-c83b-4292-ac33-17b919f49f28','秋懷  其六','韓淲','宋','宋诗','song-poetry','','[]','讀書求甚解，汲汲何時已。',72,'全唐诗/poet.song.176000.json','["讀書求甚解，汲汲何時已。", "紛然四海間，臭味少相似。", "人誰識致知，人誰務窮理。", "不專尚空言，但祇事苛禮。", "曾莫如老莊，猶解究生死。", "斯文今淪亡，吁嗟乎餘子。"]'),
('fbe63f18-9a69-4420-8cd9-02984694bd08','秋懷  其七','韓淲','宋','宋诗','song-poetry','','[]','壯士不逢時，失身雜蓬蒿。',132,'全唐诗/poet.song.176000.json','["壯士不逢時，失身雜蓬蒿。", "出門仰天笑，入門復悲號。", "驥騄無時無，誰爲九方臯。", "兩鬢空未白，脫落已蕭騷。", "博文事華藻，馳辨如波濤。", "持此可求進，義命畏所操。", "雖於交遊間，好客時一遭。", "握手或對榻，氣岸兩相高。", "奈此窮困何，耕鑿敢辭勞。", "從渠肉食者，厭薄一世豪。", "富哉漢公卿，朝夕醉醇醪。"]'),
('2542bfd3-1855-429a-8669-99eca0894560','秋懷  其八','韓淲','宋','宋诗','song-poetry','','[]','天命有生死，人事有盛衰。',96,'全唐诗/poet.song.176000.json','["天命有生死，人事有盛衰。", "亙古每如此，一致該百爲。", "墨翟非達道，徒爾悲練絲。", "寥寥千載間，聖賢眼中稀。", "悠悠水東逝，忽忽日西馳。", "爲學苟未至，於人猶可思。", "發言一不善，雖馬亦難追。", "修身撰良辰，浩然排憂悲。"]'),
('03d5db75-a08e-45e3-9aeb-b2b670d43409','秋懷  其九','韓淲','宋','宋诗','song-poetry','','[]','出門溪上行，山蒼波渺渺。',60,'全唐诗/poet.song.176000.json','["出門溪上行，山蒼波渺渺。", "漁子隠岸隈，樵者來木杪。", "時當宿雨霽，露滴秋風曉。", "晨光明朝暾，佳處殊不少。", "達觀宇宙間，城邑何褊小。"]'),
('a3a0ac41-3af5-4b66-92f7-ba1af2e1732f','秋懷  其一○','韓淲','宋','宋诗','song-poetry','','[]','憶昔武夷君，邀我相翺翔。',72,'全唐诗/poet.song.176000.json','["憶昔武夷君，邀我相翺翔。", "舟遊九曲溪，授以却老方。", "豈知一別後，蹉跎客他鄉。", "空餘清夜夢，幔亭發林芳。", "會須尋舊遊，仙家日月長。", "棄置烟火食，岩前有囷倉。"]'),
('28bb9eb3-e42e-4674-af22-24dd385eaa5b','秋懷  其一一','韓淲','宋','宋诗','song-poetry','','[]','秋來事幽討，發興不能休。',108,'全唐诗/poet.song.176000.json','["秋來事幽討，發興不能休。", "此身幸未老，焉能營菟裘。", "西山發秀色，南澗渟清流。", "山水無盡藏，似足供我謀。", "天然有奇妙，不待人力修。", "光景逐昏旦，節物因春秋。", "吏事非吾樂，世態非吾憂。", "耕鑿圖飲食，蠶繰作衾裯。", "更願長豐登，庶幾足所求。"]'),
('7aceae46-b4fe-427c-b8f0-bd6f5df335ce','妾薄命','韓淲','宋','宋诗','song-poetry','','[]','朝隨雙鴛鴦，暮爲孤鳳凰。',120,'全唐诗/poet.song.176000.json','["朝隨雙鴛鴦，暮爲孤鳳凰。", "春風顧盼間，羅帳生輝光。", "金盤薦玉食，王母持雕觴。", "能得幾時好，頃刻成參商。", "夜月滿空階，餘香在衣裳。", "人生喜懽樂，失計易沮傷。", "本謂榮九族，旦夕如金張。", "一身乃命薄，粉泪空徬徨。", "應羨里閭間，百歲同糟糠。", "悔不祇從媒，隨分作妻房。"]'),
('382009d3-0e3c-4a98-b39b-f5daeb684655','東山吟','韓淲','宋','宋诗','song-poetry','','[]','謝安久不作，東山尚誰論。',168,'全唐诗/poet.song.176000.json','["謝安久不作，東山尚誰論。", "當年擁鼻吟，幾爲妻子昏。", "撫箏挽其鬚，慷慨徒爾言。", "諸兒淝水功，折屐心已煩。", "後來名字傳，江左猶知尊。", "李白王介甫，二詩至今存。", "吾行樟丘野，迤邐懷德村。", "有客理花草，開徑於樊園。", "云是愛閒者，衣冠安石孫。", "一見邀我留，取酒置盤飧。", "世有斯人歟，豈受車馬喧。", "悠哉扁榜佳，碑板見淵源。", "因之重歎息，老語不敢吞。", "相與保初志，春秋燕鷄豚。"]'),
('301f2b9f-02ca-4f25-86c6-e1dee07577bf','效齊梁體','韓淲','宋','宋诗','song-poetry','','[]','徘徊碧山崦，想像碧山人。',60,'全唐诗/poet.song.176000.json','["徘徊碧山崦，想像碧山人。", "落日寒未昏，飛鴻過之頻。", "自視悖俗姿，忍與衆小鄰。", "一朝入聖門，畢世遺清塵。", "只今崖邊松，可以經千春。"]'),
('82902c68-9d28-4ccb-83fd-01fba341e5c9','讀鮑謝詩  其一','韓淲','宋','宋诗','song-poetry','','[]','山水能娛人，清氣溢方州。',60,'全唐诗/poet.song.176000.json','["山水能娛人，清氣溢方州。", "曳杖僧坊側，積潦看橫流。", "風光草際變，雲物天中浮。", "士豈悉慕藺，吾其不夢周。", "緬邈五柳陶，歸來事西疇。"]'),
('b96773ac-7bcb-426f-aebb-6b615bf80f84','讀鮑謝詩  其二','韓淲','宋','宋诗','song-poetry','','[]','晝日夏方永，逝波川上驚。',84,'全唐诗/poet.song.176000.json','["晝日夏方永，逝波川上驚。", "摇毫抒情思，莫知蛙黽鳴。", "老身偃仰間，遐心尚何征。", "顧步得所逢，揮手疑過清。", "黄流潏斷港，青柳散前榮。", "夫我自蓽門，伊人滿蕪城。", "景急語勿緩，混茫風雅生。"]'),
('df906eb6-cae5-4eed-b4b3-4a499dd23711','讀淵明飲酒詩','韓淲','宋','宋诗','song-poetry','','[]','山水幽絕處，吾亦難爲情。',60,'全唐诗/poet.song.176000.json','["山水幽絕處，吾亦難爲情。", "此道世莫講，肯計身後名。", "徇名與逃名，俱若可憐生。", "百年能幾何，大半寵辱驚。", "醒醉一昭徹，本來孰虧成。"]'),
('ab53df27-453f-4b1d-a6bf-cd52a66f937b','次韵斯遠和答昌甫讀謫仙詩  其一','韓淲','宋','宋诗','song-poetry','','[]','琴樽發清謠，老眼度閒日。',96,'全唐诗/poet.song.176000.json','["琴樽發清謠，老眼度閒日。", "君侯句愈奇，天然去雕織。", "得詩喜欲舞，此意越今昔。", "一從陶謝遠，誰復見真跡。", "直疑天地來，不在口耳覓。", "扶摇九萬鵬，天池可同息。", "章泉泉水清，爲我洗胸臆。", "綠葉青春深，夜月夢遥夕。"]'),
('c2cd2881-1722-43da-a9d4-7228ecd410c7','次韵斯遠和答昌甫讀謫仙詩  其二','韓淲','宋','宋诗','song-poetry','','[]','酴醿落香雪，楊柳生野煙。',48,'全唐诗/poet.song.176000.json','["酴醿落香雪，楊柳生野煙。", "東風過寒食，物色誰能憐。", "清晨沐蘭芳，夷心玉景篇。", "萬象春和中，霞珮璆鏘然。"]');
